import React, { useState, useEffect } from 'react';
import { ArrowLeft, Lock, User as UserIcon, Eye, EyeOff, AlertCircle, RefreshCw, ShieldCheck, Sparkles, GraduationCap, Laptop } from 'lucide-react';
import { Role, User } from '../types';
import { auth, firestore } from '../firebase.ts';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword } from "firebase/auth";
import { doc, getDoc, getDocs, collection, setDoc } from "firebase/firestore";

interface LoginProps {
  role: Role;
  onBack: () => void;
  onLogin: (user: User) => void;
  onNavigateSignup: () => void;
}

const Login: React.FC<LoginProps> = ({ role, onBack, onLogin, onNavigateSignup }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<{message: string}>({message: ''});
  const [loading, setLoading] = useState(false);
  const [isEmptyDb, setIsEmptyDb] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);

  const isAdmin = role === 'ADMIN';

  useEffect(() => {
    const checkUsers = async () => {
      try {
        const querySnapshot = await getDocs(collection(firestore, "users"));
        if (querySnapshot.empty) {
          setIsEmptyDb(true);
        }
      } catch (e) {
        console.warn("Status koleksi users tidak dapat dicek.");
      }
    };
    if (isAdmin) checkUsers();
  }, [isAdmin]);

  const handleCreateInitialAdmin = async () => {
    setIsInitializing(true);
    setError({message: ''});
    const adminUsername = "admin";
    const adminPass = "admin123";
    const email = `${adminUsername}@alirsyad.sch.id`;

    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, adminPass);
      const firebaseUser = userCredential.user;

      const adminData: User = {
        id: firebaseUser.uid,
        name: "Admin Utama Informatika",
        username: adminUsername,
        role: 'ADMIN',
        status: 'ACTIVE',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=admin`
      };

      await setDoc(doc(firestore, "users", firebaseUser.uid), adminData);

      alert(`ADMIN BERHASIL DIBUAT!\n\nUsername: ${adminUsername}\nPassword: ${adminPass}`);
      setIsEmptyDb(false);
      setUsername(adminUsername);
      setPassword(adminPass);
    } catch (err: any) {
      setError({message: "Gagal Inisialisasi: " + err.message});
    } finally {
      setIsInitializing(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError({message: ''});
    setLoading(true);

    const cleanUsername = username.trim().toLowerCase();
    const email = `${cleanUsername}@alirsyad.sch.id`;

    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      // Ambil profil dari koleksi utama 'users'
      let userDoc = await getDoc(doc(firestore, "users", firebaseUser.uid));
      let userData: User | null = null;

      if (userDoc.exists()) {
        userData = userDoc.data() as User;
      } else {
        // Fallback jika data belum sinkron ke users (misal pendaftar baru)
        const collections = ["elearning_students_list", "elearning_pending_students"];
        for (const col of collections) {
          const docRef = doc(firestore, col, firebaseUser.uid);
          const snap = await getDoc(docRef);
          if (snap.exists()) {
            userData = snap.data() as User;
            break;
          }
        }
      }

      if (userData) {
        // Validasi Peran (Role) - Mencegah Siswa login lewat portal Guru & sebaliknya
        if (userData.role !== role) {
          await auth.signOut();
          setError({message: `Akses Ditolak: Akun ini terdaftar sebagai ${userData.role}, bukan ${role}.`});
        } else if (userData.status === 'PENDING') {
          await auth.signOut();
          setError({message: "Akun Anda masih dalam antrean persetujuan. Mohon tunggu konfirmasi Guru."});
        } else {
          onLogin({ ...userData, id: firebaseUser.uid });
        }
      } else {
        await auth.signOut();
        setError({message: "Profil akun tidak ditemukan dalam database cloud."});
      }
    } catch (err: any) {
      if (err.code === 'auth/invalid-credential' || err.code === 'auth/wrong-password' || err.code === 'auth/user-not-found') {
        setError({message: "Username atau Password salah. Periksa kembali pengetikan Anda."});
      } else if (err.code === 'auth/network-request-failed') {
        setError({message: "Koneksi internet terputus. Gagal menghubungkan ke Cloud Firebase."});
      } else {
        setError({message: "Terjadi kesalahan sistem: " + (err.message || "Gagal login.")});
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-white selection:bg-indigo-100 selection:text-indigo-900">
      {/* Left Decoration Panel - Role Dependent Colors */}
      <div className={`hidden md:flex flex-1 items-center justify-center p-20 relative overflow-hidden transition-colors duration-700 ${isAdmin ? 'bg-slate-900' : 'bg-blue-600'}`}>
        <div className={`absolute top-0 right-0 w-96 h-96 rounded-full blur-[120px] -mr-48 -mt-48 transition-colors ${isAdmin ? 'bg-emerald-500/20' : 'bg-white/20'}`}></div>
        <div className={`absolute bottom-0 left-0 w-80 h-80 rounded-full blur-[100px] -ml-40 -mb-40 transition-colors ${isAdmin ? 'bg-indigo-500/10' : 'bg-blue-400/30'}`}></div>

        <div className="relative z-10 text-white max-w-md space-y-8 animate-in fade-in slide-in-from-left-10 duration-1000">
          <div className={`w-20 h-20 rounded-3xl flex items-center justify-center shadow-2xl ${isAdmin ? 'bg-emerald-500' : 'bg-white text-blue-600'}`}>
             {isAdmin ? <ShieldCheck size={40} /> : <GraduationCap size={40} />}
          </div>
          <div className="space-y-4">
            <h2 className="text-6xl font-black leading-tight tracking-tighter">
              Cloud Portal<br/>
              <span className={isAdmin ? 'text-emerald-400 italic' : 'text-blue-200 italic'}>
                {isAdmin ? 'Guru / Admin' : 'Siswa Informatika'}
              </span>
            </h2>
            <div className="h-1.5 w-24 bg-white/20 rounded-full"></div>
            <p className="text-xl text-white/70 font-medium leading-relaxed">
              {isAdmin 
                ? "Manajemen kurikulum, evaluasi tugas, dan pengawasan progres belajar siswa secara real-time."
                : "Akses materi digital, kumpulkan tugas praktikum, dan pantau hasil pencapaian belajar Anda."
              }
            </p>
          </div>

          <div className="pt-8 flex items-center gap-6">
             <div className="flex -space-x-3">
                {[1,2,3].map(i => (
                  <img key={i} className="w-10 h-10 rounded-full border-2 border-white/20 bg-white/10" src={`https://api.dicebear.com/7.x/avataaars/svg?seed=user${i}${role}`} alt="" />
                ))}
             </div>
             <p className="text-sm font-bold text-white/50 uppercase tracking-widest">
               {isAdmin ? "Admin Team" : "Student Community"}
             </p>
          </div>
        </div>
      </div>

      {/* Right Login Form Panel */}
      <div className="flex-1 bg-white flex flex-col justify-center items-center px-8 py-12 md:px-20">
        <div className="w-full max-w-md">
          <button onClick={onBack} className="flex items-center gap-3 text-slate-400 hover:text-slate-900 mb-12 font-black text-xs uppercase tracking-widest group transition-all">
            <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" /> Kembali ke Beranda
          </button>

          <div className="mb-10 space-y-2">
            <h3 className="text-5xl font-black text-slate-900 tracking-tighter">
              {isAdmin ? 'Masuk Guru' : 'Masuk Siswa'}
            </h3>
            <p className="text-slate-500 font-bold italic">Selamat datang kembali di Cloud Informatika.</p>
          </div>

          {error.message && (
            <div className="mb-8 p-5 bg-rose-50 border border-rose-100 rounded-3xl animate-in fade-in slide-in-from-top-2 flex items-start gap-4">
              <div className="w-10 h-10 bg-rose-100 text-rose-600 rounded-2xl flex items-center justify-center shrink-0">
                <AlertCircle size={20} />
              </div>
              <div className="space-y-1">
                <p className="text-[10px] font-black text-rose-400 uppercase tracking-widest leading-none mt-1">Gagal Login</p>
                <p className="text-xs font-bold text-rose-600 leading-relaxed">{error.message}</p>
              </div>
            </div>
          )}

          {isEmptyDb && isAdmin && (
            <div className="mb-10 p-8 bg-indigo-50 border-2 border-dashed border-indigo-200 rounded-[2.5rem] space-y-6">
               <div className="flex items-center gap-4 text-indigo-700">
                  <div className="p-3 bg-white rounded-2xl shadow-sm"><Sparkles size={24} className="text-indigo-600" /></div>
                  <div>
                    <p className="font-black text-xs uppercase tracking-widest">Setup Database</p>
                    <p className="text-[10px] font-bold text-indigo-400 italic">Belum ada admin terdaftar.</p>
                  </div>
               </div>
               <p className="text-xs text-indigo-600 leading-relaxed font-bold">Tekan tombol di bawah untuk membuat akun <span className="underline">Admin Utama</span> pertama kali.</p>
               <button 
                onClick={handleCreateInitialAdmin}
                disabled={isInitializing}
                className="w-full py-5 bg-indigo-600 text-white rounded-[1.8rem] font-black text-xs uppercase tracking-[0.2em] hover:bg-indigo-700 transition-all flex items-center justify-center gap-3 shadow-xl shadow-indigo-100 disabled:opacity-50 active:scale-[0.98]"
               >
                 {isInitializing ? <RefreshCw className="animate-spin" size={18} /> : <ShieldCheck size={18} />}
                 Inisialisasi Admin Cloud
