import React, { useState, useEffect } from 'react';
import LandingPage from './views/LandingPage.tsx';
import AdminDashboard from './views/AdminDashboard.tsx';
import StudentDashboard from './views/StudentDashboard.tsx';
import Login from './views/Login.tsx';
import Signup from './views/Signup.tsx';
import { User, Role, SiteSettings } from './types.ts';
import { RefreshCw, CheckCircle, AlertCircle, Cloud } from 'lucide-react';
import { firestore, auth } from './firebase.ts';
import { 
  collection, 
  doc, 
  getDoc, 
  getDocs, 
  setDoc, 
  addDoc 
} from "firebase/firestore"; 
import { onAuthStateChanged } from "firebase/auth";

const sanitize = (obj: any) => {
  const result: any = {};
  Object.keys(obj).forEach(key => {
    if (obj[key] !== undefined && obj[key] !== null) {
      result[key] = obj[key];
    }
  });
  return result;
};

export const db = {
  get: async (key: string) => {
    try {
      const querySnapshot = await getDocs(collection(firestore, key));
      return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    } catch (err) {
      console.error("Firestore Get Error:", err);
      return [];
    }
  },

  getSingle: async (key: string, id: string) => {
    try {
      const docSnap = await getDoc(doc(firestore, key, id));
      return docSnap.exists() ? { id: docSnap.id, ...docSnap.data() } : null;
    } catch (err) {
      console.error("Firestore Get Single Error:", err);
      return null;
    }
  },

  saveAll: async (key: string, value: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      if (Array.isArray(value)) {
        for (const item of value) {
          const id = item.id || Math.random().toString(36).substr(2, 9);
          await setDoc(doc(firestore, key, id), sanitize(item), { merge: true });
        }
      } else {
        await setDoc(doc(firestore, "settings", key), sanitize(value), { merge: true });
      }
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err) {
      console.error("Firestore Save Error:", err);
      window.dispatchEvent(new CustomEvent('sync-error'));
      throw err;
    }
  },

  append: async (key: string, value: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      const id = value.id || undefined;
      if (id) {
        await setDoc(doc(firestore, key, id), sanitize(value));
      } else {
        await addDoc(collection(firestore, key), sanitize(value));
      }
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      throw err;
    }
  },

  deleteKey: async (key: string) => {
    console.warn("Manual deletion of keys via client-side db utility is limited.");
  }
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'landing' | 'login' | 'signup' | 'dashboard'>('landing');
  const [loginRole, setLoginRole] = useState<Role | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'success' | 'error'>('idle');
  const [settings, setSettings] = useState<SiteSettings>({
    logoUrl: 'https://www.alirsyad.or.id/wp-content/uploads/download/alirsyad-alislamiyyah.png',
    heroImageUrl: 'https://cdn.fpt-is.com/vi/he-thong-elearning-1.png',
    siteName: 'Informatika SMP Al Irsyad Surakarta'
  });

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      try {
        if (firebaseUser) {
          // Cari user di master 'users'
          let userProfile = await db.getSingle('users', firebaseUser.uid);

          // Jika tidak ada di master, cari di koleksi spesifik (Student Management)
          if (!userProfile) {
             userProfile = await db.getSingle('elearning_students_list', firebaseUser.uid);
          }

          if (!userProfile) {
             userProfile = await db.getSingle('elearning_pending_students', firebaseUser.uid);
          }

          if (userProfile) {
            const userData = userProfile as User;
            // Pastikan user AKTIF atau ADMIN agar bisa masuk dashboard
            if (userData.status === 'ACTIVE' || userData.role === 'ADMIN') {
              setUser(userData);
              setView('dashboard');
            } else {
              // Jika status pending, logout otomatis
              await auth.signOut();
              setUser(null);
              setView('login');
              setLoginRole('STUDENT');
            }
          } else {
            await auth.signOut();
            setUser(null);
            setView('landing');
          }
        } else {
          setUser(null);
          if (view === 'dashboard') setView('landing');
        }
      } catch (err) {
        console.error("Auth change error:", err);
      } finally {
        setIsLoading(false);
      }
    });

    const fetchSettings = async () => {
      try {
        const stored = await getDoc(doc(firestore, "settings", "site_configs"));
        if (stored.exists()) {
          setSettings(stored.data() as SiteSettings);
        }
      } catch (e) {
        console.warn("Settings fetch failed:", e);
      }
    };

    fetchSettings();
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const handleSyncStart = () => setSyncStatus('syncing');
    const handleSyncEnd = () => {
      setSyncStatus('success');
      setTimeout(() => setSyncStatus('idle'), 3000);
    };
    const handleSyncError = () => {
      setSyncStatus('error');
      setTimeout(() => setSyncStatus('idle'), 5000);
    };

    window.addEventListener('sync-start', handleSyncStart);
    window.addEventListener('sync-end', handleSyncEnd);
    window.addEventListener('sync-error', handleSyncError);

    return () => {
      window.removeEventListener('sync-start', handleSyncStart);
      window.removeEventListener('sync-end', handleSyncEnd);
      window.removeEventListener('sync-error', handleSyncError);
    };
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    setView('dashboard');
  };

  const handleLogout = async () => {
    await auth.signOut();
    setUser(null);
    setView('landing');
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        <div className="relative mb-8">
          <div className="w-20 h-20 border-4 border-emerald-100 border-t-emerald-600 rounded-full animate-spin"></div>
          <Cloud className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-emerald-600" size={28} />
        </div>
        <h2 className="text-xl font-black text-slate-800 mb-2">Sinkronisasi Cloud...</h2>
        <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.3em]">SMP AL Irsyad Surakarta</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen selection:bg-emerald-100 selection:text-emerald-900 relative">
      <div className={`fixed top-6 left-1/2 -translate-x-1/2 z-[100] flex items-center gap-3 px-6 py-3 rounded-full shadow-2xl border backdrop-blur-md transition-all duration-500 transform ${
        syncStatus === 'idle' ? 'translate-y-[-140%] opacity-0' : 'translate-y-0 opacity-100'
      } ${
        syncStatus === 'syncing' ? 'bg-indigo-600 text-white border-indigo-500' : 
        syncStatus === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-rose-600 text-white border-rose-500'
      }`}>
        {syncStatus === 'syncing' && <RefreshCw className="animate-spin" size={16} />}
        {syncStatus === 'success' && <CheckCircle size={16} />}
        {syncStatus === 'error' && <AlertCircle size={16} />}
        <span className="text-[10px] font-black uppercase tracking-[0.2em]">
          {syncStatus === 'syncing' ? 'Firestore Sinkronisasi...' : 
           syncStatus === 'success' ? 'Data Cloud Terupdate' : 'Gagal Sinkronisasi'}
        </span>
      </div>

      {view === 'landing' && (
        <LandingPage 
          onNavigateLogin={(role) => { setLoginRole(role); setView('login'); }} 
          onNavigateSignup={() => setView('signup')} 
          settings={settings} 
        />
      )}

      {view === 'login' && (
        <Login 
          role={loginRole || 'STUDENT'} 
          onBack={() => setView('landing')} 
          onLogin={handleLogin} 
          onNavigateSignup={() => setView('signup')} 
        />
      )}

      {view === 'signup' && (
        <Signup 
          onBack={() => setView('login')} 
          onSignup={() => { setLoginRole('STUDENT'); setView('login'); }} 
          logoUrl={settings.logoUrl} 
        />
      )}

      {view === 'dashboard' && user && (
        user.role === 'ADMIN' 
          ? <AdminDashboard user={user} onLogout={handleLogout} settings={settings} setSettings={setSettings} onUpdateUser={setUser} /> 
          : <StudentDashboard user={user} onLogout={handleLogout} settings={settings} onUpdateUser={setUser} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Lock, User as UserIcon, Eye, EyeOff, AlertCircle, RefreshCw, ShieldCheck, Sparkles, GraduationCap, Laptop } from 'lucide-react';
import { Role, User } from '../types';
import { auth, firestore } from '../firebase.ts';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword } from "firebase/auth";
import { doc, getDoc, getDocs, collection, setDoc } from "firebase/firestore";

interface LoginProps {
  role: Role;
  onBack: () => void;
  onLogin: (user: User) => void;
  onNavigateSignup: () => void;
}

const Login: React.FC<LoginProps> = ({ role, onBack, onLogin, onNavigateSignup }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<{message: string}>({message: ''});
  const [loading, setLoading] = useState(false);
  const [isEmptyDb, setIsEmptyDb] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);

  const isAdmin = role === 'ADMIN';

  useEffect(() => {
    const checkUsers = async () => {
      try {
        const querySnapshot = await getDocs(collection(firestore, "users"));
        if (querySnapshot.empty) {
          setIsEmptyDb(true);
        }
      } catch (e) {
        console.warn("Status koleksi users tidak dapat dicek.");
      }
    };
    if (isAdmin) checkUsers();
  }, [isAdmin]);

  const handleCreateInitialAdmin = async () => {
    setIsInitializing(true);
    setError({message: ''});
    const adminUsername = "admin";
    const adminPass = "admin123";
    const email = `${adminUsername}@alirsyad.sch.id`;

    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, adminPass);
      const firebaseUser = userCredential.user;

      const adminData: User = {
        id: firebaseUser.uid,
        name: "Admin Utama Informatika",
        username: adminUsername,
        role: 'ADMIN',
        status: 'ACTIVE',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=admin`
      };

      await setDoc(doc(firestore, "users", firebaseUser.uid), adminData);

      alert(`ADMIN BERHASIL DIBUAT!\n\nUsername: ${adminUsername}\nPassword: ${adminPass}`);
      setIsEmptyDb(false);
      setUsername(adminUsername);
      setPassword(adminPass);
    } catch (err: any) {
      setError({message: "Gagal Inisialisasi: " + err.message});
    } finally {
      setIsInitializing(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError({message: ''});
    setLoading(true);

    const cleanUsername = username.trim().toLowerCase();
    const email = `${cleanUsername}@alirsyad.sch.id`;

    try {
      // 1. Coba login ke Firebase Auth
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      // 2. Ambil profil dari berbagai kemungkinan koleksi
      let userData: User | null = null;

      // Prioritas 1: Koleksi Utama 'users'
      const masterDoc = await getDoc(doc(firestore, "users", firebaseUser.uid));
      if (masterDoc.exists()) {
        userData = masterDoc.data() as User;
      } 

      // Prioritas 2: Jika belum ada di master (Siswa), cari di elearning_students_list
      if (!userData && role === 'STUDENT') {
        const studentDoc = await getDoc(doc(firestore, "elearning_students_list", firebaseUser.uid));
        if (studentDoc.exists()) {
          userData = studentDoc.data() as User;
        }
      }

      // Prioritas 3: Cari di pending (Siswa baru daftar)
      if (!userData && role === 'STUDENT') {
        const pendingDoc = await getDoc(doc(firestore, "elearning_pending_students", firebaseUser.uid));
        if (pendingDoc.exists()) {
          userData = pendingDoc.data() as User;
        }
      }

      if (userData) {
        // Cek Role
        if (userData.role !== role) {
          await auth.signOut();
          setError({message: `Akses Ditolak: Anda mencoba masuk sebagai ${role}, namun akun Anda terdaftar sebagai ${userData.role}.`});
          return;
        }

        // Cek Status (Harus ACTIVE untuk masuk)
        if (userData.role === 'STUDENT' && userData.status !== 'ACTIVE') {
          await auth.signOut();
          setError({message: "Akun Anda belum aktif. Mohon hubungi Guru Informatika untuk konfirmasi pendaftaran."});
          return;
        }

        onLogin({ ...userData, id: firebaseUser.uid });
      } else {
        await auth.signOut();
        setError({message: "Profil akun tidak ditemukan. Harap pastikan pendaftaran Anda sudah benar."});
      }
    } catch (err: any) {
      console.error("Login Error:", err.code);
      if (err.code === 'auth/invalid-credential' || err.code === 'auth/wrong-password' || err.code === 'auth/user-not-found') {
        setError({message: "Username atau Password salah. Jika Anda belum mendaftar, silakan buat akun terlebih dahulu."});
      } else if (err.code === 'auth/network-request-failed') {
        setError({message: "Koneksi internet bermasalah. Gagal menghubungi Cloud."});
      } else {
        setError({message: "Masalah sistem: " + (err.message || "Gagal masuk.")});
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-white selection:bg-indigo-100 selection:text-indigo-900">
      {/* Left Decoration Panel */}
      <div className={`hidden md:flex flex-1 items-center justify-center p-20 relative overflow-hidden transition-colors duration-700 ${isAdmin ? 'bg-slate-900' : 'bg-blue-600'}`}>
        <div className={`absolute top-0 right-0 w-96 h-96 rounded-full blur-[120px] -mr-48 -mt-48 transition-colors ${isAdmin ? 'bg-emerald-500/20' : 'bg-white/20'}`}></div>
        <div className="relative z-10 text-white max-w-md space-y-8 animate-in fade-in slide-in-from-left-10 duration-1000">
          <div className={`w-20 h-20 rounded-3xl flex items-center justify-center shadow-2xl ${isAdmin ? 'bg-emerald-500' : 'bg-white text-blue-600'}`}>
             {isAdmin ? <ShieldCheck size={40} /> : <GraduationCap size={40} />}
          </div>
          <div className="space-y-4">
            <h2 className="text-6xl font-black leading-tight tracking-tighter">
              Portal Cloud<br/>
              <span className={isAdmin ? 'text-emerald-400 italic' : 'text-blue-200 italic'}>
                {isAdmin ? 'Guru / Admin' : 'Siswa Informatika'}
              </span>
            </h2>
            <div className="h-1.5 w-24 bg-white/20 rounded-full"></div>
            <p className="text-xl text-white/70 font-medium leading-relaxed">
              {isAdmin 
                ? "Kelola materi, evaluasi tugas, dan pantau progres siswa."
                : "Akses materi digital dan kumpulkan tugas praktikum Anda."
              }
            </p>
          </div>
        </div>
      </div>

      {/* Right Login Form Panel */}
      <div className="flex-1 bg-white flex flex-col justify-center items-center px-8 py-12 md:px-20">
        <div className="w-full max-w-md">
          <button onClick={onBack} className="flex items-center gap-3 text-slate-400 hover:text-slate-900 mb-12 font-black text-xs uppercase tracking-widest group transition-all">
            <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" /> Beranda
          </button>

          <div className="mb-10 space-y-2">
            <h3 className="text-5xl font-black text-slate-900 tracking-tighter">
              {isAdmin ? 'Masuk Guru' : 'Masuk Siswa'}
            </h3>
            <p className="text-slate-500 font-bold italic">SMP Al Irsyad Surakarta</p>
          </div>

          {error.message && (
            <div className="mb-8 p-5 bg-rose-50 border border-rose-100 rounded-3xl animate-in fade-in slide-in-from-top-2 flex items-start gap-4">
              <div className="w-10 h-10 bg-rose-100 text-rose-600 rounded-2xl flex items-center justify-center shrink-0">
                <AlertCircle size={20} />
              </div>
              <div className="space-y-1">
                <p className="text-xs font-bold text-rose-600 leading-relaxed">{error.message}</p>
              </div>
            </div>
          )}

          {isEmptyDb && isAdmin && (
            <div className="mb-10 p-8 bg-indigo-50 border-2 border-dashed border-indigo-200 rounded-[2.5rem] space-y-4">
               <p className="text-xs text-indigo-600 font-bold">Belum ada Admin. Klik tombol di bawah untuk inisialisasi akun Admin pertama.</p>
               <button onClick={handleCreateInitialAdmin} disabled={isInitializing} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase hover:bg-indigo-700 shadow-xl disabled:opacity-50">
                 {isInitializing ? <RefreshCw className="animate-spin" size={18} /> : 'Buat Admin Utama'}
               </button>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-8">
            <div className="space-y-3">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-2">Username {role === 'STUDENT' ? 'Siswa' : 'Guru'}</label>
              <div className="relative group">
                <UserIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-500" size={22} />
                <input 
                  type="text" 
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  placeholder="Username"
                  className="w-full pl-14 pr-6 py-5 bg-slate-50 border-2 border-slate-50 rounded-[1.8rem] outline-none transition-all font-black text-slate-800 placeholder:text-slate-300 focus:border-blue-500/30 shadow-inner"
                  required
                />
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-2">Kata Sandi</label>
              <div className="relative group">
                <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-500" size={22} />
                <input 
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full pl-14 pr-14 py-5 bg-slate-50 border-2 border-slate-50 rounded-[1.8rem] outline-none transition-all font-black text-slate-800 focus:border-blue-500/30 shadow-inner"
                  required
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600">
                  {showPassword ? <EyeOff size={22} /> : <Eye size={22} />}
                </button>
              </div>
            </div>

            <button 
              disabled={loading} 
              className={`w-full py-6 rounded-[1.8rem] font-black text-lg shadow-2xl transition-all disabled:opacity-50 active:scale-[0.98] flex items-center justify-center gap-4 ${isAdmin ? 'bg-slate-900 text-white hover:bg-emerald-600' : 'bg-blue-600 text-white hover:bg-slate-900'}`}
            >
              {loading ? <RefreshCw className="animate-spin" size={26} /> : 'Login Sekarang'}
            </button>

            {role === 'STUDENT' && (
              <div className="text-center pt-4">
                <p className="text-slate-500 font-bold text-sm">
                  Belum punya akun? <button type="button" onClick={onNavigateSignup} className="text-blue-600 font-black hover:underline">Daftar Cloud Siswa</button>
                </p>
              </div>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

