import React, { useState, useEffect } from 'react';
import LandingPage from './views/LandingPage.tsx';
import AdminDashboard from './views/AdminDashboard.tsx';
import StudentDashboard from './views/StudentDashboard.tsx';
import Login from './views/Login.tsx';
import Signup from './views/Signup.tsx';
import { User, Role, SiteSettings } from './types.ts';
import { RefreshCw, CheckCircle, AlertCircle, Cloud } from 'lucide-react';
import { firestore, auth } from './firebase.ts';
import { 
  collection, 
  doc, 
  getDoc, 
  getDocs, 
  setDoc, 
  addDoc 
} from "firebase/firestore"; 
import { onAuthStateChanged } from "firebase/auth";

const sanitize = (obj: any) => {
  const result: any = {};
  Object.keys(obj).forEach(key => {
    if (obj[key] !== undefined && obj[key] !== null) {
      result[key] = obj[key];
    }
  });
  return result;
};

export const db = {
  get: async (key: string) => {
    try {
      const querySnapshot = await getDocs(collection(firestore, key));
      return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    } catch (err) {
      console.error("Firestore Get Error:", err);
      return [];
    }
  },

  getSingle: async (key: string, id: string) => {
    try {
      const docSnap = await getDoc(doc(firestore, key, id));
      return docSnap.exists() ? { id: docSnap.id, ...docSnap.data() } : null;
    } catch (err) {
      console.error("Firestore Get Single Error:", err);
      return null;
    }
  },

  saveAll: async (key: string, value: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      if (Array.isArray(value)) {
        for (const item of value) {
          const id = item.id || Math.random().toString(36).substr(2, 9);
          await setDoc(doc(firestore, key, id), sanitize(item), { merge: true });
        }
      } else {
        await setDoc(doc(firestore, "settings", key), sanitize(value), { merge: true });
      }
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err) {
      console.error("Firestore Save Error:", err);
      window.dispatchEvent(new CustomEvent('sync-error'));
      throw err;
    }
  },

  append: async (key: string, value: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      const id = value.id || undefined;
      if (id) {
        await setDoc(doc(firestore, key, id), sanitize(value));
      } else {
        await addDoc(collection(firestore, key), sanitize(value));
      }
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      throw err;
    }
  },

  deleteKey: async (key: string) => {
    console.warn("Manual deletion of keys via client-side db utility is limited.");
  }
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'landing' | 'login' | 'signup' | 'dashboard'>('landing');
  const [loginRole, setLoginRole] = useState<Role | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'success' | 'error'>('idle');
  const [settings, setSettings] = useState<SiteSettings>({
    logoUrl: 'https://www.alirsyad.or.id/wp-content/uploads/download/alirsyad-alislamiyyah.png',
    heroImageUrl: 'https://cdn.fpt-is.com/vi/he-thong-elearning-1.png',
    siteName: 'Informatika SMP Al Irsyad Surakarta'
  });

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      try {
        if (firebaseUser) {
          // 1. Cek di Master Collection 'users' (Paling Akurat)
          let profile = await db.getSingle('users', firebaseUser.uid);

          // 2. Jika tidak ada di master, coba cari di koleksi spesifik
          if (!profile) {
            profile = await db.getSingle('elearning_students_list', firebaseUser.uid);
          }
          if (!profile) {
            profile = await db.getSingle('elearning_pending_students', firebaseUser.uid);
          }

          if (profile) {
            const userData = profile as User;
            // Sinkronisasi status: Admin selalu boleh masuk, Siswa harus ACTIVE
            if (userData.role === 'ADMIN' || (userData.role === 'STUDENT' && userData.status === 'ACTIVE')) {
              setUser(userData);
              setView('dashboard');
            } else {
              // User ada tapi status PENDING atau tidak sesuai role
              await auth.signOut();
              setUser(null);
              setView('login');
              setLoginRole('STUDENT');
            }
          } else {
            // Sesi Auth ada tapi Profil di Firestore Hilang
            await auth.signOut();
            setUser(null);
            setView('landing');
          }
        } else {
          setUser(null);
          // Jika tidak sedang login, kembali ke landing jika di dashboard
          if (view === 'dashboard') setView('landing');
        }
      } catch (err) {
        console.error("Global Sync Error:", err);
      } finally {
        setIsLoading(false);
      }
    });

    const fetchSettings = async () => {
      try {
        const stored = await getDoc(doc(firestore, "settings", "site_configs"));
        if (stored.exists()) {
          setSettings(stored.data() as SiteSettings);
        }
      } catch (e) {
        console.warn("Using default settings.");
      }
    };

    fetchSettings();
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const handleSyncStart = () => setSyncStatus('syncing');
    const handleSyncEnd = () => {
      setSyncStatus('success');
      setTimeout(() => setSyncStatus('idle'), 3000);
    };
    const handleSyncError = () => {
      setSyncStatus('error');
      setTimeout(() => setSyncStatus('idle'), 5000);
    };

    window.addEventListener('sync-start', handleSyncStart);
    window.addEventListener('sync-end', handleSyncEnd);
    window.addEventListener('sync-error', handleSyncError);

    return () => {
      window.removeEventListener('sync-start', handleSyncStart);
      window.removeEventListener('sync-end', handleSyncEnd);
      window.removeEventListener('sync-error', handleSyncError);
    };
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    setView('dashboard');
  };

  const handleLogout = async () => {
    await auth.signOut();
    setUser(null);
    setView('landing');
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        <div className="w-16 h-16 border-4 border-emerald-100 border-t-emerald-600 rounded-full animate-spin mb-4"></div>
        <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Sinkronisasi Cloud...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen selection:bg-emerald-100 selection:text-emerald-900 relative">
      {/* Toast Sync Status */}
      <div className={`fixed top-6 left-1/2 -translate-x-1/2 z-[100] flex items-center gap-3 px-6 py-3 rounded-full shadow-2xl border backdrop-blur-md transition-all duration-500 transform ${
        syncStatus === 'idle' ? 'translate-y-[-140%] opacity-0' : 'translate-y-0 opacity-100'
      } ${
        syncStatus === 'syncing' ? 'bg-indigo-600 text-white border-indigo-500' : 
        syncStatus === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-rose-600 text-white border-rose-500'
      }`}>
        {syncStatus === 'syncing' && <RefreshCw className="animate-spin" size={16} />}
        {syncStatus === 'success' && <CheckCircle size={16} />}
        {syncStatus === 'error' && <AlertCircle size={16} />}
        <span className="text-[10px] font-black uppercase tracking-[0.2em]">
          {syncStatus === 'syncing' ? 'Cloud Saving...' : 
           syncStatus === 'success' ? 'Cloud Updated' : 'Sync Error'}
        </span>
      </div>

      {view === 'landing' && (
        <LandingPage 
          onNavigateLogin={(role) => { setLoginRole(role); setView('login'); }} 
          onNavigateSignup={() => setView('signup')} 
          settings={settings} 
        />
      )}

      {view === 'login' && (
        <Login 
          role={loginRole || 'STUDENT'} 
          onBack={() => setView('landing')} 
          onLogin={handleLogin} 
          onNavigateSignup={() => setView('signup')} 
        />
      )}

      {view === 'signup' && (
        <Signup 
          onBack={() => setView('login')} 
          onSignup={() => { setLoginRole('STUDENT'); setView('login'); }} 
          logoUrl={settings.logoUrl} 
        />
      )}

      {view === 'dashboard' && user && (
        user.role === 'ADMIN' 
          ? <AdminDashboard user={user} onLogout={handleLogout} settings={settings} setSettings={setSettings} onUpdateUser={setUser} /> 
          : <StudentDashboard user={user} onLogout={handleLogout} settings={settings} onUpdateUser={setUser} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
