  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [classRoom, setClassRoom] = useState('');
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchClasses = async () => {
      try {
        const querySnapshot = await getDocs(collection(firestore, "elearning_classes_list"));
        setClasses(querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as ClassRoom[]);
      } catch (e) {
        console.error("Error fetching classes:", e);
      }
    };
    fetchClasses();
  }, []);

  const checkUsernameAvailable = async (uname: string) => {
    // Cek di master users
    const q = query(collection(firestore, "users"), where("username", "==", uname), limit(1));
    const snap = await getDocs(q);
    return snap.empty;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    const cleanUsername = username.trim().toLowerCase();
    const email = `${cleanUsername}@alirsyad.sch.id`;

    try {
      // 1. Validasi Ketersediaan Username secara global
      const isAvailable = await checkUsernameAvailable(cleanUsername);
      if (!isAvailable) {
        throw new Error("Username sudah digunakan oleh orang lain.");
      }

      // 2. Buat akun Auth
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      // 3. Siapkan profil data
      const userData: User = {
        id: firebaseUser.uid,
        name,
        username: cleanUsername,
        classId: classRoom,
        role: 'STUDENT',
        status: 'PENDING',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${cleanUsername}`
      };

      // 4. Simpan ke Firestore (Master & Pending List)
      await setDoc(doc(firestore, "users", firebaseUser.uid), userData);
      await setDoc(doc(firestore, "elearning_pending_students", firebaseUser.uid), userData);

      alert("Pendaftaran Berhasil! Akun Anda sedang menunggu konfirmasi Guru Informatika.");
      await auth.signOut();
      onSignup();
    } catch (err: any) {
      if (err.code === 'auth/email-already-in-use') {
        setError("Email/Username sudah terdaftar. Silakan login.");
      } else {
        setError(err.message || "Gagal melakukan pendaftaran.");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col justify-center items-center px-6 py-12 text-black">
      <div className="w-full max-w-xl bg-white p-12 rounded-[3rem] shadow-2xl relative overflow-hidden border border-slate-100">
