                <span className="px-3 py-1 bg-orange-50 text-orange-600 rounded-full text-[10px] font-black uppercase tracking-widest border border-orange-100">
                  {pending.length} Antrean
                </span>
              </div>
              <p className="text-slate-500 font-medium text-sm mt-2 max-w-md leading-relaxed">Verifikasi identitas pendaftar baru untuk memberikan hak akses portal.</p>
