import { db } from '../App.tsx';

/**
 * Mengirim notifikasi ke siswa tertentu atau berdasarkan kelas
 */
export const notifyStudents = async (
  targetClasses: string[], 
  title: string, 
  message: string, 
  type: 'material' | 'task' | 'grade' | 'registration', 
  studentId?: string
) => {
  try {
    const students = await db.get('elearning_students_list');
    const studentList = Array.isArray(students) ? students : [];

    const targets = studentId 
      ? studentList.filter(s => s.id === studentId)
      : studentList.filter(s => targetClasses.includes(s.classId || ''));

    const newNotif = {
      id: 'notif_' + Date.now() + Math.random().toString(36).substr(2, 5),
      title,
      message,
      type,
      read: false,
      createdAt: new Date().toLocaleString('id-ID', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      })
    };

    for (const s of targets) {
      await db.append(`elearning_notifs_${s.id}`, newNotif);
    }
  } catch (err) {
    console.error("Failed to notify students:", err);
  }
};

/**
 * Mengirim notifikasi ke semua Admin (Guru)
 */
export const notifyAdmins = async (title: string, message: string) => {
  try {
    // Ambil semua user untuk mencari yang role-nya ADMIN
    const allUsers = await db.get('users');
    const adminList = Array.isArray(allUsers) ? allUsers.filter(u => u.role === 'ADMIN') : [];

    const newNotif = {
      id: 'admin_notif_' + Date.now() + Math.random().toString(36).substr(2, 5),
      title,
      message,
      type: 'registration',
      read: false,
      createdAt: new Date().toLocaleString('id-ID', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      })
    };

    // Kirim ke setiap admin yang terdaftar
    for (const admin of adminList) {
      await db.append(`elearning_notifs_${admin.id}`, newNotif);
    }
  } catch (err) {
    console.error("Failed to notify admins:", err);
  }
};

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Loader2, Eye, EyeOff, AlertCircle } from 'lucide-react';
import { User, ClassRoom } from '../types';
import { auth, firestore } from '../firebase.ts';
import { createUserWithEmailAndPassword } from "firebase/auth";
import { doc, setDoc, getDocs, collection, query, where, limit } from "firebase/firestore";
import { notifyAdmins } from '../utils/helpers.ts';

interface SignupProps {
  onBack: () => void;
  onSignup: () => void;
  logoUrl: string;
}

const Signup: React.FC<SignupProps> = ({ onBack, onSignup, logoUrl }) => {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [classRoom, setClassRoom] = useState('');
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchClasses = async () => {
      try {
        const querySnapshot = await getDocs(collection(firestore, "elearning_classes_list"));
        setClasses(querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as ClassRoom[]);
      } catch (e) {
        console.error("Error fetching classes:", e);
      }
    };
    fetchClasses();
  }, []);

  const checkUsernameAvailable = async (uname: string) => {
    const q = query(collection(firestore, "users"), where("username", "==", uname), limit(1));
    const snap = await getDocs(q);
    return snap.empty;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    const cleanUsername = username.trim().toLowerCase();
    const email = `${cleanUsername}@alirsyad.sch.id`;

    try {
      const isAvailable = await checkUsernameAvailable(cleanUsername);
      if (!isAvailable) {
        throw new Error("Username sudah digunakan oleh orang lain.");
      }

      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      const userData: User = {
        id: firebaseUser.uid,
        name,
        username: cleanUsername,
        classId: classRoom,
        role: 'STUDENT',
        status: 'PENDING',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${cleanUsername}`
      };

      await setDoc(doc(firestore, "users", firebaseUser.uid), userData);
      await setDoc(doc(firestore, "elearning_pending_students", firebaseUser.uid), userData);

      // KIRIM NOTIFIKASI KE ADMIN
      await notifyAdmins(
        "Pendaftaran Siswa Baru", 
        `${name} (Kelas ${classRoom}) telah mendaftar. Mohon segera verifikasi akun tersebut.`
      );

      alert("Pendaftaran Berhasil! Akun Anda sedang menunggu konfirmasi Guru Informatika.");
      await auth.signOut();
      onSignup();
    } catch (err: any) {
      if (err.code === 'auth/email-already-in-use') {
        setError("Email/Username sudah terdaftar. Silakan login.");
      } else {
        setError(err.message || "Gagal melakukan pendaftaran.");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col justify-center items-center px-6 py-12 text-black">
      <div className="w-full max-w-xl bg-white p-12 rounded-[3rem] shadow-2xl relative overflow-hidden border border-slate-100">
        {loading && (
          <div className="absolute inset-0 bg-white/80 z-20 flex items-center justify-center backdrop-blur-sm">
            <Loader2 className="animate-spin text-emerald-600" size={48} />
          </div>
        )}

        <button onClick={onBack} className="flex items-center gap-2 text-slate-400 hover:text-slate-900 mb-10 font-black text-xs uppercase tracking-widest transition-colors">
          <ArrowLeft size={16} /> Kembali
        </button>

        <div className="text-center mb-10 space-y-2">
          <h3 className="text-4xl font-black text-slate-900 tracking-tight">Registrasi Cloud Siswa</h3>
          <p className="text-slate-400 font-bold text-sm italic">Sistem E-Learning Informatika SMP Al Irsyad</p>
        </div>

        {error && (
          <div className="mb-8 p-4 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-3 text-rose-600 animate-in fade-in slide-in-from-top-2">
            <AlertCircle size={20} />
            <p className="text-xs font-black uppercase tracking-tight">{error}</p>
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          {step === 1 ? (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Nama Lengkap Siswa</label>
                <input 
                  value={name} 
                  onChange={e => setName(e.target.value)} 
                  className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold text-slate-800 focus:border-emerald-500 focus:bg-white transition-all shadow-inner" 
                  placeholder="Contoh: Ahmad Fauzi" 
                  required 
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Pilih Kelas Aktif</label>
                <select 
                  value={classRoom} 
                  onChange={e => setClassRoom(e.target.value)} 
                  className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold text-slate-800 focus:border-emerald-500 focus:bg-white transition-all shadow-inner appearance-none" 
                  required
                >
                  <option value="">-- Pilih Kelas Anda --</option>
                  {classes.map(c => <option key={c.id} value={c.name}>Kelas {c.name}</option>)}
                </select>
              </div>
              <button 
                type="button" 
                onClick={() => setStep(2)} 
                disabled={!name || !classRoom}
                className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-emerald-600 disabled:opacity-30 active:scale-[0.98] transition-all"
              >
                Lanjut ke Kredensial
              </button>
            </div>
          ) : (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Username Baru</label>
                <input 
                  value={username} 
                  onChange={e => setUsername(e.target.value.toLowerCase().replace(/\s/g, ''))} 
                  className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold text-slate-800 focus:border-emerald-500 focus:bg-white transition-all shadow-inner" 
                  placeholder="Contoh: ahmad8a" 
                  required 
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Password Keamanan</label>
                <div className="relative">
                  <input 
                    type={showPassword ? 'text' : 'password'} 
                    value={password} 
                    onChange={e => setPassword(e.target.value)} 
                    className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold text-slate-800 focus:border-emerald-500 focus:bg-white transition-all shadow-inner" 
                    placeholder="Minimal 6 Karakter" 
                    required 
                  />
                  <button 
                    type="button" 
                    onClick={() => setShowPassword(!showPassword)} 
                    className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-600 transition-colors"
                  >
                    {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                  </button>
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setStep(1)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-200 transition-all">Kembali</button>
                <button type="submit" className="flex-[2] py-5 bg-emerald-600 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-emerald-100 hover:bg-slate-900 active:scale-[0.98] transition-all">Selesaikan Pendaftaran</button>
              </div>
            </div>
          )}
        </form>
      </div>
    </div>
  );
};

export default Signup;

import React, { useState, useEffect } from 'react';
import { BarChart3, BookOpen, ClipboardList, Users, School, Settings, UserPlus, CheckCircle, AlertTriangle } from 'lucide-react';
import Layout from '../components/Layout.tsx';
import { User, SiteSettings, ClassRoom } from '../types.ts';
import { db } from '../App.tsx';

// Import Tab Components
import OverviewTab from './admin/OverviewTab.tsx';
import ConfirmRegistrationsTab from './admin/ConfirmRegistrationsTab.tsx';
import ManageMaterialsTab from './admin/ManageMaterialsTab.tsx';
import ManageTasksTab from './admin/ManageTasksTab.tsx';
import GradesTab from './admin/GradesTab.tsx';
import ManageStudentsTab from './admin/ManageStudentsTab.tsx';
import ManageClassesTab from './admin/ManageClassesTab.tsx';
import SettingsTab from './admin/SettingsTab.tsx';

interface AdminDashboardProps {
  user: User;
  onLogout: () => void;
  settings: SiteSettings;
  setSettings: React.Dispatch<React.SetStateAction<SiteSettings>>;
  onUpdateUser?: (u: User) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ user, onLogout, settings, setSettings, onUpdateUser }) => {
  const [activeView, setActiveView] = useState('overview');
  const [notifications, setNotifications] = useState<any[]>([]);
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [confirmModal, setConfirmModal] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    onConfirm: () => void;
    type: 'danger' | 'warning';
  }>({
    isOpen: false,
    title: '',
    message: '',
    onConfirm: () => {},
    type: 'danger'
  });

  useEffect(() => {
    const fetchNotifs = async () => {
      // Ambil notifikasi asli dari Firestore
      const stored = await db.get(`elearning_notifs_${user.id}`);
      setNotifications(Array.isArray(stored) ? stored : []);
    };

    const fetchClasses = async () => {
      const c = await db.get('elearning_classes_list');
      setClasses(Array.isArray(c) ? c : []);
    };

    fetchNotifs();
    fetchClasses();

    // Polling notifikasi setiap 30 detik agar dashboard tetap update
    const interval = setInterval(fetchNotifs, 30000);
    return () => clearInterval(interval);
  }, [user.id, activeView]);

  const handleMarkAsRead = async (id: string) => {
    const updated = notifications.map(n => n.id === id ? { ...n, read: true } : n);
    setNotifications(updated);
    await db.saveAll(`elearning_notifs_${user.id}`, updated);

    // Jika notifikasi tipe registrasi, arahkan ke tab konfirmasi
    if (notifications.find(n => n.id === id)?.type === 'registration') {
      setActiveView('confirmations');
    }
  };

  const handleMarkAllRead = async () => {
    const updated = notifications.map(n => ({ ...n, read: true }));
    setNotifications(updated);
    await db.saveAll(`elearning_notifs_${user.id}`, updated);
  };

  const sidebarItems = [
    { id: 'overview', label: 'Ringkasan', icon: BarChart3 },
    { id: 'confirmations', label: 'Konfirmasi Siswa', icon: UserPlus },
    { id: 'materials', label: 'Kelola Materi', icon: BookOpen },
    { id: 'tasks', label: 'Kelola Tugas', icon: ClipboardList },
    { id: 'grades', label: 'Nilai Tugas', icon: CheckCircle },
    { id: 'students', label: 'Kelola Siswa', icon: Users },
    { id: 'classes', label: 'Kelola Kelas', icon: School },
    { id: 'settings', label: 'Pengaturan', icon: Settings },
  ];

  const triggerConfirm = (title: string, message: string, onConfirm: () => void, type: 'danger' | 'warning' = 'danger') => {
    setConfirmModal({ isOpen: true, title, message, onConfirm, type });
  };

  const closeConfirm = () => setConfirmModal(prev => ({ ...prev, isOpen: false }));

  const renderContent = () => {
    switch (activeView) {
      case 'overview': return <OverviewTab setActiveView={setActiveView} />;
      case 'confirmations': return <ConfirmRegistrationsTab triggerConfirm={triggerConfirm} />;
      case 'materials': return <ManageMaterialsTab triggerConfirm={triggerConfirm} classes={classes} />;
      case 'tasks': return <ManageTasksTab triggerConfirm={triggerConfirm} classes={classes} />;
      case 'grades': return <GradesTab triggerConfirm={triggerConfirm} classes={classes} />;
      case 'students': return <ManageStudentsTab triggerConfirm={triggerConfirm} classes={classes} />;
      case 'classes': return <ManageClassesTab triggerConfirm={triggerConfirm} classes={classes} setClasses={setClasses} />;
      case 'settings': return <SettingsTab settings={settings} setSettings={setSettings} user={user} onUpdateUser={onUpdateUser!} />;
      default: return <OverviewTab setActiveView={setActiveView} />;
    }
  };

  return (
    <Layout 
      user={user} 
      onLogout={onLogout} 
      sidebarItems={sidebarItems} 
      activeView={activeView} 
      setActiveView={setActiveView}
      logoUrl={settings.logoUrl}
      siteName={settings.siteName}
      notifications={notifications}
      onMarkAsRead={handleMarkAsRead}
      onMarkAllAsRead={handleMarkAllRead}
    >
      {renderContent()}

      {confirmModal.isOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-6 text-black">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200 text-center">
            <div className={`w-20 h-20 mx-auto rounded-3xl flex items-center justify-center mb-6 ${confirmModal.type === 'danger' ? 'bg-red-50 text-red-500' : 'bg-orange-50 text-orange-50'}`}>
              <AlertTriangle size={40} className={confirmModal.type === 'danger' ? 'text-red-500' : 'text-orange-500'} />
            </div>
            <h3 className="text-2xl font-black text-slate-800 mb-2">{confirmModal.title}</h3>
            <p className="text-slate-500 font-medium text-sm leading-relaxed mb-10">{confirmModal.message}</p>
            <div className="flex gap-4">
              <button onClick={closeConfirm} className="flex-1 py-4 bg-slate-50 text-slate-500 rounded-2xl font-black text-sm hover:bg-slate-100 transition-all">Batal</button>
              <button onClick={() => { confirmModal.onConfirm(); closeConfirm(); }} className={`flex-1 py-4 text-white rounded-2xl font-black text-sm shadow-xl transition-all ${confirmModal.type === 'danger' ? 'bg-red-500 hover:bg-red-600' : 'bg-orange-500 hover:bg-orange-600'}`}>Ya, Lanjutkan</button>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { Loader2, UserPlus, Award, ChevronRight, Users, BookOpen, ClipboardList, School, Sparkles, TrendingUp } from 'lucide-react';
import { db } from '../../App.tsx';
import { Submission, User } from '../../types.ts';

interface OverviewTabProps {
  setActiveView: (v: string) => void;
}

const OverviewTab: React.FC<OverviewTabProps> = ({ setActiveView }) => {
  const [stats, setStats] = useState({ students: 0, classes: 0, materials: 0, tasks: 0, pending: 0, ungraded: 0 });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      setLoading(true);
      try {
        const [allUsers, pending, classes, materials, tasks, submissions] = await Promise.all([
          db.get('users'),
          db.get('elearning_pending_students'),
          db.get('elearning_classes_list'),
          db.get('elearning_materi_list'),
          db.get('elearning_tugas_list'),
          db.get('elearning_submissions_list')
        ]);

        // Hitung siswa aktif dari Master 'users'
        const activeStudents = Array.isArray(allUsers) ? allUsers.filter((u: any) => u.role === 'STUDENT' && u.status === 'ACTIVE').length : 0;

        setStats({
          students: activeStudents,
          pending: Array.isArray(pending) ? pending.length : 0,
          classes: Array.isArray(classes) ? classes.length : 0,
          materials: Array.isArray(materials) ? materials.length : 0,
          tasks: Array.isArray(tasks) ? tasks.length : 0,
          ungraded: Array.isArray(submissions) ? submissions.filter((s: Submission) => s.grade === undefined || s.grade === null).length : 0
        });
      } catch (err) {
        console.error("Gagal memuat statistik:", err);
      } finally {
        setLoading(false);
      }
    };
    fetch();
  }, []);

  if (loading) return (
