export const notifyStudents = async (
  targetClasses: string[], 
  title: string, 
  message: string, 
  type: 'material' | 'task' | 'grade' | 'registration', 
  studentId?: string
) => {
  try {
    const allUsers = await db.get('users');
    const studentList = Array.isArray(allUsers) ? allUsers.filter((u: any) => u.role === 'STUDENT') : [];

    const targets = studentId 
      ? studentList.filter(s => s.id === studentId)
      : studentList.filter(s => targetClasses.includes(s.classId || ''));

    for (const s of targets) {
      const newNotif: Partial<Notification> = {
        userId: s.id,
        title,
        message,
        type,
        read: false,
        createdAt: new Date().toLocaleString('id-ID')
      };
      await db.add('elearning_notifications', newNotif);
    }
  } catch (err) {
    console.error("Failed to notify students:", err);
  }
};

export const notifyAdmins = async (title: string, message: string) => {
  try {
    const allUsers = await db.get('users');
    const adminList = Array.isArray(allUsers) ? allUsers.filter((u: any) => u.role === 'ADMIN') : [];

    for (const admin of adminList) {
      const newNotif: Partial<Notification> = {
        userId: admin.id,
        title,
        message,
        type: 'registration',
        read: false,
        createdAt: new Date().toLocaleString('id-ID')
      };
      await db.add('elearning_notifications', newNotif);
    }
  } catch (err) {
    console.error("Failed to notify admins:", err);
  }
};

