interface ConfirmRegistrationsTabProps {
  triggerConfirm: any;
}

const ConfirmRegistrationsTab: React.FC<ConfirmRegistrationsTabProps> = ({ triggerConfirm }) => {
  const [pending, setPending] = useState<User[]>([]);
  const [loading, setLoading] = useState(false);
  const [search, setSearch] = useState('');
  const [isProcessing, setIsProcessing] = useState<string | null>(null);

  useEffect(() => { loadData(); }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const allUsers = await db.get('users');
      const pendingUsers = Array.isArray(allUsers) 
        ? allUsers.filter((u: any) => u.role === 'STUDENT' && u.status === 'PENDING') 
        : [];
      setPending(pendingUsers);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const filteredPending = useMemo(() => {
    return pending.filter(s => 
      s.name.toLowerCase().includes(search.toLowerCase()) || 
      s.username.toLowerCase().includes(search.toLowerCase())
    );
  }, [pending, search]);

  const handleApprove = async (student: User) => {
    setIsProcessing(student.id);
    try {
      await db.update('users', student.id, { status: 'ACTIVE' });
      setPending(pending.filter(s => s.id !== student.id));
      notifyStudents([], "Akun Aktif!", "Selamat, pendaftaran Anda telah disetujui Guru Informatika.", "registration", student.id);
      alert(`${student.name} berhasil diaktifkan!`);
    } catch (err) {
      alert("Gagal mengaktifkan akun.");
    } finally {
      setIsProcessing(null);
    }
  };

  const handleReject = (student: User) => {
    triggerConfirm(
      "Tolak Pendaftaran?", 
      `Hapus data pendaftaran ${student.name} secara permanen?`, 
      async () => {
        setIsProcessing(student.id);
        try {
          await db.delete('users', student.id);
          setPending(pending.filter(s => s.id !== student.id));
        } catch (err) {
          alert("Gagal menolak.");
        } finally {
          setIsProcessing(null);
        }
      }
    );
  };

  if (loading) return <div className="py-20 text-center text-black"><Loader2 className="animate-spin mx-auto text-orange-500 mb-4" size={40}/>Memuat pendaftar...</div>;

  return (
    <div className="space-y-8 text-black animate-in fade-in duration-500">
      <section className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex items-center gap-5">
           <div className="w-14 h-14 bg-orange-50 text-orange-600 rounded-2xl flex items-center justify-center shadow-inner">
              <Fingerprint size={28} />
           </div>
           <div>
              <h3 className="text-2xl font-black text-slate-800">Verifikasi Siswa</h3>
              <p className="text-slate-500 font-medium text-xs mt-1">Total {pending.length} antrean registrasi baru.</p>
           </div>
        </div>
        <div className="flex gap-4 w-full md:w-auto">
          <input 
            type="text" placeholder="Cari nama..." 
            value={search} onChange={e => setSearch(e.target.value)}
            className="flex-1 md:w-64 px-6 py-4 bg-slate-50 rounded-2xl border-none outline-none focus:ring-2 focus:ring-orange-500/20 font-bold"
          />
          <button onClick={loadData} className="p-4 bg-slate-50 rounded-2xl text-slate-400 hover:text-orange-500 transition-all"><RefreshCw size={20}/></button>
        </div>
      </section>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {filteredPending.map(s => (
          <div key={s.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col items-center text-center">
            <img src={s.avatar} className="w-20 h-20 rounded-full border-4 border-slate-50 shadow-sm mb-4" />
            <h4 className="font-black text-slate-800">{s.name}</h4>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Kelas {s.classId}</p>
            <div className="flex gap-3 mt-8 w-full">
               <button 
                  onClick={() => handleApprove(s)} 
                  disabled={isProcessing === s.id}
                  className="flex-1 py-4 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase hover:bg-emerald-600 transition-all disabled:opacity-50"
               >
                  Setujui
               </button>
               <button 
                  onClick={() => handleReject(s)} 
                  disabled={isProcessing === s.id}
                  className="px-5 py-4 bg-rose-50 text-rose-500 rounded-2xl hover:bg-rose-100 transition-all disabled:opacity-50"
               >
                  <UserX size={18} />
               </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

