import React, { useState, useEffect, useMemo } from 'react';
import { 
  Loader2, Plus, Search, Filter, BookOpen, Link as LinkIcon, 
  Edit, PlayCircle, FileText, SearchX, X, Info, 
  Zap, School, Save, Trash2, ExternalLink
} from 'lucide-react';
import { db } from '../../App.tsx';
import { Material, ClassRoom } from '../../types.ts';
import { notifyStudents } from '../../utils/helpers.ts';

interface ManageMaterialsTabProps {
  triggerConfirm: any;
  classes: ClassRoom[];
}

const ManageMaterialsTab: React.FC<ManageMaterialsTabProps> = ({ triggerConfirm, classes }) => {
  const [items, setItems] = useState<Material[]>([]);
  const [showModal, setShowModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [search, setSearch] = useState('');
  const [classFilter, setClassFilter] = useState('');
  const [form, setForm] = useState<Partial<Material>>({ 
    title: '', 
    description: '', 
    type: 'link', 
    content: '', 
    targetClassIds: [] 
  });

  useEffect(() => { loadData(); }, []);
  const loadData = async () => {
    setLoading(true);
    const saved = await db.get('elearning_materials');
    setItems(Array.isArray(saved) ? saved : []);
    setLoading(false);
  };

  const ensureArray = (data: any): string[] => {
    if (Array.isArray(data)) return data;
    if (typeof data === 'string') return data.split(',').filter(Boolean);
    return [];
  };

  const filteredItems = useMemo(() => items.filter(it => {
    const targetClasses = ensureArray(it.targetClassIds);
    const matchSearch = it.title.toLowerCase().includes(search.toLowerCase()) || 
                        it.description.toLowerCase().includes(search.toLowerCase());
    const matchClass = !classFilter || targetClasses.includes(classFilter);
    return matchSearch && matchClass;
  }), [items, search, classFilter]);

  const handleSave = async () => {
    if (!form.title || !form.content || ensureArray(form.targetClassIds).length === 0) { 
      alert("Mohon lengkapi Judul, Konten, dan minimal satu Kelas Target"); 
      return; 
    }

    setIsSaving(true);
    const isNew = !form.id;
    const newItem = { 
      ...form, 
      id: form.id || `mat_${Date.now()}`, 
      targetClassIds: ensureArray(form.targetClassIds).join(','),
      createdAt: form.createdAt || new Date().toLocaleString('id-ID')
    } as any;

    try {
      if (isNew) {
        await db.add('elearning_materials', newItem);
        setItems([newItem, ...items]);
        notifyStudents(ensureArray(newItem.targetClassIds), "Materi Baru!", newItem.title, "material");
      } else {
        await db.update('elearning_materials', newItem.id, newItem);
        setItems(items.map(it => it.id === newItem.id ? newItem : it));
      }
      setShowModal(false);
    } catch (err) {
      alert("Gagal menyimpan materi.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = (id: string, title: string) => {
    triggerConfirm(
      `Hapus Materi?`, 
      `Apakah Anda yakin ingin menghapus materi "${title}"?`, 
      async () => {
        try {
          await db.delete('elearning_materials', id);
          setItems(items.filter(it => it.id !== id));
        } catch (err) {
          alert("Gagal menghapus.");
        }
      }
    );
  };

  const getTypeIcon = (type: string) => {
    switch(type) {
      case 'link': return <LinkIcon size={16} className="text-blue-500" />;
      case 'embed': return <PlayCircle size={16} className="text-purple-500" />;
      case 'file': return <FileText size={16} className="text-emerald-500" />;
      default: return <BookOpen size={16} />;
    }
  };

  if (loading) return <div className="py-20 flex justify-center text-black"><Loader2 className="animate-spin text-emerald-600" size={40} /></div>;

  return (
    <div className="space-y-6 text-black animate-in fade-in duration-500 pb-20">
      <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center shadow-inner">
              <BookOpen size={20} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Perpustakaan Materi</h3>
              <p className="text-slate-500 font-medium text-xs mt-0.5">Kelola modul pembelajaran digital.</p>
            </div>
          </div>
          <button 
            onClick={() => { 
              setForm({ title: '', description: '', type: 'link', content: '', targetClassIds: [] }); 
              setShowModal(true); 
            }} 
            className="px-6 py-3 bg-emerald-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-emerald-700 shadow-lg shadow-emerald-100 active:scale-95 transition-all"
          >
            <Plus size={18}/> Tambah Materi
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-4">
        {filteredItems.map(it => (
          <div key={it.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col group relative overflow-hidden hover:shadow-xl hover:-translate-y-1 transition-all duration-300">
             <div className="absolute top-4 right-4 flex gap-1.5 opacity-0 group-hover:opacity-100 transition-all scale-90 group-hover:scale-100">
                <button onClick={() => { setForm({...it, targetClassIds: ensureArray(it.targetClassIds)}); setShowModal(true); }} className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-600 hover:text-white transition-all shadow-sm"><Edit size={14}/></button>
                <button onClick={() => handleDelete(it.id, it.title)} className="p-2 bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-600 hover:text-white transition-all shadow-sm"><Trash2 size={14}/></button>
             </div>

             <div className="flex items-center gap-3 mb-4">
                <div className="p-3 bg-slate-50 rounded-xl shadow-inner group-hover:bg-emerald-50 transition-colors">
                  {getTypeIcon(it.type)}
                </div>
                <div className="flex flex-col">
                  <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{it.type}</span>
                </div>
             </div>

             <h4 className="font-black text-slate-800 text-sm leading-tight mb-2 group-hover:text-emerald-600 transition-colors line-clamp-1">{it.title}</h4>
             <p className="text-[11px] text-slate-500 font-medium line-clamp-2 leading-relaxed mb-6">{it.description}</p>
          </div>
        ))}
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4 md:p-6 text-black">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl animate-in zoom-in-95 duration-300 relative flex flex-col max-h-[90vh]">
            <div className="p-8 border-b border-slate-50 flex items-center justify-between">
               <h3 className="text-2xl font-black text-slate-800">{form.id ? 'Edit Materi' : 'Materi Baru'}</h3>
               <button onClick={() => setShowModal(false)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl">
                  <X size={24} />
               </button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-6">
              <input value={form.title} onChange={e => setForm({...form, title: e.target.value})} placeholder="Judul Materi" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold" />
              <textarea value={form.description} onChange={e => setForm({...form, description: e.target.value})} placeholder="Deskripsi" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold h-28" />
              <input value={form.content} onChange={e => setForm({...form, content: e.target.value})} placeholder="URL Konten" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold" />
              <div className="grid grid-cols-2 gap-2">
                {classes.map(c => (
                  <button key={c.id} onClick={() => {
                    const current = ensureArray(form.targetClassIds);
                    setForm({...form, targetClassIds: current.includes(c.name) ? current.filter(x => x !== c.name) : [...current, c.name]});
                  }} className={`p-3 rounded-xl font-bold text-xs ${ensureArray(form.targetClassIds).includes(c.name) ? 'bg-emerald-600 text-white' : 'bg-slate-100 text-slate-500'}`}>
                    Kelas {c.name}
                  </button>
                ))}
              </div>
            </div>
            <div className="p-8 border-t border-slate-50">
              <button onClick={handleSave} disabled={isSaving} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest">
                {isSaving ? 'Menyimpan...' : 'Simpan Materi'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManageMaterialsTab;

