import React, { useState, useEffect, useMemo } from 'react';
import { 
  Loader2, Plus, Search, Filter, ClipboardList, Calendar, 
  Edit, Trash, CheckCircle, X, Info, Layers, Link as LinkIcon, 
  Youtube, FileCode, Clock, ToggleRight, ToggleLeft, School, 
  Save, Type, MessageSquare, CheckCircle2, ChevronRight, Zap, 
  SearchX, AlertCircle, CalendarDays, MousePointer2, PlayCircle,
  FileText, Globe, Trash2, ExternalLink
} from 'lucide-react';
import { db } from '../../App.tsx';
import { Task, ClassRoom } from '../../types.ts';
import { notifyStudents } from '../../utils/helpers.ts';

interface ManageTasksTabProps {
  triggerConfirm: any;
  classes: ClassRoom[];
}

const ManageTasksTab: React.FC<ManageTasksTabProps> = ({ triggerConfirm, classes }) => {
  const [items, setItems] = useState<Task[]>([]);
  const [showModal, setShowModal] = useState(false);
  const [search, setSearch] = useState('');
  const [classFilter, setClassFilter] = useState('');
  const [loading, setLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [form, setForm] = useState<Partial<Task>>({ 
    title: '', 
    description: '', 
    content: '', 
    targetClassIds: [], 
    dueDate: '', 
    isSubmissionEnabled: true, 
    type: 'link' 
  });

  useEffect(() => { loadData(); }, []);
  const loadData = async () => {
    setLoading(true);
    const saved = await db.get('elearning_tasks');
    setItems(Array.isArray(saved) ? saved : []);
    setLoading(false);
  };

  const ensureArray = (data: any): string[] => {
    if (Array.isArray(data)) return data;
    if (typeof data === 'string') return data.split(',').filter(Boolean);
    return [];
  };

  const filteredItems = useMemo(() => items.filter(it => {
    const targetClasses = ensureArray(it.targetClassIds);
    const matchSearch = it.title.toLowerCase().includes(search.toLowerCase()) || 
                        it.description.toLowerCase().includes(search.toLowerCase());
    const matchClass = !classFilter || targetClasses.includes(classFilter);
    return matchSearch && matchClass;
  }), [items, search, classFilter]);

  const handleSave = async () => {
    if (!form.title || !form.dueDate || ensureArray(form.targetClassIds).length === 0 || !form.content) { 
      alert("Mohon lengkapi Judul, Konten/Link, Tenggat, dan minimal satu Kelas."); 
      return; 
    }

    setIsSaving(true);
    const isNew = !form.id;
    const newItem = { 
      ...form, 
      id: form.id || `tsk_${Date.now()}`, 
      targetClassIds: ensureArray(form.targetClassIds).join(','),
      createdAt: form.createdAt || new Date().toLocaleString('id-ID')
    } as any;

    try {
      if (isNew) {
        await db.add('elearning_tasks', newItem);
        setItems([newItem, ...items]);
        notifyStudents(ensureArray(newItem.targetClassIds), "Tugas Baru!", newItem.title, "task");
      } else {
        await db.update('elearning_tasks', newItem.id, newItem);
        setItems(items.map(it => it.id === newItem.id ? newItem : it));
      }
      setShowModal(false);
    } catch (err) {
      alert("Gagal menyimpan tugas.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = (id: string, title: string) => {
    triggerConfirm(
      `Hapus Tugas?`, 
      `Apakah Anda yakin ingin menghapus tugas "${title}"?`, 
      async () => {
        try {
          await db.delete('elearning_tasks', id);
          setItems(items.filter(it => it.id !== id));
        } catch (err) {
          alert("Gagal menghapus tugas.");
        }
      }
    );
  };

  if (loading) return <div className="py-20 flex flex-col items-center justify-center gap-4 text-black">
    <Loader2 className="animate-spin text-purple-600" size={40} />
    <p className="text-slate-400 font-bold text-[9px] uppercase tracking-widest">Memuat Daftar Tugas...</p>
  </div>;

  return (
    <div className="space-y-6 text-black animate-in fade-in duration-500 pb-20">
      <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-purple-50 text-purple-600 rounded-xl flex items-center justify-center shadow-inner">
              <ClipboardList size={20} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Manajemen Tugas</h3>
              <p className="text-slate-500 font-medium text-xs mt-0.5">Kelola penugasan informatika.</p>
            </div>
          </div>
          <button 
            onClick={() => { 
              setForm({ title: '', description: '', content: '', targetClassIds: [], dueDate: '', isSubmissionEnabled: true, type: 'link' }); 
              setShowModal(true); 
            }} 
            className="px-6 py-3 bg-purple-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-purple-700 shadow-lg active:scale-95 transition-all"
          >
            <Plus size={18}/> Tambah Tugas
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-4">
        {filteredItems.map(it => (
            <div key={it.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col group relative overflow-hidden hover:shadow-xl hover:-translate-y-1 transition-all duration-300">
               <div className="absolute top-4 right-4 flex gap-1.5 opacity-0 group-hover:opacity-100 transition-all z-10">
                  <button onClick={() => { setForm({...it, targetClassIds: ensureArray(it.targetClassIds)}); setShowModal(true); }} className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-600 hover:text-white transition-all shadow-sm"><Edit size={14}/></button>
                  <button onClick={() => handleDelete(it.id, it.title)} className="p-2 bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-600 hover:text-white transition-all shadow-sm"><Trash2 size={14}/></button>
               </div>
               <h4 className="font-black text-slate-800 text-sm leading-tight mb-2 group-hover:text-purple-600 line-clamp-1">{it.title}</h4>
               <p className="text-[10px] text-slate-400 font-bold mb-4">Tenggat: {it.dueDate}</p>
            </div>
          )
        )}
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4 text-black">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl relative flex flex-col max-h-[90vh]">
            <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-white shrink-0">
               <h3 className="text-2xl font-black text-slate-800">{form.id ? 'Edit Tugas' : 'Tugas Baru'}</h3>
               <button onClick={() => setShowModal(false)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-rose-50 hover:text-rose-500 transition-all">
                  <X size={24} />
               </button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-6">
              <input value={form.title} onChange={e => setForm({...form, title: e.target.value})} placeholder="Judul Tugas" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold" />
              <textarea value={form.description} onChange={e => setForm({...form, description: e.target.value})} placeholder="Deskripsi Tugas" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold h-24" />
              <input type="date" value={form.dueDate} onChange={e => setForm({...form, dueDate: e.target.value})} className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold" />
              <input value={form.content} onChange={e => setForm({...form, content: e.target.value})} placeholder="Link Tugas" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold" />
              <div className="grid grid-cols-2 gap-2">
                {classes.map(c => (
                  <button key={c.id} onClick={() => {
                    const current = ensureArray(form.targetClassIds);
                    setForm({...form, targetClassIds: current.includes(c.name) ? current.filter(x => x !== c.name) : [...current, c.name]});
                  }} className={`p-3 rounded-xl font-bold text-xs ${ensureArray(form.targetClassIds).includes(c.name) ? 'bg-purple-600 text-white' : 'bg-slate-100 text-slate-500'}`}>
                    Kelas {c.name}
                  </button>
                ))}
              </div>
            </div>
            <div className="p-8 border-t border-slate-50 shrink-0">
              <button onClick={handleSave} disabled={isSaving} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-purple-600 transition-all">
                {isSaving ? 'Menyimpan...' : 'Simpan Tugas'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManageTasksTab;

import React, { useState, useMemo } from 'react';
import { 
  ClipboardList, CheckCircle2, Clock, Calendar, 
  AlertCircle, Send, LayoutList, CheckCircle, 
  ArrowRight, MessageSquare, Star, Loader2,
  X, Info, ExternalLink, Filter, Globe, PlayCircle,
  Link as LinkIcon, FileText, Zap, ChevronRight,
  Trophy, MousePointer2, Monitor, ArrowUpRight,
  PartyPopper, ShieldCheck
} from 'lucide-react';
import { db } from '../../App.tsx';
import { User, Submission, Task } from '../../types.ts';

interface TasksTabProps {
  user: User;
  tasks: Task[];
  submissions: Submission[];
  onRefresh: () => void;
}

const TasksTab: React.FC<TasksTabProps> = ({ user, tasks, submissions, onRefresh }) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [link, setLink] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [activeFilter, setActiveFilter] = useState<'all' | 'pending' | 'completed'>('all');

  const getDeadlineInfo = (dueDate: string) => {
    const now = new Date();
    const deadline = new Date(dueDate);
    const diffTime = deadline.getTime() - now.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return { label: 'Lampau', color: 'text-rose-500 bg-rose-50', icon: AlertCircle };
    if (diffDays <= 2) return { label: `${diffDays} hari`, color: 'text-orange-500 bg-orange-50', icon: Clock };
    return { label: `${diffDays} hari`, color: 'text-emerald-500 bg-emerald-50', icon: Calendar };
  };

  const getTypeStyle = (type: string) => {
    switch(type) {
      case 'embed': return { bg: 'bg-purple-50', text: 'text-purple-600', icon: PlayCircle, label: 'Interaktif' };
      case 'file': return { bg: 'bg-emerald-50', text: 'text-emerald-600', icon: FileText, label: 'Modul' };
      case 'link': return { bg: 'bg-blue-50', text: 'text-blue-600', icon: LinkIcon, label: 'Tautan' };
      default: return { bg: 'bg-slate-50', text: 'text-slate-600', icon: ClipboardList, label: 'Tugas' };
    }
  };

  const filteredTasks = useMemo(() => {
    return tasks.filter(t => {
      const isSubmitted = submissions.some(s => s.taskId === t.id);
      if (activeFilter === 'pending') return !isSubmitted;
      if (activeFilter === 'completed') return isSubmitted;
      return true;
    });
  }, [tasks, submissions, activeFilter]);

  const stats = useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter(t => submissions.some(s => s.taskId === t.id)).length;
    return { total, completed, pending: total - completed };
  }, [tasks, submissions]);

  const getEmbedUrl = (url: string) => {
    if (!url) return '';
    let embedUrl = url;
    if (url.includes('youtube.com/watch?v=')) {
      embedUrl = url.replace('watch?v=', 'embed/');
    } else if (url.includes('youtu.be/')) {
      embedUrl = 'https://www.youtube.com/embed/' + url.split('youtu.be/')[1];
    } else if (url.includes('docs.google.com')) {
      embedUrl = url.includes('?') ? `${url}&embedded=true` : `${url}?embedded=true`;
    }
    return embedUrl;
  };

  const handleSubmit = async () => {
    if (!link && selectedTask?.isSubmissionEnabled) return alert("Masukkan link hasil pengerjaan Anda!");
    if (!selectedTask) return;

    setSubmitting(true);
    const newSub: Submission = {
      id: `sub_${Date.now()}`,
      taskId: selectedTask.id,
      studentId: user.id,
      content: link || 'Tugas Selesai (Tanpa Link)',
      submittedAt: new Date().toLocaleString('id-ID'),
    };

    try {
      await db.add('elearning_submissions', newSub);
      onRefresh();
      setLink('');
      setSelectedTask(null);
      alert("Tugas berhasil dikirim!");
    } catch (err) {
      alert("Gagal mengirim tugas. Coba lagi.");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700 text-black pb-24">
      <section className="grid grid-cols-3 gap-4">
        {[
          { label: 'Total', val: stats.total, color: 'bg-indigo-600', icon: LayoutList },
          { label: 'Proses', val: stats.pending, color: 'bg-orange-500', icon: Clock },
          { label: 'Selesai', val: stats.completed, color: 'bg-emerald-500', icon: CheckCircle2 }
        ].map(s => (
          <div key={s.label} className={`${s.color} p-5 rounded-[1.8rem] text-white flex flex-col justify-center`}>
            <p className="text-[8px] font-black uppercase tracking-widest opacity-70 mb-1">{s.label}</p>
            <h4 className="text-2xl font-black">{s.val}</h4>
          </div>
        ))}
      </section>

      <section className="flex flex-wrap gap-2">
        {['all', 'pending', 'completed'].map(tab => (
          <button
            key={tab}
            onClick={() => setActiveFilter(tab as any)}
            className={`px-5 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${
              activeFilter === tab ? 'bg-slate-900 text-white shadow-lg' : 'bg-white text-slate-400 border border-slate-100'
            }`}
          >
            {tab === 'all' ? 'Semua' : tab === 'pending' ? 'Perlu Dikerjakan' : 'Selesai'}
          </button>
        ))}
      </section>

      <section className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-5">
        {filteredTasks.map(t => {
          const submission = submissions.find(s => s.taskId === t.id);
          const deadline = getDeadlineInfo(t.dueDate);
          const typeStyle = getTypeStyle(t.type);
          return (
            <div key={t.id} className="bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all duration-300 group flex flex-col overflow-hidden relative">
              <div className={`h-16 ${typeStyle.bg} flex items-center justify-center relative`}>
                 <div className="absolute top-3 right-3">
                    <span className={`px-2 py-0.5 rounded-md text-[7px] font-black uppercase tracking-widest flex items-center gap-1 bg-white/80 ${deadline.color}`}>
                      {deadline.label}
                    </span>
                 </div>
                 <typeStyle.icon size={28} className={`${typeStyle.text} opacity-20`} />
              </div>
              <div className="p-5 flex-1 flex flex-col">
                <h4 className="text-base font-black text-slate-800 mb-2 leading-tight group-hover:text-indigo-600 line-clamp-2">{t.title}</h4>
                <div className="mt-auto">
                  <button 
                    onClick={() => setSelectedTask(t)}
                    className={`w-full py-3 rounded-xl font-black text-[9px] uppercase tracking-widest transition-all ${
                      submission ? 'bg-slate-50 text-slate-500' : 'bg-slate-900 text-white hover:bg-indigo-600'
                    }`}
                  >
                    {submission ? 'Detail Nilai' : 'Kerjakan'} 
                  </button>
                </div>
              </div>
            </div>
          );
        })}
      </section>

      {selectedTask && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[100] flex items-center justify-center p-4 md:p-8">
            <div className="bg-white w-full max-w-7xl h-full md:max-h-[95vh] md:rounded-[3.5rem] shadow-2xl flex flex-col overflow-hidden">
              <div className="p-6 border-b border-slate-50 flex items-center justify-between bg-white shrink-0">
                 <h3 className="text-lg font-black text-slate-800">{selectedTask.title}</h3>
                 <button onClick={() => setSelectedTask(null)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-rose-50 hover:text-rose-500 transition-all">
                    <X size={24} />
                 </button>
              </div>
              <div className="flex-1 flex flex-col lg:flex-row overflow-hidden">
                <div className="flex-[3] bg-slate-100 p-4 overflow-hidden border-r border-slate-50">
                  <iframe src={getEmbedUrl(selectedTask.content)} className="w-full h-full border-0 rounded-2xl bg-white" allowFullScreen title="Task Content"></iframe>
                </div>
                <div className="flex-1 bg-white p-6 overflow-y-auto flex flex-col space-y-6">
                  <div className="space-y-4">
                    <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400">Instruksi</h4>
                    <p className="text-xs text-slate-700 font-medium leading-relaxed italic bg-slate-50 p-6 rounded-2xl border border-slate-100">
                      "{selectedTask.description || 'Selesaikan tepat waktu.'}"
                    </p>
                  </div>
                  {selectedTask.isSubmissionEnabled && !submissions.some(s => s.taskId === selectedTask.id) && (
                    <div className="space-y-4 pt-4 border-t border-slate-50">
                      <input 
                        type="url"
                        value={link} 
                        onChange={e => setLink(e.target.value)} 
                        placeholder="Link Pekerjaan Kamu (Drive/Canva)" 
                        className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-xs font-bold outline-none focus:border-emerald-500 transition-all" 
                      />
                      <button onClick={handleSubmit} disabled={submitting} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-emerald-600 transition-all flex items-center justify-center gap-2">
                        {submitting ? <Loader2 size={16} className="animate-spin" /> : <Send size={16} />}
                        Kirim Sekarang
                      </button>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
      )}
    </div>
  );
};

export default TasksTab;

import { db } from '../App.tsx';
import { Notification, User } from '../types.ts';

export const notifyStudents = async (
  targetClasses: string[], 
  title: string, 
  message: string, 
  type: 'material' | 'task' | 'grade' | 'registration', 
  studentId?: string
) => {
  try {
    let targets: any[] = [];

    if (studentId) {
      // Jika ada studentId spesifik, ambil satu user saja
      const user = await db.getSingle('users', studentId);
      if (user) targets = [user];
    } else if (targetClasses.length > 0) {
      // Jika berbasis kelas, ambil user per kelas (lebih efisien)
      const allStudents = await db.getByQuery('users', 'role', 'STUDENT');
      targets = allStudents.filter((s: any) => targetClasses.includes(s.classId || ''));
    }

    for (const s of targets) {
      const newNotif: Partial<Notification> = {
        userId: s.id,
        title,
        message,
        type,
        read: false,
        createdAt: new Date().toLocaleString('id-ID')
      };
      await db.add('elearning_notifications', newNotif);
    }
  } catch (err) {
    console.error("Failed to notify students:", err);
  }
};

export const notifyAdmins = async (title: string, message: string) => {
  try {
    const adminList = await db.getByQuery('users', 'role', 'ADMIN');

    for (const admin of adminList) {
      const newNotif: Partial<Notification> = {
        userId: admin.id,
        title,
        message,
        type: 'registration',
        read: false,
        createdAt: new Date().toLocaleString('id-ID')
      };
      await db.add('elearning_notifications', newNotif);
    }
  } catch (err) {
    console.error("Failed to notify admins:", err);
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Loader2, UserCheck, UserX, Search, Users, 
  Clock, SearchX, RefreshCw, Fingerprint, 
  CheckCircle2, XCircle, AlertCircle, Calendar,
  UserCircle
} from 'lucide-react';
import { db } from '../../App.tsx';
import { User } from '../../types.ts';
import { notifyStudents } from '../../utils/helpers.ts';

interface ConfirmRegistrationsTabProps {
  triggerConfirm: any;
}

const ConfirmRegistrationsTab: React.FC<ConfirmRegistrationsTabProps> = ({ triggerConfirm }) => {
  const [pending, setPending] = useState<User[]>([]);
  const [loading, setLoading] = useState(false);
  const [search, setSearch] = useState('');
  const [isProcessing, setIsProcessing] = useState<string | null>(null);

  useEffect(() => { loadData(); }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      // Menggunakan query status PENDING (Lebih aman & cepat)
      const pendingUsers = await db.getByQuery('users', 'status', 'PENDING');
      setPending(Array.isArray(pendingUsers) ? pendingUsers : []);
    } catch (err) {
      console.error("Error loading pending users:", err);
    } finally {
      setLoading(false);
    }
  };

  const filteredPending = useMemo(() => {
    return pending.filter(s => 
      s.name.toLowerCase().includes(search.toLowerCase()) || 
      s.username.toLowerCase().includes(search.toLowerCase())
    );
  }, [pending, search]);

  const handleApprove = async (student: User) => {
    setIsProcessing(student.id);
    try {
      await db.update('users', student.id, { status: 'ACTIVE' });
      setPending(prev => prev.filter(s => s.id !== student.id));

      // Kirim notifikasi selamat ke siswa
      await notifyStudents([], "Akun Aktif!", "Selamat, pendaftaran Anda telah disetujui Guru Informatika. Silakan login.", "registration", student.id);

      // Feedback sukses visual bisa ditambahkan di sini jika perlu
    } catch (err) {
      alert("Gagal mengaktifkan akun. Silakan coba lagi.");
    } finally {
      setIsProcessing(null);
    }
  };

  const handleReject = (student: User) => {
    triggerConfirm(
      "Tolak Pendaftaran?", 
      `Apakah Anda yakin ingin menghapus data pendaftaran ${student.name}? Tindakan ini permanen.`, 
      async () => {
        setIsProcessing(student.id);
        try {
          await db.delete('users', student.id);
          setPending(prev => prev.filter(s => s.id !== student.id));
        } catch (err) {
          alert("Gagal menolak pendaftaran.");
        } finally {
          setIsProcessing(null);
        }
      },
      'danger'
    );
  };

  if (loading) return (
    <div className="py-32 flex flex-col items-center justify-center gap-4 text-black">
      <div className="w-12 h-12 border-4 border-orange-100 border-t-orange-500 rounded-full animate-spin"></div>
      <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Memindai Antrean Registrasi...</p>
    </div>
  );

  return (
    <div className="space-y-8 text-black animate-in fade-in duration-500 pb-20">
      {/* Header Panel */}
      <section className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex items-center gap-5">
           <div className="w-16 h-16 bg-orange-50 text-orange-600 rounded-[1.5rem] flex items-center justify-center shadow-inner group-hover:rotate-6 transition-transform">
              <Fingerprint size={32} />
           </div>
           <div>
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">Verifikasi Siswa</h3>
              <p className="text-slate-500 font-medium text-sm mt-1">
                {pending.length > 0 
                  ? `Ada ${pending.length} pendaftaran baru yang butuh persetujuan.` 
                  : 'Semua pendaftaran telah diproses.'}
              </p>
           </div>
        </div>
        <div className="flex gap-4 w-full md:w-auto">
          <div className="relative flex-1 md:w-64">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
            <input 
              type="text" placeholder="Cari nama siswa..." 
              value={search} onChange={e => setSearch(e.target.value)}
              className="w-full pl-11 pr-4 py-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-orange-500/20 outline-none font-bold text-sm transition-all"
            />
          </div>
          <button 
            onClick={loadData} 
            className="p-4 bg-slate-50 rounded-2xl text-slate-400 hover:text-orange-500 hover:bg-orange-50 transition-all active:scale-90"
            title="Refresh Data"
          >
            <RefreshCw size={20} className={loading ? 'animate-spin' : ''}/>
          </button>
        </div>
      </section>

      {/* Grid Content */}
      {filteredPending.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {filteredPending.map(s => (
            <div key={s.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col items-center text-center relative group hover:shadow-2xl hover:-translate-y-1 transition-all duration-300">
              <div className="relative mb-6">
                <img 
                  src={s.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${s.username}`} 
                  className="w-24 h-24 rounded-full border-4 border-slate-50 shadow-xl bg-slate-50" 
                  alt={s.name}
                />
                <div className="absolute -bottom-1 -right-1 bg-orange-500 p-2 rounded-full border-4 border-white">
                  <Clock size={14} className="text-white" />
                </div>
              </div>

              <h4 className="font-black text-slate-800 text-lg leading-tight line-clamp-1">{s.name}</h4>
              <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mt-1 mb-4">@{s.username}</p>

              <div className="flex items-center gap-2 px-4 py-2 bg-slate-50 rounded-full mb-8">
                <Users size={12} className="text-slate-400" />
                <span className="text-[10px] font-black text-slate-600 uppercase tracking-tight">Kelas {s.classId || 'N/A'}</span>
              </div>

              <div className="flex gap-3 mt-auto w-full">
                 <button 
                    onClick={() => handleApprove(s)} 
                    disabled={isProcessing === s.id}
                    className="flex-1 py-4 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-600 transition-all disabled:opacity-50 flex items-center justify-center gap-2 active:scale-95 shadow-lg shadow-slate-100"
                 >
                    {isProcessing === s.id ? <Loader2 size={16} className="animate-spin" /> : <UserCheck size={16} />}
                    Setujui
                 </button>
                 <button 
                    onClick={() => handleReject(s)} 
                    disabled={isProcessing === s.id}
                    className="px-5 py-4 bg-rose-50 text-rose-500 rounded-2xl hover:bg-rose-500 hover:text-white transition-all disabled:opacity-50 active:scale-95 border border-rose-100"
                    title="Tolak Pendaftaran"
                 >
                    <UserX size={20} />
                 </button>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-[3rem] border-2 border-dashed border-slate-200 p-20 flex flex-col items-center text-center">
          <div className="w-20 h-20 bg-slate-50 text-slate-300 rounded-3xl flex items-center justify-center mb-6">
            <SearchX size={40} />
          </div>
          <h4 className="text-xl font-black text-slate-400">Tidak Ada Antrean</h4>
          <p className="text-slate-400 font-medium text-sm max-w-xs mt-2 italic">
            {search ? `Tidak ditemukan pendaftar dengan nama "${search}"` : 'Semua pendaftaran siswa sudah diverifikasi atau belum ada pendaftar baru.'}
          </p>
          {search && (
            <button 
              onClick={() => setSearch('')}
              className="mt-6 text-[10px] font-black uppercase tracking-widest text-orange-500 hover:underline"
            >
              Reset Pencarian
            </button>
          )}
        </div>
      )}
    </div>
  );
};

export default ConfirmRegistrationsTab;

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Lock, User as UserIcon, Eye, EyeOff, AlertCircle, RefreshCw, ShieldCheck, Sparkles, GraduationCap, Laptop } from 'lucide-react';
import { Role, User } from '../types';
import { auth, firestore } from '../firebase.ts';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword } from "firebase/auth";
import { doc, getDoc, getDocs, collection, setDoc, query, where, limit } from "firebase/firestore";

interface LoginProps {
  role: Role;
  onBack: () => void;
  onLogin: (user: User) => void;
  onNavigateSignup: () => void;
}

const Login: React.FC<LoginProps> = ({ role, onBack, onLogin, onNavigateSignup }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<{message: string; hint?: string}>({message: ''});
  const [loading, setLoading] = useState(false);
  const [isEmptyDb, setIsEmptyDb] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);

  const isAdmin = role === 'ADMIN';

  useEffect(() => {
    const checkUsers = async () => {
      try {
        const querySnapshot = await getDocs(query(collection(firestore, "users"), limit(1)));
        if (querySnapshot.empty) {
          setIsEmptyDb(true);
        }
      } catch (e) {
        console.warn("Status koleksi users tidak dapat dicek.");
      }
    };
    if (isAdmin) checkUsers();
  }, [isAdmin]);

  const handleCreateInitialAdmin = async () => {
    setIsInitializing(true);
    setError({message: ''});
    const adminUsername = "admin";
    const adminPass = "admin123";
    const email = `${adminUsername}@alirsyad.sch.id`;

    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, adminPass);
      const firebaseUser = userCredential.user;

      const adminData: User = {
        id: firebaseUser.uid,
        name: "Admin Utama Informatika",
        username: adminUsername,
        role: 'ADMIN',
        status: 'ACTIVE',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=admin`
      };

      await setDoc(doc(firestore, "users", firebaseUser.uid), adminData);

      alert(`ADMIN BERHASIL DIBUAT!\n\nUsername: ${adminUsername}\nPassword: ${adminPass}`);
      setIsEmptyDb(false);
      setUsername(adminUsername);
      setPassword(adminPass);
    } catch (err: any) {
      setError({message: "Gagal Inisialisasi: " + err.message});
    } finally {
      setIsInitializing(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError({message: ''});
    setLoading(true);

    const cleanUsername = username.trim().toLowerCase();
    const email = `${cleanUsername}@alirsyad.sch.id`;

    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      // Ambil profil dari satu sumber utama: 'users'
      const masterDoc = await getDoc(doc(firestore, "users", firebaseUser.uid));

      if (masterDoc.exists()) {
        const userData = masterDoc.data() as User;

        if (userData.role !== role) {
          await auth.signOut();
          setError({message: `Akses Ditolak: Akun ini terdaftar sebagai ${userData.role}.`});
          return;
        }

        if (userData.role === 'STUDENT' && userData.status !== 'ACTIVE') {
          await auth.signOut();
          setError({message: "Akun Anda sedang menunggu verifikasi Guru Informatika."});
          return;
        }

        onLogin({ ...userData, id: firebaseUser.uid });
      } else {
        await auth.signOut();
        setError({message: "Profil akun tidak ditemukan di database Cloud."});
      }
    } catch (err: any) {
      if (err.code === 'auth/invalid-credential' || err.code === 'auth/wrong-password' || err.code === 'auth/user-not-found') {
        setError({message: "Username atau Password salah. Pastikan penulisan benar."});
      } else if (err.code === 'auth/network-request-failed') {
        setError({message: "Masalah koneksi internet."});
      } else {
        setError({message: "Gagal masuk: " + (err.message || "Kesalahan sistem.")});
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-white selection:bg-indigo-100 selection:text-indigo-900">
      <div className={`hidden md:flex flex-1 items-center justify-center p-20 relative overflow-hidden transition-colors duration-700 ${isAdmin ? 'bg-slate-900' : 'bg-blue-600'}`}>
        <div className={`absolute top-0 right-0 w-96 h-96 rounded-full blur-[120px] -mr-48 -mt-48 transition-colors ${isAdmin ? 'bg-emerald-500/20' : 'bg-white/20'}`}></div>
        <div className="relative z-10 text-white max-w-md space-y-8 animate-in fade-in slide-in-from-left-10 duration-1000">
          <div className={`w-20 h-20 rounded-3xl flex items-center justify-center shadow-2xl ${isAdmin ? 'bg-emerald-500' : 'bg-white text-blue-600'}`}>
             {isAdmin ? <ShieldCheck size={40} /> : <GraduationCap size={40} />}
          </div>
          <div className="space-y-4">
            <h2 className="text-6xl font-black leading-tight tracking-tighter">
              Portal Cloud<br/>
              <span className={isAdmin ? 'text-emerald-400 italic' : 'text-blue-200 italic'}>
                {isAdmin ? 'Guru / Admin' : 'Siswa Informatika'}
              </span>
            </h2>
            <div className="h-1.5 w-24 bg-white/20 rounded-full"></div>
            <p className="text-xl text-white/70 font-medium leading-relaxed">
              {isAdmin ? "Manajemen kurikulum & pantau progres siswa." : "Akses materi digital & kumpulkan tugas Anda."}
            </p>
          </div>
        </div>
      </div>

      <div className="flex-1 bg-white flex flex-col justify-center items-center px-8 py-12 md:px-20">
        <div className="w-full max-w-md">
          <button onClick={onBack} className="flex items-center gap-3 text-slate-400 hover:text-slate-900 mb-12 font-black text-xs uppercase tracking-widest group">
            <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" /> Beranda
          </button>

          <div className="mb-10 space-y-2">
            <h3 className="text-5xl font-black text-slate-900 tracking-tighter">
              {isAdmin ? 'Masuk Guru' : 'Masuk Siswa'}
            </h3>
            <p className="text-slate-500 font-bold italic">SMP Al Irsyad Surakarta</p>
          </div>

          {error.message && (
            <div className="mb-8 p-5 bg-rose-50 border border-rose-100 rounded-3xl animate-in fade-in slide-in-from-top-2">
              <div className="flex items-start gap-4">
                <div className="w-10 h-10 bg-rose-100 text-rose-600 rounded-2xl flex items-center justify-center shrink-0">
                  <AlertCircle size={20} />
                </div>
                <p className="text-xs font-black text-rose-600 leading-tight">{error.message}</p>
              </div>
            </div>
          )}

          {isEmptyDb && isAdmin && (
            <div className="mb-10 p-8 bg-indigo-50 border-2 border-dashed border-indigo-200 rounded-[2.5rem] space-y-4">
               <p className="text-xs text-indigo-600 font-bold">Admin belum ada. Klik di bawah untuk inisialisasi akun Admin utama.</p>
               <button onClick={handleCreateInitialAdmin} disabled={isInitializing} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl disabled:opacity-50">
                 {isInitializing ? <RefreshCw className="animate-spin" size={18} /> : 'Buat Admin Sekarang'}
               </button>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-8">
            <div className="space-y-3">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-2">Username</label>
              <div className="relative group">
                <UserIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-500" size={22} />
                <input 
                  type="text" 
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  placeholder="Username"
                  className="w-full pl-14 pr-6 py-5 bg-slate-50 border-2 border-slate-50 rounded-[1.8rem] outline-none transition-all font-black text-slate-800 focus:border-blue-500/30 shadow-inner"
                  required
                />
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-2">Kata Sandi</label>
              <div className="relative group">
                <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-500" size={22} />
                <input 
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full pl-14 pr-14 py-5 bg-slate-50 border-2 border-slate-50 rounded-[1.8rem] outline-none transition-all font-black text-slate-800 focus:border-blue-500/30 shadow-inner"
                  required
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600">
                  {showPassword ? <EyeOff size={22} /> : <Eye size={22} />}
                </button>
              </div>
            </div>

            <button 
              disabled={loading} 
              className={`w-full py-6 rounded-[1.8rem] font-black text-lg shadow-2xl transition-all disabled:opacity-50 active:scale-[0.98] flex items-center justify-center gap-4 ${isAdmin ? 'bg-slate-900 text-white hover:bg-emerald-600' : 'bg-blue-600 text-white hover:bg-slate-900'}`}
            >
              {loading ? <RefreshCw className="animate-spin" size={26} /> : 'Login Sekarang'}
            </button>

            {role === 'STUDENT' && (
              <div className="text-center pt-4">
                <p className="text-slate-500 font-bold text-sm">
                  Belum punya akun? <button type="button" onClick={onNavigateSignup} className="text-blue-600 font-black hover:underline underline-offset-4">Daftar Cloud Siswa</button>
                </p>
              </div>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Loader2, Plus, Search, Filter, BookOpen, Link as LinkIcon, 
  Edit, PlayCircle, FileText, SearchX, X, Info, 
  Zap, School, Save, Trash2, ExternalLink, Globe,
  LayoutGrid, Youtube, FileCode, CheckCircle2,
  ChevronRight, Bookmark
} from 'lucide-react';
import { db } from '../../App.tsx';
import { Material, ClassRoom } from '../../types.ts';
import { notifyStudents } from '../../utils/helpers.ts';

interface ManageMaterialsTabProps {
  triggerConfirm: any;
  classes: ClassRoom[];
}

const ManageMaterialsTab: React.FC<ManageMaterialsTabProps> = ({ triggerConfirm, classes }) => {
  const [items, setItems] = useState<Material[]>([]);
  const [showModal, setShowModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [search, setSearch] = useState('');
  const [classFilter, setClassFilter] = useState('');
  const [form, setForm] = useState<Partial<Material>>({ 
    title: '', 
    description: '', 
    type: 'link', 
    content: '', 
    targetClassIds: [] 
  });

  useEffect(() => { loadData(); }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const saved = await db.get('elearning_materials');
      setItems(Array.isArray(saved) ? saved : []);
    } catch (err) {
      console.error("Gagal memuat materi:", err);
    } finally {
      setLoading(false);
    }
  };

  const ensureArray = (data: any): string[] => {
    if (Array.isArray(data)) return data;
    if (typeof data === 'string') return data.split(',').filter(Boolean);
    return [];
  };

  const filteredItems = useMemo(() => items.filter(it => {
    const targetClasses = ensureArray(it.targetClassIds);
    const matchSearch = it.title.toLowerCase().includes(search.toLowerCase()) || 
                        it.description.toLowerCase().includes(search.toLowerCase());
    const matchClass = !classFilter || targetClasses.includes(classFilter);
    return matchSearch && matchClass;
  }), [items, search, classFilter]);

  const handleSave = async () => {
    if (!form.title || !form.content || ensureArray(form.targetClassIds).length === 0) { 
      alert("Mohon lengkapi Judul, Link Konten, dan minimal satu Kelas Target"); 
      return; 
    }

    setIsSaving(true);
    const isNew = !form.id;
    // Simpan sebagai array di Firestore sesuai types.ts
    const newItem: Material = { 
      ...form, 
      id: form.id || `mat_${Date.now()}`, 
      targetClassIds: ensureArray(form.targetClassIds),
      createdAt: form.createdAt || new Date().toLocaleString('id-ID'),
      type: form.type as any || 'link',
      title: form.title || '',
      description: form.description || '',
      content: form.content || ''
    } as Material;

    try {
      if (isNew) {
        await db.add('elearning_materials', newItem);
        setItems([newItem, ...items]);
        await notifyStudents(newItem.targetClassIds, "Materi Baru!", `Guru telah mempublikasikan materi: ${newItem.title}`, "material");
      } else {
        await db.update('elearning_materials', newItem.id, newItem);
        setItems(items.map(it => it.id === newItem.id ? newItem : it));
      }
      setShowModal(false);
    } catch (err) {
      alert("Gagal menyimpan materi ke Cloud.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = (id: string, title: string) => {
    triggerConfirm(
      `Hapus Materi?`, 
      `Materi "${title}" akan dihapus permanen. Siswa tidak akan bisa lagi mengakses konten ini.`, 
      async () => {
        try {
          await db.delete('elearning_materials', id);
          setItems(items.filter(it => it.id !== id));
        } catch (err) {
          alert("Gagal menghapus materi.");
        }
      }
    );
  };

  const getTypeStyle = (type: string) => {
    switch(type) {
      case 'link': return { icon: LinkIcon, color: 'text-blue-500', bg: 'bg-blue-50', border: 'border-blue-100', label: 'Tautan' };
      case 'embed': return { icon: Youtube, color: 'text-rose-500', bg: 'bg-rose-50', border: 'border-rose-100', label: 'Interaktif' };
      case 'file': return { icon: FileText, color: 'text-emerald-500', bg: 'bg-emerald-50', border: 'border-emerald-100', label: 'Dokumen' };
      default: return { icon: BookOpen, color: 'text-slate-500', bg: 'bg-slate-50', border: 'border-slate-100', label: 'Materi' };
    }
  };

  if (loading) return (
    <div className="py-32 flex flex-col items-center justify-center gap-4 text-black">
      <Loader2 className="animate-spin text-emerald-600" size={48} />
      <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Sinkronisasi Cloud...</p>
    </div>
  );

  return (
    <div className="space-y-8 text-black animate-in fade-in duration-500 pb-24">
      {/* Action Header */}
      <section className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex items-center gap-5">
