      id: form.id || `std_${Date.now()}`, 
      role: 'STUDENT', 
      avatar: form.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${form.username || 'default'}`, 
      status: 'ACTIVE',
      createdAt: form.createdAt || new Date().toLocaleString('id-ID')
    } as User;

    try {
      if (form.id) {
        await db.update('users', form.id, studentData);
        setStudents(prev => prev.map(s => s.id === form.id ? studentData : s));
      } else {
        await db.add('users', studentData);
        setStudents(prev => [studentData, ...prev]);
      }
      setShowModal(false);
    } catch (err) {
      alert("Gagal menyimpan data siswa ke Cloud.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = (id: string, name: string) => {
    triggerConfirm(
      `Hapus Profil Siswa?`, 
      `Data akademik dan akses cloud untuk "${name}" akan dihapus permanen. Tindakan ini tidak dapat dibatalkan.`, 
      async () => {
        try {
          await db.delete('users', id);
          setStudents(students.filter(s => s.id !== id));
        } catch (err) {
          alert("Gagal menghapus data.");
        }
      }
    );
  };

  if (loading) return (
