        }
        if (auth.currentUser) {
          await updatePassword(auth.currentUser, adminPassword);
        }
      }

      // 3. Perbarui Username (Email Auth) jika berubah
      const newEmail = `${adminUsername}@alirsyad.sch.id`;
      const oldEmail = `${user.username}@alirsyad.sch.id`;

      if (adminUsername !== user.username && auth.currentUser) {
        try {
          await updateEmail(auth.currentUser, newEmail);
        } catch (authErr: any) {
          if (authErr.code === 'auth/requires-recent-login') {
            throw new Error("Sesi login Anda sudah lama. Mohon logout dan login kembali untuk mengubah username.");
          }
          throw authErr;
        }
      }

      // 4. Perbarui Profil di Firestore
      const updatedUser: User = { 
        ...user, 
        name: adminName, 
        username: adminUsername, 
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${adminUsername}`
      };

      await setDoc(doc(firestore, "users", user.id), updatedUser, { merge: true });

      if (onUpdateUser) onUpdateUser(updatedUser);
      setAdminPassword(''); // Reset field password setelah sukses
      alert('Konfigurasi dan Akun Berhasil Diperbarui!');

    } catch (err: any) {
      console.error(err);
      alert('Gagal menyimpan data: ' + (err.message || 'Kesalahan Sistem'));
