import { db } from '../../App';
import { SiteSettings, User } from '../../types';
import { doc, setDoc } from "firebase/firestore";
import { firestore, auth } from '../../firebase';
import { updatePassword, updateEmail } from "firebase/auth";

interface SettingsTabProps {
  settings: SiteSettings;
  setSettings: (s: SiteSettings) => void;
  user: User;
  onUpdateUser: (u: User) => void;
}

const SettingsTab: React.FC<SettingsTabProps> = ({ settings, setSettings, user, onUpdateUser }) => {
  const [adminName, setAdminName] = useState(user.name);
  const [adminUsername, setAdminUsername] = useState(user.username);
  const [adminPassword, setAdminPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const handleSave = async () => {
    if (!settings.siteName || !adminName || !adminUsername) {
      alert("Nama Platform, Nama Guru, dan Username tidak boleh kosong.");
      return;
    }

    setIsSaving(true);
    let authErrorOccurred = false;
    let authErrorMessage = "";

    try {
      // 1. Perbarui Pengaturan Situs di Firestore
      await db.update('settings', 'site_configs', settings);

      const currentUser = auth.currentUser;

      if (currentUser) {
        // 2. Perbarui Password jika diisi
        if (adminPassword) {
          if (adminPassword.length < 6) {
            throw new Error("Password minimal harus 6 karakter.");
          }
          try {
            await updatePassword(currentUser, adminPassword);
          } catch (pErr: any) {
            authErrorOccurred = true;
            if (pErr.code === 'auth/requires-recent-login') {
              authErrorMessage += "Gagal Update Password: Sesi login sudah lama. Silakan Logout & Login kembali.\n";
            } else {
              authErrorMessage += `Gagal Update Password: ${pErr.message}\n`;
            }
          }
        }

        // 3. Perbarui Username (Email Auth) jika berubah
        if (adminUsername !== user.username) {
          const newEmail = `${adminUsername}@alirsyad.sch.id`;
          try {
            await updateEmail(currentUser, newEmail);
          } catch (eErr: any) {
            authErrorOccurred = true;
            if (eErr.code === 'auth/requires-recent-login') {
              authErrorMessage += "Gagal Update Username: Sesi login sudah lama. Silakan Logout & Login kembali.\n";
            } else if (eErr.code === 'auth/operation-not-allowed') {
              authErrorMessage += "Gagal Update Username: Fitur 'Email Change' belum diaktifkan di Firebase Console (Authentication > Settings).\n";
            } else if (eErr.code === 'auth/email-already-in-use') {
              authErrorMessage += "Gagal Update Username: Username tersebut sudah digunakan oleh admin lain.\n";
            } else {
              authErrorMessage += `Gagal Update Username: ${eErr.message}\n`;
            }
            // Jika email gagal, kita kembalikan username ke yang lama untuk profil Firestore agar tetap sinkron dengan Auth
            setAdminUsername(user.username);
          }
        }
      }

      // 4. Perbarui Profil di Firestore (Selalu lakukan ini untuk nama display)
      const updatedUser: User = { 
        ...user, 
        name: adminName, 
        username: authErrorOccurred && adminUsername !== user.username ? user.username : adminUsername, 
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${adminUsername}`
      };

      await setDoc(doc(firestore, "users", user.id), updatedUser, { merge: true });
      if (onUpdateUser) onUpdateUser(updatedUser);

      if (authErrorOccurred) {
        alert(`Profil Nama berhasil diperbarui, namun ada masalah pada kredensial:\n\n${authErrorMessage}`);
      } else {
        setAdminPassword('');
