import React, { useState, useEffect } from 'react';
import LandingPage from './views/LandingPage';
import AdminDashboard from './views/AdminDashboard';
import StudentDashboard from './views/StudentDashboard';
import Login from './views/Login';
import Signup from './views/Signup';
import { User, Role, SiteSettings } from './types';
import { firestore, auth } from './firebase';
import { 
  collection, 
  doc, 
  getDoc, 
  getDocs, 
  setDoc, 
  addDoc,
  deleteDoc,
  onSnapshot,
  query,
  where
} from "firebase/firestore"; 
import { onAuthStateChanged } from "firebase/auth";
import { AlertCircle, Database, ShieldAlert, ExternalLink, X, WifiOff, Cloud } from 'lucide-react';

const sanitize = (obj: any) => {
  const result: any = {};
  Object.keys(obj).forEach(key => {
    if (obj[key] !== undefined && obj[key] !== null) {
      result[key] = obj[key];
    }
  });
  return result;
};

// Helper for Local Storage fallback
const localDb = {
  get: (key: string) => JSON.parse(localStorage.getItem(key) || '[]'),
  set: (key: string, data: any) => localStorage.setItem(key, JSON.stringify(data)),
  getSingle: (key: string, id: string) => {
    const data = JSON.parse(localStorage.getItem(key) || '[]');
    return data.find((item: any) => item.id === id) || null;
  }
};

export const db = {
  useLocal: false,

  get: async (collName: string) => {
    if (db.useLocal) return localDb.get(collName);
    try {
      const querySnapshot = await getDocs(collection(firestore, collName));
      return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    } catch (err: any) {
      console.warn(`Firestore Error, switching to local:`, err.message);
      db.useLocal = true;
      return localDb.get(collName);
    }
  },

  getByQuery: async (collName: string, field: string, value: any) => {
    if (db.useLocal) {
      const data = localDb.get(collName);
      return data.filter((item: any) => item[field] === value);
    }
    try {
      const q = query(collection(firestore, collName), where(field, "==", value));
      const querySnapshot = await getDocs(q);
      return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    } catch (err: any) {
      db.useLocal = true;
      return localDb.get(collName).filter((item: any) => item[field] === value);
    }
  },

  getSingle: async (collName: string, id: string) => {
    if (db.useLocal) return localDb.getSingle(collName, id);
    try {
      const docSnap = await getDoc(doc(firestore, collName, id));
      return docSnap.exists() ? { id: docSnap.id, ...docSnap.data() } : null;
    } catch (err) {
      return localDb.getSingle(collName, id);
    }
  },

  update: async (collName: string, id: string, data: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    const sanitizedData = sanitize(data);

    // Always update local for redundancy
    const localData = localDb.get(collName);
    const index = localData.findIndex((i: any) => i.id === id);
    if (index > -1) localData[index] = { ...localData[index], ...sanitizedData };
    else localData.push({ id, ...sanitizedData });
    localDb.set(collName, localData);

    if (db.useLocal) {
      window.dispatchEvent(new CustomEvent('sync-end'));
      return;
    }

    try {
      await setDoc(doc(firestore, collName, id), sanitizedData, { merge: true });
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err: any) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      throw err;
    }
  },

  add: async (collName: string, data: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    const sanitizedData = sanitize(data);
    const id = data.id || `local_${Date.now()}`;

    const localData = localDb.get(collName);
    localData.push({ ...sanitizedData, id });
    localDb.set(collName, localData);

    if (db.useLocal) {
      window.dispatchEvent(new CustomEvent('sync-end'));
      return id;
    }

    try {
      if (data.id) {
        await setDoc(doc(firestore, collName, id), sanitizedData);
      } else {
        const docRef = await addDoc(collection(firestore, collName), sanitizedData);
        window.dispatchEvent(new CustomEvent('sync-end'));
        return docRef.id;
      }
      window.dispatchEvent(new CustomEvent('sync-end'));
      return id;
    } catch (err: any) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      throw err;
    }
  },

  delete: async (collName: string, id: string) => {
    window.dispatchEvent(new CustomEvent('sync-start'));

    const localData = localDb.get(collName).filter((i: any) => i.id !== id);
    localDb.set(collName, localData);

    if (db.useLocal) {
      window.dispatchEvent(new CustomEvent('sync-end'));
      return;
    }

    try {
      await deleteDoc(doc(firestore, collName, id));
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err: any) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      throw err;
    }
  },

  saveAll: async (collName: string, data: any[]) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    localDb.set(collName, data);

    if (db.useLocal) {
      window.dispatchEvent(new CustomEvent('sync-end'));
      return;
    }

    try {
      const promises = data.map(item => {
        const id = item.id || doc(collection(firestore, collName)).id;
        return setDoc(doc(firestore, collName, id), sanitize(item), { merge: true });
      });
      await Promise.all(promises);
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err: any) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      throw err;
    }
  }
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'landing' | 'login' | 'signup' | 'dashboard'>('landing');
  const [loginRole, setLoginRole] = useState<Role | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'success' | 'error'>('idle');
  const [isOfflineMode, setIsOfflineMode] = useState(false);
  const [settings, setSettings] = useState<SiteSettings>({
    logoUrl: 'https://www.alirsyad.or.id/wp-content/uploads/download/alirsyad-alislamiyyah.png',
    heroImageUrl: 'https://cdn.fpt-is.com/vi/he-thong-elearning-1.png',
    siteName: 'Informatika SMP Al Irsyad Surakarta'
  });

  useEffect(() => {
    // Check local session first
    const savedUser = localStorage.getItem('elearning_session');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
      setView('dashboard');
      setIsOfflineMode(true);
      db.useLocal = true;
      setIsLoading(false);
    }

    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (savedUser) return; // Prioritize local session if it exists

      try {
        if (firebaseUser) {
          const profile = await db.getSingle('users', firebaseUser.uid);
          if (profile) {
            const userData = profile as User;
            setUser(userData);
            setView('dashboard');
            setIsOfflineMode(false);
            db.useLocal = false;
          }
        }
      } catch (e: any) {
        console.warn("Auth error, keeping local state if any.");
      } finally {
        setIsLoading(false);
      }
    });

    const unsubSettings = onSnapshot(
      doc(firestore, 'settings', 'site_configs'), 
      (doc) => { if (doc.exists()) setSettings(doc.data() as SiteSettings); },
      () => { /* Ignore errors on settings load */ }
    );

    return () => {
      unsubscribe();
      unsubSettings();
    };
  }, []);

  useEffect(() => {
    const handleSyncStart = () => setSyncStatus('syncing');
    const handleSyncEnd = () => {
      setSyncStatus('success');
      setTimeout(() => setSyncStatus('idle'), 2000);
    };
    const handleSyncError = () => {
      setSyncStatus('error');
      setTimeout(() => setSyncStatus('idle'), 3000);
    };

    window.addEventListener('sync-start', handleSyncStart);
    window.addEventListener('sync-end', handleSyncEnd);
    window.addEventListener('sync-error', handleSyncError);

    return () => {
      window.removeEventListener('sync-start', handleSyncStart);
      window.removeEventListener('sync-end', handleSyncEnd);
      window.removeEventListener('sync-error', handleSyncError);
    };
  }, []);

  const handleLogout = async () => {
    await auth.signOut();
    localStorage.removeItem('elearning_session');
    setUser(null);
    setView('landing');
  };

  const handleLoginSuccess = (userData: User, isLocal: boolean) => {
    setUser(userData);
    setView('dashboard');
    setIsOfflineMode(isLocal);
    db.useLocal = isLocal;
    if (isLocal) {
      localStorage.setItem('elearning_session', JSON.stringify(userData));
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-6 text-black">
        <div className="w-12 h-12 border-4 border-slate-100 border-t-emerald-600 rounded-full animate-spin mb-4"></div>
        <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest text-center">Inisialisasi Sistem...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen selection:bg-emerald-100 selection:text-emerald-900 relative">
      {/* DB Status Indicator */}
      <div className={`fixed top-4 right-4 z-[1000] px-4 py-2 rounded-2xl flex items-center gap-2 border shadow-xl transition-all duration-500 ${isOfflineMode ? 'bg-amber-600 border-amber-500 text-white' : 'bg-emerald-600 border-emerald-500 text-white'}`}>
        {isOfflineMode ? <WifiOff size={14} /> : <Cloud size={14} />}
        <span className="text-[9px] font-black uppercase tracking-widest">{isOfflineMode ? 'Mode Lokal' : 'Mode Cloud'}</span>
      </div>

      <div className={`fixed top-6 left-1/2 -translate-x-1/2 z-[100] flex items-center gap-3 px-6 py-3 rounded-full shadow-2xl border backdrop-blur-md transition-all duration-500 transform ${
        syncStatus === 'idle' ? 'translate-y-[-140%] opacity-0' : 'translate-y-0 opacity-100'
      } ${
        syncStatus === 'syncing' ? 'bg-slate-900 text-white border-slate-700' : 
        syncStatus === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-rose-600 text-white border-rose-500'
      }`}>
        <div className={`w-2 h-2 rounded-full ${syncStatus === 'syncing' ? 'bg-blue-400 animate-pulse' : 'bg-white'}`}></div>
        <span className="text-[10px] font-black uppercase tracking-[0.2em]">{syncStatus === 'syncing' ? 'Menyimpan' : 'Berhasil'}</span>
      </div>

      {view === 'landing' && (
        <LandingPage 
          onNavigateLogin={(role) => { setLoginRole(role); setView('login'); }} 
          onNavigateSignup={() => setView('signup')} 
          settings={settings} 
        />
      )}
      {view === 'login' && (
        <Login 
          role={loginRole || 'STUDENT'} 
          onBack={() => setView('landing')} 
          onLogin={(u, isLocal) => handleLoginSuccess(u, isLocal)} 
          onNavigateSignup={() => setView('signup')} 
        />
      )}
      {view === 'signup' && <Signup onBack={() => setView('login')} onSignup={() => { setLoginRole('STUDENT'); setView('login'); }} logoUrl={settings.logoUrl} />}
      {view === 'dashboard' && user && (
        user.role === 'ADMIN' 
          ? <AdminDashboard user={user} onLogout={handleLogout} settings={settings} setSettings={setSettings} onUpdateUser={setUser} /> 
          : <StudentDashboard user={user} onLogout={handleLogout} settings={settings} onUpdateUser={setUser} />
      )}
    </div>
  );
};

export default App;

