import React, { useState, useEffect, useMemo } from 'react';
import { 
  Loader2, UserCheck, UserX, Search, Users, 
  Clock, SearchX, RefreshCw, Fingerprint, 
  CheckCircle2, XCircle, AlertCircle, Calendar,
  UserCircle
} from 'lucide-react';
import { firestore } from '../../firebase';
import { collection, query, where, onSnapshot } from "firebase/firestore";
import { db } from '../../App.tsx';
import { User } from '../../types.ts';
import { notifyStudents } from '../../utils/helpers.ts';

interface ConfirmRegistrationsTabProps {
  triggerConfirm: any;
}

const ConfirmRegistrationsTab: React.FC<ConfirmRegistrationsTabProps> = ({ triggerConfirm }) => {
  const [pending, setPending] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [isProcessing, setIsProcessing] = useState<string | null>(null);

  useEffect(() => {
    setLoading(true);

    // Gunakan onSnapshot untuk memantau pendaftar baru secara Real-time dari Cloud
    const q = query(collection(firestore, "users"), where("status", "==", "PENDING"));

    const unsubscribe = onSnapshot(q, (querySnapshot) => {
      const penders: User[] = [];
      querySnapshot.forEach((doc) => {
        penders.push({ id: doc.id, ...doc.data() } as User);
      });

      setPending(penders);
      setLoading(false);
    }, (error) => {
      console.error("Firestore Snapshot Error:", error);
      // Jika error (mungkin offline), coba ambil dari sistem Hybrid db
      db.getByQuery('users', 'status', 'PENDING').then(res => {
        setPending(res as User[]);
        setLoading(false);
      });
    });

    return () => unsubscribe();
  }, []);

  const filteredPending = useMemo(() => {
    return pending.filter(s => 
      (s.name || '').toLowerCase().includes(search.toLowerCase()) || 
      (s.username || '').toLowerCase().includes(search.toLowerCase())
    );
  }, [pending, search]);

  const handleApprove = async (student: User) => {
    setIsProcessing(student.id);
    try {
      await db.update('users', student.id, { status: 'ACTIVE' });
      // Notification
      await notifyStudents([], "Akun Aktif!", "Selamat, pendaftaran Anda telah disetujui Guru Informatika. Silakan login.", "registration", student.id);
    } catch (err) {
      alert("Gagal mengaktifkan akun. Pastikan koneksi internet stabil.");
    } finally {
      setIsProcessing(null);
    }
  };

  const handleReject = (student: User) => {
    triggerConfirm(
      "Tolak Pendaftaran?", 
      `Apakah Anda yakin ingin menghapus data pendaftaran ${student.name}? Tindakan ini permanen.`, 
      async () => {
        setIsProcessing(student.id);
        try {
          await db.delete('users', student.id);
        } catch (err) {
          alert("Gagal menolak pendaftaran.");
        } finally {
          setIsProcessing(null);
        }
      },
      'danger'
    );
  };

  if (loading) return (
    <div className="py-32 flex flex-col items-center justify-center gap-4 text-black">
      <div className="w-12 h-12 border-4 border-orange-100 border-t-orange-500 rounded-full animate-spin"></div>
      <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Memindai Antrean Cloud...</p>
    </div>
  );

  return (
    <div className="space-y-8 text-black animate-in fade-in duration-500 pb-20">
      {/* Header Panel */}
      <section className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex items-center gap-5">
           <div className="w-16 h-16 bg-orange-50 text-orange-600 rounded-[1.5rem] flex items-center justify-center shadow-inner">
              <Fingerprint size={32} />
           </div>
           <div>
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">Verifikasi Siswa</h3>
              <p className="text-slate-500 font-medium text-sm mt-1">
                {pending.length > 0 
                  ? `Ada ${pending.length} pendaftaran baru terdeteksi di Cloud.` 
                  : 'Belum ada pendaftaran baru yang masuk.'}
              </p>
           </div>
        </div>
        <div className="flex gap-4 w-full md:w-auto">
          <div className="relative flex-1 md:w-64">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
            <input 
              type="text" placeholder="Cari nama pendaftar..." 
              value={search} onChange={e => setSearch(e.target.value)}
              className="w-full pl-11 pr-4 py-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-orange-500/20 outline-none font-bold text-sm transition-all shadow-inner"
            />
          </div>
        </div>
      </section>

      {/* Grid Content */}
      {filteredPending.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {filteredPending.map(s => (
            <div key={s.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col items-center text-center relative group hover:shadow-2xl hover:-translate-y-1 transition-all duration-300">
              <div className="relative mb-6">
                <img 
                  src={s.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${s.username}`} 
                  className="w-24 h-24 rounded-full border-4 border-slate-50 shadow-xl bg-slate-50" 
                  alt={s.name}
                />
                <div className="absolute -bottom-1 -right-1 bg-orange-500 p-2 rounded-full border-4 border-white">
                  <Clock size={14} className="text-white" />
                </div>
              </div>

              <h4 className="font-black text-slate-800 text-lg leading-tight line-clamp-1">{s.name}</h4>
              <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mt-1 mb-4">@{s.username}</p>

              <div className="flex items-center gap-2 px-4 py-2 bg-slate-50 rounded-full mb-8">
                <Users size={12} className="text-slate-400" />
                <span className="text-[10px] font-black text-slate-600 uppercase tracking-tight">Kelas {s.classId || 'N/A'}</span>
              </div>

              <div className="flex gap-3 mt-auto w-full">
                 <button 
                    onClick={() => handleApprove(s)} 
                    disabled={isProcessing === s.id}
                    className="flex-1 py-4 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-600 transition-all disabled:opacity-50 flex items-center justify-center gap-2 active:scale-95 shadow-lg"
                 >
                    {isProcessing === s.id ? <Loader2 size={16} className="animate-spin" /> : <UserCheck size={16} />}
                    Setujui
                 </button>
                 <button 
                    onClick={() => handleReject(s)} 
                    disabled={isProcessing === s.id}
                    className="px-5 py-4 bg-rose-50 text-rose-500 rounded-2xl hover:bg-rose-500 hover:text-white transition-all disabled:opacity-50 active:scale-95 border border-rose-100"
                 >
                    <UserX size={20} />
                 </button>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-[3rem] border-2 border-dashed border-slate-200 p-20 flex flex-col items-center text-center">
          <div className="w-20 h-20 bg-slate-50 text-slate-300 rounded-3xl flex items-center justify-center mb-6">
            <SearchX size={40} />
          </div>
          <h4 className="text-xl font-black text-slate-400">Tidak Ada Antrean</h4>
          <p className="text-slate-400 font-medium text-sm max-w-xs mt-2 italic">
            {search ? `Tidak ditemukan pendaftar dengan nama "${search}"` : 'Belum ada pendaftaran siswa baru yang masuk ke database Cloud.'}
          </p>
        </div>
      )}
    </div>
  );
};

export default ConfirmRegistrationsTab;

rules_version = '2';

service cloud.firestore {
  match /databases/{database}/documents {

    // Fungsi pembantu untuk mengecek status login
    function isSignedIn() {
      return request.auth != null;
    }

    // Fungsi pembantu untuk mengambil data user dari koleksi 'users'
    function getUserData() {
      return get(/databases/$(database)/documents/users/$(request.auth.uid)).data;
    }

    // Fungsi pembantu untuk mengecek apakah user adalah ADMIN
    function isAdmin() {
      return isSignedIn() && getUserData().role == 'ADMIN';
    }

    // Fungsi pembantu untuk mengecek apakah user adalah pemilik dokumen
    function isOwner(userId) {
      return isSignedIn() && request.auth.uid == userId;
    }

    // Aturan untuk koleksi Users
    match /users/{userId} {
      // Admin bisa baca semua, Siswa hanya bisa baca profilnya sendiri atau pendaftar PENDING (untuk verifikasi role)
      allow read: if isSignedIn() && (isOwner(userId) || isAdmin());
      // Siapapun yang terautentikasi bisa mendaftar (create)
      allow create: if isSignedIn();
      // User bisa update profil sendiri, Admin bisa update semuanya
      allow update: if isSignedIn() && (isOwner(userId) || isAdmin());
      // Hanya Admin yang bisa hapus user
      allow delete: if isAdmin();
    }

    // Aturan untuk Kelas, Materi, dan Tugas
    match /elearning_classes/{id} {
      allow read: if isSignedIn();
      allow write: if isAdmin();
    }

    match /elearning_materials/{id} {
      allow read: if isSignedIn();
      allow write: if isAdmin();
    }

    match /elearning_tasks/{id} {
      allow read: if isSignedIn();
      allow write: if isAdmin();
    }

    // Aturan untuk Pengumpulan Tugas (Submissions)
    match /elearning_submissions/{id} {
      // Siswa bisa baca miliknya, Admin bisa baca semua
      allow read: if isSignedIn() && (resource.data.studentId == request.auth.uid || isAdmin());
      // Siswa bisa kirim tugas
      allow create: if isSignedIn();
      // Siswa bisa update tugasnya (sebelum dinilai), Admin bisa update untuk memberi nilai
      allow update: if isSignedIn() && (resource.data.studentId == request.auth.uid || isAdmin());
      allow delete: if isAdmin();
    }

    // Aturan untuk Notifikasi
    match /elearning_notifications/{id} {
      allow read: if isSignedIn() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isSignedIn();
      allow update: if isSignedIn() && (resource.data.userId == request.auth.uid || isAdmin());
      allow delete: if isAdmin();
    }

    // Aturan untuk Pengaturan Situs
    match /settings/{id} {
      // Landing page perlu baca setting meskipun belum login
      allow read: if true;
      allow write: if isAdmin();
    }
  }
}

rules_version = '2';

service firebase.storage {
  match /b/{bucket}/o {

    // Fungsi pembantu
    function isSignedIn() {
      return request.auth != null;
    }

    match /{allPaths=**} {
      // Izinkan baca jika user terautentikasi
      allow read: if isSignedIn();
      // Izinkan tulis jika user terautentikasi dan ukuran file < 5MB
      allow write: if isSignedIn() && request.resource.size < 5 * 1024 * 1024;
    }
  }
}

