      allow write: if isAdmin();
    }
  }
}
```

### 2. (Opsional) Salin ke Tab "Rules" di Storage:
Jika Anda menggunakan fitur unggah foto profil, tempelkan ini di **Build > Storage > Rules**:

```javascript
rules_version = '2';

service firebase.storage {
  match /b/{bucket}/o {
    function isSignedIn() {
      return request.auth != null;
    }
    match /{allPaths=**} {
      allow read: if isSignedIn();
      allow write: if isSignedIn() && request.resource.size < 5 * 1024 * 1024;
    }
