import React, { useState, useEffect } from 'react';
import LandingPage from './views/LandingPage';
import AdminDashboard from './views/AdminDashboard';
import StudentDashboard from './views/StudentDashboard';
import Login from './views/Login';
import Signup from './views/Signup';
import { User, Role, SiteSettings } from './types';
import { firestore, auth } from './firebase';
import { 
  collection, 
  doc, 
  getDoc, 
  getDocs, 
  setDoc, 
  addDoc,
  deleteDoc,
  onSnapshot,
  query,
  where
} from "firebase/firestore"; 
import { onAuthStateChanged } from "firebase/auth";
import { AlertCircle, Database, ShieldAlert, ExternalLink, X } from 'lucide-react';

const sanitize = (obj: any) => {
  const result: any = {};
  Object.keys(obj).forEach(key => {
    if (obj[key] !== undefined && obj[key] !== null) {
      result[key] = obj[key];
    }
  });
  return result;
};

export const db = {
  get: async (collName: string) => {
    try {
      const querySnapshot = await getDocs(collection(firestore, collName));
      return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    } catch (err: any) {
      console.error(`Firestore Get Error (${collName}):`, err);
      if (err.code === 'permission-denied') window.dispatchEvent(new CustomEvent('db-permission-error'));
      return [];
    }
  },

  getByQuery: async (collName: string, field: string, value: any) => {
    try {
      const q = query(collection(firestore, collName), where(field, "==", value));
      const querySnapshot = await getDocs(q);
      return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    } catch (err: any) {
      console.error(`Firestore Query Error (${collName}):`, err);
      if (err.code === 'permission-denied') window.dispatchEvent(new CustomEvent('db-permission-error'));
      return [];
    }
  },

  getSingle: async (collName: string, id: string) => {
    try {
      // Tambahkan opsi untuk mendapatkan data terbaru dari server guna menghindari cache 'PENDING'
      const docSnap = await getDoc(doc(firestore, collName, id));
      return docSnap.exists() ? { id: docSnap.id, ...docSnap.data() } : null;
    } catch (err: any) {
      console.error(`Firestore Get Single Error (${collName}):`, err);
      if (err.code === 'permission-denied') window.dispatchEvent(new CustomEvent('db-permission-error'));
      return null;
    }
  },

  update: async (collName: string, id: string, data: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      await setDoc(doc(firestore, collName, id), sanitize(data), { merge: true });
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err: any) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      if (err.code === 'permission-denied') window.dispatchEvent(new CustomEvent('db-permission-error'));
      throw err;
    }
  },

  add: async (collName: string, data: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      const docData = sanitize(data);
      if (data.id) {
        // PERBAIKAN: Gunakan merge: true agar status yang sudah ACTIVE tidak hilang jika tidak dikirim
        await setDoc(doc(firestore, collName, data.id), docData, { merge: true });
        window.dispatchEvent(new CustomEvent('sync-end'));
        return data.id;
      } else {
        const docRef = await addDoc(collection(firestore, collName), docData);
        window.dispatchEvent(new CustomEvent('sync-end'));
        return docRef.id;
      }
    } catch (err: any) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      if (err.code === 'permission-denied') window.dispatchEvent(new CustomEvent('db-permission-error'));
      throw err;
    }
  },

  delete: async (collName: string, id: string) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      await deleteDoc(doc(firestore, collName, id));
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err: any) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      if (err.code === 'permission-denied') window.dispatchEvent(new CustomEvent('db-permission-error'));
      throw err;
    }
  },

  saveAll: async (collName: string, data: any[]) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      const promises = data.map(item => {
        const id = item.id || doc(collection(firestore, collName)).id;
        return setDoc(doc(firestore, collName, id), sanitize(item), { merge: true });
      });
      await Promise.all(promises);
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err: any) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      if (err.code === 'permission-denied') window.dispatchEvent(new CustomEvent('db-permission-error'));
      throw err;
    }
  },

  append: async (collName: string, data: any) => {
    return db.add(collName, data);
  }
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'landing' | 'login' | 'signup' | 'dashboard'>('landing');
  const [loginRole, setLoginRole] = useState<Role | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'success' | 'error'>('idle');
  const [dbError, setDbError] = useState<boolean>(false);
  const [settings, setSettings] = useState<SiteSettings>({
    logoUrl: 'https://www.alirsyad.or.id/wp-content/uploads/download/alirsyad-alislamiyyah.png',
    heroImageUrl: 'https://cdn.fpt-is.com/vi/he-thong-elearning-1.png',
    siteName: 'Informatika SMP Al Irsyad Surakarta'
  });

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      try {
        if (firebaseUser) {
          const profile = await db.getSingle('users', firebaseUser.uid);
          if (profile) {
            const userData = profile as User;
            // Validasi status secara ketat
            if (userData.role === 'ADMIN' || (userData.role === 'STUDENT' && userData.status === 'ACTIVE')) {
              setUser(userData);
              setView('dashboard');
            } else {
              await auth.signOut();
              setUser(null);
              setView('login');
              setLoginRole('STUDENT');
              alert("Akun Anda sedang menunggu verifikasi Guru.");
            }
          }
        } else {
          setUser(null);
          if (view === 'dashboard') setView('landing');
        }
      } catch (e: any) {
        console.error("Auth Listener Error:", e);
      } finally {
        setIsLoading(false);
      }
    });

    const unsubSettings = onSnapshot(
      doc(firestore, 'settings', 'site_configs'), 
      (doc) => {
        if (doc.exists()) {
          setSettings(doc.data() as SiteSettings);
        }
      },
      (error) => {
        console.error("Settings Snapshot Error:", error);
      }
    );

    return () => {
      unsubscribe();
      unsubSettings();
    };
  }, []);

  useEffect(() => {
    const handleSyncStart = () => setSyncStatus('syncing');
    const handleSyncEnd = () => {
      setSyncStatus('success');
      setTimeout(() => setSyncStatus('idle'), 3000);
    };
    const handleSyncError = () => {
      setSyncStatus('error');
      setTimeout(() => setSyncStatus('idle'), 5000);
    };
    const handlePermissionError = () => setDbError(true);

    window.addEventListener('sync-start', handleSyncStart);
    window.addEventListener('sync-end', handleSyncEnd);
    window.addEventListener('sync-error', handleSyncError);
    window.addEventListener('db-permission-error', handlePermissionError);

    return () => {
      window.removeEventListener('sync-start', handleSyncStart);
      window.removeEventListener('sync-end', handleSyncEnd);
      window.removeEventListener('sync-error', handleSyncError);
      window.removeEventListener('db-permission-error', handlePermissionError);
    };
  }, []);

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-black">
        <div className="w-16 h-16 border-4 border-emerald-100 border-t-emerald-600 rounded-full animate-spin mb-4"></div>
        <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest text-center">Inisialisasi Keamanan & Database...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen selection:bg-emerald-100 selection:text-emerald-900 relative">
      {/* DB Error Banner - Hanya tampil jika benar-benar krusial */}
      {dbError && (
        <div className="fixed inset-x-0 top-0 z-[1000] bg-rose-600 text-white p-4 shadow-2xl animate-in slide-in-from-top duration-500">
          <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-4">
              <div className="p-2 bg-white/20 rounded-xl">
                <ShieldAlert size={24} />
              </div>
              <div className="text-center md:text-left">
                <p className="text-xs font-black uppercase tracking-widest">Akses Database Terbatas</p>
                <p className="text-[10px] font-medium opacity-80">Beberapa data mungkin tidak dapat dimuat karena aturan keamanan Firestore.</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <button onClick={() => setDbError(false)} className="px-4 py-2 bg-white/20 text-white rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-white/30 transition-colors">
                Tutup
              </button>
            </div>
          </div>
        </div>
      )}

      <div className={`fixed top-6 left-1/2 -translate-x-1/2 z-[100] flex items-center gap-3 px-6 py-3 rounded-full shadow-2xl border backdrop-blur-md transition-all duration-500 transform ${
        syncStatus === 'idle' ? 'translate-y-[-140%] opacity-0' : 'translate-y-0 opacity-100'
      } ${
        syncStatus === 'syncing' ? 'bg-slate-900 text-white border-slate-700' : 
        syncStatus === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-rose-600 text-white border-rose-500'
      }`}>
        <div className={`w-2 h-2 rounded-full ${syncStatus === 'syncing' ? 'bg-blue-400 animate-pulse' : 'bg-white'}`}></div>
        <span className="text-[10px] font-black uppercase tracking-[0.2em]">{syncStatus === 'syncing' ? 'Sinkronisasi' : syncStatus === 'success' ? 'Tersimpan' : 'Error'}</span>
      </div>

      {view === 'landing' && (
        <LandingPage 
          onNavigateLogin={(role) => { setLoginRole(role); setView('login'); }} 
          onNavigateSignup={() => setView('signup')} 
          settings={settings} 
        />
      )}
      {view === 'login' && <Login role={loginRole || 'STUDENT'} onBack={() => setView('landing')} onLogin={(u) => { setUser(u); setView('dashboard'); }} onNavigateSignup={() => setView('signup')} />}
      {view === 'signup' && <Signup onBack={() => setView('login')} onSignup={() => { setLoginRole('STUDENT'); setView('login'); }} logoUrl={settings.logoUrl} />}
      {view === 'dashboard' && user && (
        user.role === 'ADMIN' 
          ? <AdminDashboard user={user} onLogout={async () => { await auth.signOut(); setView('landing'); }} settings={settings} setSettings={setSettings} onUpdateUser={setUser} /> 
          : <StudentDashboard user={user} onLogout={async () => { await auth.signOut(); setView('landing'); }} settings={settings} onUpdateUser={setUser} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Lock, User as UserIcon, Eye, EyeOff, AlertCircle, RefreshCw, ShieldCheck, Sparkles, GraduationCap, Laptop } from 'lucide-react';
import { Role, User } from '../types';
import { auth, firestore } from '../firebase';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword } from "firebase/auth";
import { doc, getDoc, getDocs, collection, setDoc, query, where, limit } from "firebase/firestore";

interface LoginProps {
  role: Role;
  onBack: () => void;
  onLogin: (user: User) => void;
  onNavigateSignup: () => void;
}

const Login: React.FC<LoginProps> = ({ role, onBack, onLogin, onNavigateSignup }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<{message: string; hint?: string}>({message: ''});
  const [loading, setLoading] = useState(false);
  const [isEmptyDb, setIsEmptyDb] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);

  const isAdmin = role === 'ADMIN';

  useEffect(() => {
    const checkUsers = async () => {
      try {
        const querySnapshot = await getDocs(query(collection(firestore, "users"), limit(1)));
        if (querySnapshot.empty) {
          setIsEmptyDb(true);
        }
      } catch (e) {
        // Abaikan error cek admin jika permission ditolak (karena admin belum ada)
      }
    };
    if (isAdmin) checkUsers();
  }, [isAdmin]);

  const handleCreateInitialAdmin = async () => {
    if (!isAdmin) return; // Proteksi tambahan

    setIsInitializing(true);
    setError({message: ''});
    const adminUsername = "admin";
    const adminPass = "admin123";
    const email = `${adminUsername}@alirsyad.sch.id`;

    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, adminPass);
      const firebaseUser = userCredential.user;

      const adminData: User = {
        id: firebaseUser.uid,
        name: "Admin Utama Informatika",
        username: adminUsername,
        role: 'ADMIN',
        status: 'ACTIVE',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=admin`
      };

      await setDoc(doc(firestore, "users", firebaseUser.uid), adminData);

      alert(`ADMIN BERHASIL DIBUAT!\n\nUsername: ${adminUsername}\nPassword: ${adminPass}`);
      setIsEmptyDb(false);
      setUsername(adminUsername);
      setPassword(adminPass);
    } catch (err: any) {
      setError({message: "Gagal Inisialisasi: " + err.message});
    } finally {
      setIsInitializing(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError({message: ''});
    setLoading(true);

    const cleanUsername = username.trim().toLowerCase();
    const email = `${cleanUsername}@alirsyad.sch.id`;

    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      // Ambil profil murni Read-Only
      const masterDoc = await getDoc(doc(firestore, "users", firebaseUser.uid));

      if (masterDoc.exists()) {
        const userData = masterDoc.data() as User;

        if (userData.role !== role) {
          await auth.signOut();
          setError({message: `Akses Ditolak: Akun ini terdaftar sebagai ${userData.role}.`});
          return;
        }

        if (userData.role === 'STUDENT' && userData.status !== 'ACTIVE') {
          await auth.signOut();
          setError({message: "Akun Anda sedang menunggu verifikasi Guru Informatika."});
          return;
        }

        // Login sukses, kirim ke App state
        onLogin({ ...userData, id: firebaseUser.uid });
      } else {
        await auth.signOut();
        setError({message: "Profil akun tidak ditemukan di database Cloud."});
      }
    } catch (err: any) {
      if (err.code === 'auth/invalid-credential' || err.code === 'auth/wrong-password' || err.code === 'auth/user-not-found') {
        setError({message: "Username atau Password salah. Pastikan pendaftaran sudah dikonfirmasi."});
      } else {
        setError({message: "Gagal masuk: " + (err.message || "Kesalahan sistem.")});
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-white selection:bg-indigo-100 selection:text-indigo-900">
      <div className={`hidden md:flex flex-1 items-center justify-center p-20 relative overflow-hidden transition-colors duration-700 ${isAdmin ? 'bg-slate-900' : 'bg-blue-600'}`}>
        <div className={`absolute top-0 right-0 w-96 h-96 rounded-full blur-[120px] -mr-48 -mt-48 transition-colors ${isAdmin ? 'bg-emerald-500/20' : 'bg-white/20'}`}></div>
        <div className="relative z-10 text-white max-w-md space-y-8 animate-in fade-in slide-in-from-left-10 duration-1000">
          <div className={`w-20 h-20 rounded-3xl flex items-center justify-center shadow-2xl ${isAdmin ? 'bg-emerald-500' : 'bg-white text-blue-600'}`}>
             {isAdmin ? <ShieldCheck size={40} /> : <GraduationCap size={40} />}
          </div>
          <div className="space-y-4">
            <h2 className="text-6xl font-black leading-tight tracking-tighter">
              Portal Cloud<br/>
              <span className={isAdmin ? 'text-emerald-400 italic' : 'text-blue-200 italic'}>
                {isAdmin ? 'Guru / Admin' : 'Siswa Informatika'}
              </span>
            </h2>
            <div className="h-1.5 w-24 bg-white/20 rounded-full"></div>
            <p className="text-xl text-white/70 font-medium leading-relaxed">
              {isAdmin ? "Manajemen kurikulum & pantau progres siswa." : "Akses materi digital & kumpulkan tugas Anda."}
            </p>
          </div>
        </div>
      </div>

      <div className="flex-1 bg-white flex flex-col justify-center items-center px-8 py-12 md:px-20">
        <div className="w-full max-w-md">
          <button onClick={onBack} className="flex items-center gap-3 text-slate-400 hover:text-slate-900 mb-12 font-black text-xs uppercase tracking-widest group">
            <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" /> Beranda
          </button>

          <div className="mb-10 space-y-2">
            <h3 className="text-5xl font-black text-slate-900 tracking-tighter">
              {isAdmin ? 'Masuk Guru' : 'Masuk Siswa'}
            </h3>
            <p className="text-slate-500 font-bold italic">SMP Al Irsyad Surakarta</p>
          </div>

          {error.message && (
            <div className="mb-8 p-5 bg-rose-50 border border-rose-100 rounded-3xl animate-in fade-in slide-in-from-top-2">
              <div className="flex items-start gap-4">
                <div className="w-10 h-10 bg-rose-100 text-rose-600 rounded-2xl flex items-center justify-center shrink-0">
                  <AlertCircle size={20} />
                </div>
                <p className="text-xs font-black text-rose-600 leading-tight">{error.message}</p>
              </div>
            </div>
          )}

          {isEmptyDb && isAdmin && (
            <div className="mb-10 p-8 bg-indigo-50 border-2 border-dashed border-indigo-200 rounded-[2.5rem] space-y-4">
               <p className="text-xs text-indigo-600 font-bold">Admin belum ada. Klik di bawah untuk inisialisasi akun Admin utama.</p>
               <button onClick={handleCreateInitialAdmin} disabled={isInitializing} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl disabled:opacity-50">
                 {isInitializing ? <RefreshCw className="animate-spin" size={18} /> : 'Buat Admin Sekarang'}
               </button>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-8">
            <div className="space-y-3">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-2">Username</label>
              <div className="relative group">
                <UserIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-500" size={22} />
                <input 
                  type="text" 
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  placeholder="Username"
                  className="w-full pl-14 pr-6 py-5 bg-slate-50 border-2 border-slate-50 rounded-[1.8rem] outline-none transition-all font-black text-slate-800 focus:border-blue-500/30 shadow-inner"
                  required
                />
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-2">Kata Sandi</label>
              <div className="relative group">
                <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-500" size={22} />
                <input 
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full pl-14 pr-14 py-5 bg-slate-50 border-2 border-slate-50 rounded-[1.8rem] outline-none transition-all font-black text-slate-800 focus:border-blue-500/30 shadow-inner"
                  required
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600">
                  {showPassword ? <EyeOff size={22} /> : <Eye size={22} />}
                </button>
              </div>
            </div>

            <button 
              disabled={loading} 
              className={`w-full py-6 rounded-[1.8rem] font-black text-lg shadow-2xl transition-all disabled:opacity-50 active:scale-[0.98] flex items-center justify-center gap-4 ${isAdmin ? 'bg-slate-900 text-white hover:bg-emerald-600' : 'bg-blue-600 text-white hover:bg-slate-900'}`}
            >
              {loading ? <RefreshCw className="animate-spin" size={26} /> : 'Login Sekarang'}
            </button>

            {role === 'STUDENT' && (
              <div className="text-center pt-4">
                <p className="text-slate-500 font-bold text-sm">
                  Belum punya akun? <button type="button" onClick={onNavigateSignup} className="text-blue-600 font-black hover:underline underline-offset-4">Daftar Cloud Siswa</button>
                </p>
              </div>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Loader2, Eye, EyeOff, AlertCircle } from 'lucide-react';
import { User, ClassRoom } from '../types';
import { auth, firestore } from '../firebase';
import { createUserWithEmailAndPassword } from "firebase/auth";
import { doc, getDoc, getDocs, collection, query, where, limit } from "firebase/firestore";
import { notifyAdmins } from '../utils/helpers';
import { db } from '../App';

interface SignupProps {
  onBack: () => void;
  onSignup: () => void;
  logoUrl: string;
}

const Signup: React.FC<SignupProps> = ({ onBack, onSignup, logoUrl }) => {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [classRoom, setClassRoom] = useState('');
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchClasses = async () => {
      try {
        const querySnapshot = await db.get('elearning_classes');
        setClasses(querySnapshot as ClassRoom[]);
      } catch (e) {
        console.error("Error fetching classes:", e);
      }
    };
    fetchClasses();
  }, []);

  const checkUsernameAvailable = async (uname: string) => {
    try {
      const q = query(collection(firestore, "users"), where("username", "==", uname), limit(1));
      const snap = await getDocs(q);
      return snap.empty;
    } catch (e) {
      // Jika error (misal Permission Denied), anggap username sudah ada demi keamanan
      return false;
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    const cleanUsername = username.trim().toLowerCase();
    const email = `${cleanUsername}@alirsyad.sch.id`;

    try {
      // Proteksi ganda: Cek apakah username sudah ada
      const isAvailable = await checkUsernameAvailable(cleanUsername);
      if (!isAvailable) {
        throw new Error("Username sudah digunakan atau masalah koneksi. Silakan pilih username lain.");
      }

      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      const userData: User = {
        id: firebaseUser.uid,
        name,
        username: cleanUsername,
        classId: classRoom,
        role: 'STUDENT',
        status: 'PENDING',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${cleanUsername}`
      };

      // Pastikan status adalah PENDING secara eksplisit
      await db.add('users', userData);

      await notifyAdmins(
        "Pendaftaran Siswa Baru", 
        `${name} (Kelas ${classRoom}) telah mendaftar. Mohon segera verifikasi akun tersebut.`
      );

      alert("Pendaftaran Berhasil! Akun Anda sedang menunggu konfirmasi Guru Informatika.");
      await auth.signOut();
      onSignup();
    } catch (err: any) {
      if (err.code === 'auth/email-already-in-use') {
        setError("Username/Akun sudah terdaftar. Silakan login.");
      } else {
        setError(err.message || "Gagal melakukan pendaftaran.");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col justify-center items-center px-6 py-12 text-black">
      <div className="w-full max-w-xl bg-white p-12 rounded-[3rem] shadow-2xl relative overflow-hidden border border-slate-100">
        {loading && (
          <div className="absolute inset-0 bg-white/80 z-20 flex items-center justify-center backdrop-blur-sm">
            <Loader2 className="animate-spin text-emerald-600" size={48} />
          </div>
        )}

        <button onClick={onBack} className="flex items-center gap-2 text-slate-400 hover:text-slate-900 mb-10 font-black text-xs uppercase tracking-widest transition-colors">
          <ArrowLeft size={16} /> Kembali
        </button>

        <div className="text-center mb-10 space-y-2">
          <h3 className="text-4xl font-black text-slate-900 tracking-tight">Registrasi Cloud Siswa</h3>
          <p className="text-slate-400 font-bold text-sm italic">Sistem E-Learning Informatika SMP Al Irsyad</p>
        </div>

        {error && (
          <div className="mb-8 p-4 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-3 text-rose-600 animate-in fade-in slide-in-from-top-2">
            <AlertCircle size={20} />
            <p className="text-xs font-black uppercase tracking-tight">{error}</p>
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          {step === 1 ? (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Nama Lengkap Siswa</label>
                <input 
                  value={name} 
                  onChange={e => setName(e.target.value)} 
                  className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold text-slate-800 focus:border-emerald-500 focus:bg-white transition-all shadow-inner" 
                  placeholder="Contoh: Ahmad Fauzi" 
                  required 
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Pilih Kelas Aktif</label>
                <select 
                  value={classRoom} 
                  onChange={e => setClassRoom(e.target.value)} 
                  className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold text-slate-800 focus:border-emerald-500 focus:bg-white transition-all shadow-inner appearance-none" 
                  required
                >
                  <option value="">-- Pilih Kelas Anda --</option>
                  {classes.map(c => <option key={c.id} value={c.name}>Kelas {c.name}</option>)}
                </select>
              </div>
              <button 
                type="button" 
                onClick={() => setStep(2)} 
                disabled={!name || !classRoom}
                className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-emerald-600 disabled:opacity-30 active:scale-[0.98] transition-all"
              >
                Lanjut ke Kredensial
              </button>
            </div>
          ) : (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Username Baru</label>
                <input 
                  value={username} 
                  onChange={e => setUsername(e.target.value.toLowerCase().replace(/\s/g, ''))} 
