  return (
    <div className="space-y-8 text-black animate-in fade-in duration-500 pb-24">
      {/* Header & Filter Panel */}
      <section className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm space-y-8 relative overflow-hidden">
