                 <input value={forgotUsername} onChange={e => setForgotUsername(e.target.value)} placeholder="Username Siswa" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none font-bold text-center" required />
                 <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase">Kirim Link Reset</button>
