import React, { useState, useEffect } from 'react';
import { ArrowLeft, Loader2, Eye, EyeOff, AlertCircle } from 'lucide-react';
import { User, ClassRoom } from '../types';
import { auth, firestore } from '../firebase';
import { createUserWithEmailAndPassword, signOut } from "firebase/auth";
import { doc, getDocs, collection, query, where, limit, setDoc } from "firebase/firestore";
import { notifyAdmins } from '../utils/helpers';

interface SignupProps {
  onBack: () => void;
  onSignup: () => void;
  logoUrl: string;
}

const Signup: React.FC<SignupProps> = ({ onBack, onSignup, logoUrl }) => {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [classRoom, setClassRoom] = useState('');
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchClasses = async () => {
      try {
        const q = query(collection(firestore, 'elearning_classes'));
        const snap = await getDocs(q);
        setClasses(snap.docs.map(d => ({ id: d.id, ...d.data() } as ClassRoom)));
      } catch (e) {
        console.error("Error fetching classes:", e);
      }
    };
    fetchClasses();
  }, []);

  const checkUsernameAvailable = async (uname: string) => {
    try {
      const q = query(collection(firestore, "users"), where("username", "==", uname), limit(1));
      const snap = await getDocs(q);
      return snap.empty;
    } catch (e) {
      return false;
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (password !== confirmPassword) {
      setError("Konfirmasi password tidak cocok!");
      return;
    }

    if (password.length < 6) {
      setError("Password minimal harus 6 karakter.");
      return;
    }

    setLoading(true);
    const cleanUsername = username.trim().toLowerCase();
    const email = `${cleanUsername}@alirsyad.sch.id`;

    try {
      const isAvailable = await checkUsernameAvailable(cleanUsername);
      if (!isAvailable) {
        throw new Error("Username sudah digunakan. Silakan pilih username lain.");
      }

      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      const userData: User = {
        id: firebaseUser.uid,
        name,
        username: cleanUsername,
        classId: classRoom,
        role: 'STUDENT',
        status: 'PENDING',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${cleanUsername}`,
        createdAt: new Date().toLocaleString('id-ID'),
        password: password
      };

      // Pastikan status adalah PENDING secara eksplisit dan penulisan dokumen selesai
      await setDoc(doc(firestore, "users", firebaseUser.uid), userData);

      await notifyAdmins(
        "Pendaftaran Siswa Baru", 
        `${name} (Kelas ${classRoom}) telah mendaftar. Mohon segera verifikasi akun tersebut.`
      );

      alert("Pendaftaran Berhasil! Akun Anda sedang menunggu konfirmasi Guru Informatika.");

      // Tunggu sejenak sebelum sign out agar auth listener di App.tsx tidak crash
      await new Promise(r => setTimeout(r, 500));
      await signOut(auth);
      onSignup();
    } catch (err: any) {
      if (err.code === 'auth/email-already-in-use') {
        setError("Username/Akun sudah terdaftar. Silakan login.");
      } else {
        setError(err.message || "Gagal melakukan pendaftaran.");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col justify-center items-center px-6 py-12 text-black">
      <div className="w-full max-w-xl bg-white p-10 md:p-14 rounded-[3.5rem] shadow-2xl relative overflow-hidden border border-slate-100">
        {loading && (
          <div className="absolute inset-0 bg-white/80 z-20 flex items-center justify-center backdrop-blur-sm">
            <Loader2 className="animate-spin text-emerald-600" size={48} />
          </div>
        )}

        <button onClick={onBack} className="flex items-center gap-2 text-slate-400 hover:text-slate-900 mb-10 font-black text-xs uppercase tracking-widest transition-colors">
          <ArrowLeft size={16} /> Kembali
        </button>

        <div className="text-center mb-12 space-y-3">
          <div className="w-20 h-20 bg-white rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-sm p-2 border border-slate-50">
             <img src={logoUrl} alt="Logo" className="w-full h-full object-contain" />
          </div>
          <h3 className="text-4xl font-black text-slate-900 tracking-tight">Registrasi Cloud</h3>
          <p className="text-slate-400 font-bold text-sm italic">Siswa Informatika SMP Al Irsyad Surakarta</p>
        </div>

        {error && (
          <div className="mb-8 p-5 bg-rose-50 border border-rose-100 rounded-3xl flex items-center gap-4 text-rose-600 animate-in fade-in slide-in-from-top-2">
            <AlertCircle size={24} className="shrink-0" />
            <p className="text-xs font-black uppercase tracking-tight leading-tight">{error}</p>
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-8">
          {step === 1 ? (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Nama Lengkap Siswa</label>
                <input 
                  value={name} 
                  onChange={e => setName(e.target.value)} 
                  className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-[1.8rem] outline-none font-bold text-slate-800 focus:border-emerald-500 focus:bg-white transition-all shadow-inner" 
                  placeholder="Nama Lengkap..." 
                  required 
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Pilih Kelas</label>
                <select 
                  value={classRoom} 
                  onChange={e => setClassRoom(e.target.value)} 
                  className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-[1.8rem] outline-none font-bold text-slate-800 focus:border-emerald-500 focus:bg-white transition-all shadow-inner appearance-none cursor-pointer" 
                  required
                >
                  <option value="">-- Pilih Kelas Anda --</option>
                  {classes.map(c => <option key={c.id} value={c.name}>Kelas {c.name}</option>)}
                </select>
              </div>
              <button 
                type="button" 
                onClick={() => setStep(2)} 
                disabled={!name || !classRoom}
                className="w-full py-6 bg-slate-900 text-white rounded-[1.8rem] font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-emerald-600 disabled:opacity-30 active:scale-[0.98] transition-all"
              >
                Lanjut ke Kredensial
              </button>
            </div>
          ) : (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Username Baru</label>
                <input 
                  value={username} 
                  onChange={e => setUsername(e.target.value.toLowerCase().replace(/\s/g, ''))} 
                  className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-[1.8rem] outline-none font-black text-emerald-600 focus:border-emerald-500 focus:bg-white transition-all shadow-inner" 
                  placeholder="Contoh: fauzi8a" 
                  required 
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Password</label>
                  <div className="relative">
                    <input 
                      type={showPassword ? 'text' : 'password'} 
                      value={password} 
                      onChange={e => setPassword(e.target.value)} 
                      className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-[1.5rem] outline-none font-bold text-slate-800 focus:border-emerald-500 focus:bg-white transition-all shadow-inner" 
                      placeholder="Minimal 6 Karakter" 
                      required 
                    />
                    <button 
                      type="button" 
                      onClick={() => setShowPassword(!showPassword)} 
                      className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-600 transition-colors"
                    >
                      {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                    </button>
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Ulangi Password</label>
                  <input 
                    type={showPassword ? 'text' : 'password'} 
                    value={confirmPassword} 
                    onChange={e => setConfirmPassword(e.target.value)} 
                    className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-[1.5rem] outline-none font-bold text-slate-800 focus:border-emerald-500 focus:bg-white transition-all shadow-inner" 
                    placeholder="Konfirmasi" 
                    required 
                  />
                </div>
              </div>

              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setStep(1)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-200 transition-all">Kembali</button>
                <button type="submit" className="flex-[2] py-5 bg-emerald-600 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-emerald-100 hover:bg-slate-900 active:scale-[0.98] transition-all">Selesaikan Pendaftaran</button>
              </div>
            </div>
          )}
        </form>
      </div>
    </div>
  );
};

export default Signup;

import React, { useState, useMemo } from 'react';
import { 
  ClipboardList, CheckCircle2, Clock, Calendar, 
  AlertCircle, Send, LayoutList, CheckCircle, 
  ArrowRight, MessageSquare, Star, Loader2,
  X, Info, ExternalLink, Filter, Globe, PlayCircle,
  Link as LinkIcon, FileText, Zap, ChevronRight,
  Trophy, MousePointer2, Monitor, ArrowUpRight,
  PartyPopper, ShieldCheck, BadgeCheck, Award
} from 'lucide-react';
import { db } from '../../App.tsx';
import { User, Submission, Task } from '../../types.ts';

interface TasksTabProps {
  user: User;
  tasks: Task[];
  submissions: Submission[];
  onRefresh: () => void;
}

const TasksTab: React.FC<TasksTabProps> = ({ user, tasks, submissions, onRefresh }) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [link, setLink] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [activeFilter, setActiveFilter] = useState<'all' | 'pending' | 'completed'>('all');

  const getDeadlineInfo = (dueDate: string) => {
    const now = new Date();
    const deadline = new Date(dueDate);
    const diffTime = deadline.getTime() - now.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return { label: 'Lampau', color: 'text-rose-500 bg-rose-50', icon: AlertCircle };
    if (diffDays <= 2) return { label: `${diffDays} hari`, color: 'text-orange-500 bg-orange-50', icon: Clock };
    return { label: `${diffDays} hari`, color: 'text-emerald-500 bg-emerald-50', icon: Calendar };
  };

  const getTypeStyle = (type: string) => {
    switch(type) {
      case 'embed': return { bg: 'bg-purple-50', text: 'text-purple-600', icon: PlayCircle, label: 'Interaktif' };
      case 'file': return { bg: 'bg-emerald-50', text: 'text-emerald-600', icon: FileText, label: 'Modul' };
      case 'link': return { bg: 'bg-blue-50', text: 'text-blue-600', icon: LinkIcon, label: 'Tautan' };
      default: return { bg: 'bg-slate-50', text: 'text-slate-600', icon: ClipboardList, label: 'Tugas' };
    }
  };

  const filteredTasks = useMemo(() => {
    return tasks.filter(t => {
      const isSubmitted = submissions.some(s => s.taskId === t.id);
      if (activeFilter === 'pending') return !isSubmitted;
      if (activeFilter === 'completed') return isSubmitted;
      return true;
    });
  }, [tasks, submissions, activeFilter]);

  const stats = useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter(t => submissions.some(s => s.taskId === t.id)).length;
    return { total, completed, pending: total - completed };
  }, [tasks, submissions]);

  const getEmbedUrl = (url: string) => {
    if (!url) return '';
    let embedUrl = url;
    if (url.includes('youtube.com/watch?v=')) {
      embedUrl = url.replace('watch?v=', 'embed/');
    } else if (url.includes('youtu.be/')) {
      embedUrl = 'https://www.youtube.com/embed/' + url.split('youtu.be/')[1];
    } else if (url.includes('docs.google.com')) {
      embedUrl = url.includes('?') ? `${url}&embedded=true` : `${url}?embedded=true`;
    }
    return embedUrl;
  };

  const handleSubmit = async () => {
    if (!selectedTask) return;

    // Validasi input jika pengumpulan diaktifkan
    if (selectedTask.isSubmissionEnabled) {
      if (!link) {
        alert("Mohon masukkan link hasil pengerjaan Anda (Google Drive/Canva/URL lainnya).");
        return;
      }
      if (!link.startsWith('http')) {
        alert("Mohon masukkan URL yang valid (diawali dengan http:// atau https://).");
        return;
      }
    }

    setSubmitting(true);
    const newSub: Submission = {
      id: `sub_${Date.now()}`,
      taskId: selectedTask.id,
      studentId: user.id,
      content: link || 'Tugas Selesai (Tanpa Pengumpulan Link)',
      submittedAt: new Date().toLocaleString('id-ID'),
    };

    try {
      await db.add('elearning_submissions', newSub);
      setIsSuccess(true);

      // Berikan feedback visual sebentar sebelum menutup modal
      setTimeout(() => {
        onRefresh();
        setLink('');
        setIsSuccess(false);
        setSelectedTask(null);
      }, 1500);
    } catch (err) {
      alert("Gagal mengirim tugas. Mohon periksa koneksi internet Anda.");
      setSubmitting(false);
    }
  };

  const currentSubmission = useMemo(() => {
    if (!selectedTask) return null;
    return submissions.find(s => s.taskId === selectedTask.id);
  }, [selectedTask, submissions]);

  return (
    <div className="space-y-8 animate-in fade-in duration-700 text-black pb-24">
      {/* Dashboard Stats */}
      <section className="grid grid-cols-3 gap-4">
        {[
          { label: 'Total Tugas', val: stats.total, color: 'bg-indigo-600', icon: LayoutList },
          { label: 'Belum Selesai', val: stats.pending, color: 'bg-orange-500', icon: Clock },
          { label: 'Sudah Selesai', val: stats.completed, color: 'bg-emerald-500', icon: CheckCircle2 }
        ].map(s => (
          <div key={s.label} className={`${s.color} p-6 rounded-[2rem] text-white flex flex-col justify-center shadow-lg`}>
            <div className="flex items-center gap-2 opacity-70 mb-2">
               <s.icon size={14} />
               <p className="text-[8px] font-black uppercase tracking-widest">{s.label}</p>
            </div>
            <h4 className="text-3xl font-black tracking-tight">{s.val}</h4>
          </div>
        ))}
      </section>

      {/* Filter Tabs */}
      <section className="flex flex-wrap gap-2">
        {[
          { id: 'all', label: 'Semua Tugas' },
          { id: 'pending', label: 'Perlu Dikerjakan' },
          { id: 'completed', label: 'Selesai' }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveFilter(tab.id as any)}
            className={`px-6 py-3 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${
              activeFilter === tab.id 
                ? 'bg-slate-900 text-white shadow-xl translate-y-[-2px]' 
                : 'bg-white text-slate-400 border border-slate-100 hover:bg-slate-50'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </section>

      {/* Task Grid */}
      <section className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-6">
        {filteredTasks.map(t => {
          const submission = submissions.find(s => s.taskId === t.id);
          const deadline = getDeadlineInfo(t.dueDate);
          const typeStyle = getTypeStyle(t.type);
          return (
            <div key={t.id} className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all duration-500 group flex flex-col overflow-hidden relative">
              <div className={`h-24 ${typeStyle.bg} flex items-center justify-center relative`}>
                 <div className="absolute top-4 right-4">
                    <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest flex items-center gap-1.5 bg-white/90 backdrop-blur-sm shadow-sm ${deadline.color}`}>
                      <Clock size={10} /> {deadline.label}
                    </span>
                 </div>
                 <typeStyle.icon size={36} className={`${typeStyle.text} opacity-20 group-hover:scale-110 transition-transform duration-500`} />
              </div>
              <div className="p-7 flex-1 flex flex-col">
                <div className="flex items-center gap-2 mb-3">
                  <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md bg-slate-100 text-slate-400`}>
                    {typeStyle.label}
                  </span>
                  {submission && (
                    <span className="text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md bg-emerald-100 text-emerald-600 flex items-center gap-1">
                      <CheckCircle size={10} /> Selesai
                    </span>
                  )}
                </div>
                <h4 className="text-lg font-black text-slate-800 mb-3 leading-tight group-hover:text-indigo-600 transition-colors line-clamp-2">{t.title}</h4>
                <div className="mt-auto">
                  <button 
                    onClick={() => { setSelectedTask(t); setIsSuccess(false); setLink(''); }}
                    className={`w-full py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95 ${
                      submission 
                        ? 'bg-slate-50 text-slate-500 border border-slate-100 hover:bg-slate-100' 
                        : 'bg-slate-900 text-white hover:bg-indigo-600 shadow-xl shadow-slate-100'
                    }`}
                  >
                    {submission ? 'Lihat Detail' : 'Kerjakan Sekarang'} 
                  </button>
                </div>
              </div>
            </div>
          );
        })}
      </section>

      {/* Enhanced Task Modal */}
      {selectedTask && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[100] flex items-center justify-center p-4 md:p-10 animate-in fade-in zoom-in-95 duration-300">
            <div className="bg-white w-full max-w-7xl h-full md:max-h-[90vh] rounded-[3rem] shadow-2xl flex flex-col overflow-hidden border border-white/20">

              {/* Modal Header */}
              <div className="p-6 md:px-10 border-b border-slate-50 flex items-center justify-between bg-white shrink-0">
                 <div className="flex items-center gap-5">
                    <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${getTypeStyle(selectedTask.type).bg} ${getTypeStyle(selectedTask.type).text} shadow-inner`}>
                      <ClipboardList size={28} />
                    </div>
                    <div>
                      <h3 className="text-xl font-black text-slate-800 tracking-tight leading-none">{selectedTask.title}</h3>
                      <p className="text-slate-400 font-bold text-[10px] uppercase tracking-[0.2em] mt-2 flex items-center gap-2">
                        <Calendar size={12} /> Tenggat: {selectedTask.dueDate}
                      </p>
                    </div>
                 </div>
                 <button onClick={() => { if(!submitting) setSelectedTask(null); }} className="p-4 bg-slate-50 text-slate-400 rounded-2xl hover:bg-rose-50 hover:text-rose-500 transition-all active:scale-90">
                    <X size={24} />
                 </button>
              </div>

              <div className="flex-1 flex flex-col lg:flex-row overflow-hidden">
                {/* Task Content / Iframe Area */}
                <div className="flex-[3] bg-slate-100 p-4 md:p-8 overflow-hidden border-r border-slate-50 flex flex-col">
                  <div className="bg-blue-50 border border-blue-100 p-4 rounded-2xl mb-4 flex items-center justify-between gap-4">
                    <div className="flex items-center gap-3">
                      <Info size={18} className="text-blue-500 shrink-0" />
                      <p className="text-[11px] font-bold text-blue-700 leading-tight">Gunakan viewer di bawah untuk melihat soal/materi tugas secara langsung.</p>
                    </div>
                    <a href={selectedTask.content} target="_blank" rel="noreferrer" className="shrink-0 px-5 py-2.5 bg-white text-blue-600 rounded-xl text-[10px] font-black uppercase tracking-widest border border-blue-100 hover:bg-blue-600 hover:text-white transition-all flex items-center gap-2">
                       <ExternalLink size={14} /> Buka Tab Baru
                    </a>
                  </div>
                  <div className="flex-1 w-full bg-white rounded-[2rem] shadow-2xl overflow-hidden border-4 border-white relative">
                    <iframe 
                      src={getEmbedUrl(selectedTask.content)} 
                      className="w-full h-full border-0" 
                      allowFullScreen 
                      title="Task Content"
                      loading="lazy"
                    ></iframe>
                  </div>
                </div>

                {/* Sidebar / Submission Area */}
                <div className="flex-1 bg-white p-8 overflow-y-auto flex flex-col space-y-10 scrollbar-hide">
                  <div className="space-y-4">
                    <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 flex items-center gap-2">
                      <Info size={14} /> Instruksi Guru
                    </h4>
                    <p className="text-xs text-slate-600 font-medium leading-relaxed italic bg-slate-50 p-6 rounded-[2rem] border border-slate-100 shadow-inner">
                      "{selectedTask.description || 'Harap selesaikan tugas ini dengan teliti dan tepat waktu sesuai instruksi yang diberikan.'}"
                    </p>
                  </div>

                  {/* Submission Status or Form */}
                  <div className="pt-8 border-t border-slate-50 space-y-6">
                    <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 flex items-center gap-2">
                      <Zap size={14} className="text-amber-500" /> Status Pengumpulan
                    </h4>

                    {currentSubmission ? (
                      <div className="space-y-6">
                        {/* Submitted Content Card */}
                        <div className="bg-emerald-50 border border-emerald-100 p-6 rounded-[2.5rem] relative overflow-hidden group">
                           <div className="absolute top-0 right-0 w-24 h-24 bg-emerald-100 rounded-full -mr-12 -mt-12 opacity-50"></div>
                           <div className="relative z-10 space-y-4">
                              <div className="flex items-center gap-3">
                                 <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-emerald-600 shadow-sm">
                                    <BadgeCheck size={22} />
                                 </div>
                                 <div>
                                    <p className="text-[9px] font-black text-emerald-600 uppercase tracking-widest leading-none">Tugas Terkirim</p>
                                    <p className="text-[10px] text-slate-500 font-bold mt-1">{currentSubmission.submittedAt}</p>
                                 </div>
                              </div>
                              <div className="pt-4 border-t border-emerald-100 flex flex-col gap-2">
                                 <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Keterangan/Link:</p>
                                 {currentSubmission.content.startsWith('http') ? (
                                   <a 
                                    href={currentSubmission.content} 
                                    target="_blank" 
                                    rel="noreferrer" 
                                    className="text-[11px] font-bold text-blue-600 hover:underline flex items-center gap-2 truncate"
                                   >
                                      <LinkIcon size={12} /> {currentSubmission.content}
                                   </a>
                                 ) : (
                                   <p className="text-[11px] font-bold text-slate-600 flex items-center gap-2">
                                      <CheckCircle2 size={12} className="text-emerald-500" /> {currentSubmission.content}
                                   </p>
                                 )}
                              </div>
                           </div>
                        </div>

                        {/* Grading Card */}
                        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden">
                           <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-2xl -mr-16 -mt-16"></div>
                           <div className="relative z-10 flex flex-col items-center text-center space-y-4">
                              <Award size={32} className="text-indigo-400" />
                              <div>
                                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-3">Hasil Penilaian</p>
                                 <div className="text-5xl font-black tracking-tighter text-white">
                                    {currentSubmission.grade !== undefined && currentSubmission.grade !== null 
                                      ? currentSubmission.grade 
                                      : <span className="text-slate-600 italic">--</span>}
                                 </div>
                                 {currentSubmission.grade === undefined || currentSubmission.grade === null ? (
                                   <p className="text-[9px] font-bold text-amber-400 mt-4 uppercase tracking-widest bg-amber-400/10 px-4 py-2 rounded-full border border-amber-400/20">Menunggu Koreksi Guru</p>
                                 ) : (
                                   <div className="mt-6 p-4 bg-white/5 border border-white/10 rounded-2xl w-full">
                                      <p className="text-[11px] font-medium text-slate-300 italic">
                                         {currentSubmission.feedback ? `"${currentSubmission.feedback}"` : "Selamat! Tugasmu sudah dinilai."}
                                      </p>
                                   </div>
                                 )}
                              </div>
                           </div>
                        </div>
                      </div>
                    ) : (
                      <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
                        {selectedTask.isSubmissionEnabled ? (
                          <>
                            <div className="p-6 bg-blue-50 rounded-[2rem] border border-blue-100">
                               <p className="text-[10px] font-bold text-blue-700 leading-relaxed italic">
                                 Siswa diperbolehkan mengumpulkan tugas melalui link Google Drive, Canva, atau platform lainnya. Pastikan link dapat diakses oleh Guru.
                               </p>
                            </div>
                            <div className="space-y-3">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Tautan Hasil Pekerjaan (URL)</label>
                              <div className="relative group">
                                <Globe className={`absolute left-5 top-1/2 -translate-y-1/2 transition-colors ${link ? 'text-emerald-500' : 'text-slate-300'}`} size={20} />
                                <input 
                                  type="url"
                                  value={link} 
                                  onChange={e => setLink(e.target.value)} 
                                  placeholder="https://canva.com/..." 
                                  className="w-full p-5 pl-14 bg-slate-50 border-2 border-slate-100 rounded-2xl text-xs font-bold outline-none focus:bg-white focus:border-emerald-500 transition-all shadow-inner" 
                                />
                              </div>
                            </div>
                          </>
                        ) : (
                          <div className="p-6 bg-amber-50 rounded-[2rem] border border-amber-100">
                             <p className="text-[10px] font-bold text-amber-700 leading-relaxed italic text-center">
                               Tugas ini tidak memerlukan pengiriman link. Klik tombol di bawah jika Anda sudah selesai mengerjakan sesuai instruksi.
                             </p>
                          </div>
                        )}

                        <button 
                          onClick={handleSubmit} 
                          disabled={submitting || isSuccess} 
                          className={`w-full py-6 rounded-3xl font-black text-sm uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-4 shadow-2xl active:scale-[0.98] ${
                            isSuccess 
                              ? 'bg-emerald-600 text-white' 
                              : 'bg-slate-900 text-white hover:bg-emerald-600 shadow-slate-100 hover:shadow-emerald-200'
                          }`}
                        >
                          {submitting ? (
                            <Loader2 size={24} className="animate-spin" />
                          ) : isSuccess ? (
                            <>
                              <PartyPopper size={24} className="animate-bounce" /> Berhasil!
                            </>
                          ) : (
                            <>
                              <Send size={20} /> {selectedTask.isSubmissionEnabled ? 'Kumpulkan Tugas' : 'Selesai Mengerjakan'}
                            </>
                          )}
                        </button>

                        <p className="text-center text-[9px] text-slate-400 font-bold uppercase tracking-widest">
                          Tugas yang dikirim tidak dapat diubah tanpa seizin Guru.
                        </p>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
      )}
    </div>
  );
};

export default TasksTab;

import React, { useState, useRef } from 'react';
import { 
  Camera, UserCog, Lock, Eye, EyeOff, 
  Info, Save, Loader2, User as UserIcon,
  ShieldCheck, BadgeCheck, LayoutGrid, Trash2,
  RefreshCw
} from 'lucide-react';
import { db } from '../../App';
import { User } from '../../types';
import { auth, firestore } from '../../firebase';
import { updatePassword, updateEmail } from "firebase/auth";
import { doc, setDoc } from "firebase/firestore";

interface SettingsTabProps {
  user: User;
  onUpdateUser?: (u: User) => void;
}

const SettingsTab: React.FC<SettingsTabProps> = ({ user, onUpdateUser }) => {
  const [name, setName] = useState(user.name);
  const [username, setUsername] = useState(user.username);
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [previewAvatar, setPreviewAvatar] = useState(user.avatar || '');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 500 * 1024) {
        alert("Ukuran foto terlalu besar! Maksimal 500KB.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setPreviewAvatar(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const randomizeAvatar = () => {
    // Menghasilkan string acak untuk seed avatar baru
    const randomSeed = Math.random().toString(36).substring(2, 10);
    setPreviewAvatar(`https://api.dicebear.com/7.x/avataaars/svg?seed=${randomSeed}`);
  };

  const handleUpdate = async () => {
    if (!username || !name) return alert("Nama dan Username tidak boleh kosong!");

    setIsSaving(true);
    let authError = false;
    let errorMsg = "";

    try {
      const currentUser = auth.currentUser;

      // Jika password diisi, update di Firebase Auth
      if (password && currentUser) {
        if (password.length < 6) throw new Error("Password minimal 6 karakter.");
        try {
          await updatePassword(currentUser, password);
        } catch (e: any) {
          authError = true;
          errorMsg += "Gagal update password ke sistem login. ";
        }
      }

      // Jika username berubah, update email di Firebase Auth
      if (username !== user.username && currentUser) {
        const newEmail = `${username}@alirsyad.sch.id`;
        try {
          await updateEmail(currentUser, newEmail);
        } catch (e: any) {
          authError = true;
          errorMsg += "Gagal update username ke sistem login. ";
        }
      }

      // Update data di Firestore
      const updatedUser: User = { 
        ...user, 
        name,
        username: authError && username !== user.username ? user.username : username, 
        avatar: previewAvatar,
        // SINKRONISASI: Simpan password baru ke Firestore agar Admin bisa lihat
        password: password || user.password,
        status: user.status || 'ACTIVE'
      };

      await setDoc(doc(firestore, "users", user.id), updatedUser, { merge: true });

      if (onUpdateUser) onUpdateUser(updatedUser);

      if (authError) {
        alert("Nama & Foto berhasil diperbarui, namun ada kendala di sistem login: " + errorMsg);
      } else {
        setPassword('');
        alert("Profil Anda berhasil diperbarui!");
      }
    } catch (err: any) {
      alert("Gagal menyimpan: " + err.message);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-8 duration-700 text-black pb-32 px-4">
      <section className="bg-white rounded-[3.5rem] p-10 border border-slate-100 shadow-sm relative overflow-hidden flex flex-col items-center text-center">
        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-50 rounded-full -mr-32 -mt-32 opacity-50"></div>
        <div className="relative z-10 space-y-6">
          <div className="relative group mx-auto w-max">
            <div className="absolute -inset-2 bg-gradient-to-tr from-emerald-500 to-indigo-500 rounded-full blur opacity-20"></div>
            <img 
              src={previewAvatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} 
              className="w-40 h-40 rounded-full border-8 border-white shadow-2xl bg-white object-cover relative" 
              alt="Avatar"
            />
            <div className="absolute bottom-2 right-2 flex gap-2">
              <button 
                onClick={() => fileInputRef.current?.click()} 
                className="p-3 bg-emerald-600 text-white rounded-2xl shadow-lg border-4 border-white hover:scale-110 transition-all"
                title="Unggah Foto"
              >
                <Camera size={20}/>
              </button>
              <button 
                onClick={randomizeAvatar} 
                className="p-3 bg-white text-rose-500 rounded-2xl shadow-lg border-4 border-white hover:bg-rose-50 transition-all"
                title="Acak Avatar"
              >
                <RefreshCw size={20}/>
              </button>
            </div>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
          </div>
          <div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">{name}</h2>
            <div className="flex items-center justify-center gap-2 mt-2">
              <span className="px-4 py-1.5 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 border border-indigo-100">
                <BadgeCheck size={14} /> Siswa Aktif
              </span>
              <span className="px-4 py-1.5 bg-slate-900 text-white rounded-full text-[10px] font-black uppercase tracking-widest">
                Kelas {user.classId}
              </span>
            </div>
          </div>
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        <div className="lg:col-span-7 space-y-8">
          <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm">
            <div className="flex items-center gap-4 mb-10">
              <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center"><UserCog size={24}/></div>
              <h4 className="text-xl font-black text-slate-800">Identitas Diri</h4>
            </div>
            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Lengkap</label>
                <input value={name} onChange={e => setName(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl font-bold outline-none focus:border-emerald-500 transition-all" />
              </div>
              <div className="space-y-2">
                <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-1">Username (Login ID)</label>
                <input value={username} onChange={e => setUsername(e.target.value.toLowerCase())} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl font-black text-emerald-600 outline-none focus:border-emerald-500 transition-all" />
              </div>
              <div className="space-y-2">
                <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-1">Ganti Password (Opsional)</label>
                <div className="relative">
                  <input type={showPassword ? 'text' : 'password'} value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" className="w-full p-5 pr-14 bg-slate-50 border border-slate-200 rounded-2xl font-bold outline-none focus:border-emerald-500 transition-all" />
                  <button onClick={() => setShowPassword(!showPassword)} className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400">{showPassword ? <EyeOff size={20}/> : <Eye size={20}/>}</button>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-5 flex flex-col gap-6">
          <div className="bg-slate-900 p-10 rounded-[3rem] text-white shadow-2xl relative overflow-hidden flex flex-col">
             <h4 className="text-xl font-black mb-6">Status Cloud</h4>
             <div className="space-y-4">
                <div className="flex justify-between items-center py-3 border-b border-white/10">
                   <span className="text-xs text-slate-400 font-bold uppercase">ID Database</span>
                   <span className="text-xs font-mono">{user.id.substring(0, 12)}...</span>
                </div>
                <div className="flex justify-between items-center py-3 border-b border-white/10">
                   <span className="text-xs text-slate-400 font-bold uppercase">Email Login</span>
                   <span className="text-xs font-bold text-emerald-400">{username}@alirsyad.sch.id</span>
                </div>
             </div>
          </div>
          <button onClick={handleUpdate} disabled={isSaving} className="w-full py-6 bg-emerald-600 text-white rounded-[2rem] font-black text-xl hover:bg-emerald-700 transition-all flex items-center justify-center gap-4 shadow-xl active:scale-95 disabled:opacity-50">
            {isSaving ? <Loader2 className="animate-spin" size={24}/> : <Save size={24}/>}
            {isSaving ? 'Memproses...' : 'Update Profil'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default SettingsTab;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { 
  LogOut, User as UserIcon, Bell, X, Check, 
  Info, BookOpen, ClipboardList, CheckCircle, 
  UserPlus, ChevronDown, Settings, UserCircle 
} from 'lucide-react';

interface Notification {
  id: string;
  title: string;
  message: string;
  read: boolean;
  type: 'material' | 'task' | 'grade' | 'registration';
  createdAt: string;
}

interface LayoutProps {
  children: React.ReactNode;
  user: any;
  onLogout: () => void;
  sidebarItems: { icon: any; label: string; id: string }[];
  activeView: string;
  setActiveView: (id: string) => void;
  logoUrl: string;
  siteName: string;
  notifications?: Notification[];
  onMarkAsRead?: (id: string) => void;
  onMarkAllAsRead?: () => void;
}

const Layout: React.FC<LayoutProps> = ({ 
  children, 
  user, 
  onLogout, 
  sidebarItems, 
  activeView, 
  setActiveView,
  logoUrl,
  siteName,
  notifications = [],
  onMarkAsRead,
  onMarkAllAsRead
}) => {
  const [showNotifications, setShowNotifications] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);

  const sortedNotifications = useMemo(() => {
    return [...notifications].sort((a, b) => b.id.localeCompare(a.id));
  }, [notifications]);

  const unreadCount = useMemo(() => {
    return notifications.filter(n => !n.read).length;
  }, [notifications]);

  const notificationRef = useRef<HTMLDivElement>(null);
  const profileRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setShowProfileMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const getIcon = (type: string) => {
    switch(type) {
      case 'material': return <BookOpen size={16} className="text-emerald-500" />;
      case 'task': return <ClipboardList size={16} className="text-purple-500" />;
      case 'grade': return <CheckCircle size={16} className="text-blue-500" />;
      case 'registration': return <UserPlus size={16} className="text-orange-500" />;
      default: return <Info size={16} className="text-slate-400" />;
    }
  };

  const NotificationBadge = ({ count }: { count: number }) => (
    count > 0 ? (
      <span className="absolute -top-1 -right-1 w-4 h-4 md:w-5 md:h-5 bg-rose-500 text-white text-[8px] md:text-[9px] font-black flex items-center justify-center rounded-full border-2 border-white shadow-lg animate-in zoom-in-50 duration-300">
        {count > 9 ? '9+' : count}
      </span>
    ) : null
  );

  return (
    <div className="flex min-h-screen bg-slate-50">
      {/* Sidebar Desktop */}
      <aside className="w-72 bg-white border-r border-slate-200 hidden md:flex flex-col sticky top-0 h-screen">
        <div className="p-8 flex flex-col gap-4">
          <img src={logoUrl} alt="Logo" className="h-14 w-auto object-contain self-start" />
          <span className="font-black text-slate-800 text-[10px] leading-tight opacity-40 uppercase tracking-[0.3em]">{siteName}</span>
        </div>

        <nav className="flex-1 px-4 py-4 space-y-2">
          {sidebarItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveView(item.id)}
              className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${
                activeView === item.id 
                  ? 'bg-slate-900 text-white shadow-2xl shadow-slate-200 translate-x-1' 
                  : 'text-slate-400 hover:bg-slate-50 hover:text-slate-600'
              }`}
            >
              <item.icon size={20} />
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-6 border-t border-slate-50">
          <div className="p-5 bg-emerald-50 rounded-[2rem] border border-emerald-100/50">
             <p className="text-[9px] font-black text-emerald-600 uppercase tracking-widest mb-1.5 flex items-center gap-2">
               <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
               Status Sistem
             </p>
             <span className="text-[11px] font-bold text-slate-700">Cloud Terhubung</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        {/* Navbar */}
        <header className="h-16 md:h-20 bg-white/80 backdrop-blur-md border-b border-slate-200 px-4 md:px-10 flex items-center justify-between sticky top-0 z-40">
          <div className="flex items-center gap-4">
            <h2 className="text-lg md:text-xl font-black text-slate-900 tracking-tighter truncate max-w-[150px] md:max-w-none">
              {sidebarItems.find(i => i.id === activeView)?.label || 'Dashboard'}
            </h2>
          </div>

          <div className="flex items-center gap-2 md:gap-4">
            <div className="relative" ref={notificationRef}>
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className={`p-2.5 md:p-3.5 rounded-xl md:rounded-2xl transition-all relative ${showNotifications ? 'bg-slate-900 text-white shadow-xl' : 'bg-slate-50 text-slate-400 hover:text-slate-900'}`}
              >
                <Bell size={18} className="md:w-5 md:h-5" />
                <NotificationBadge count={unreadCount} />
              </button>

              {showNotifications && (
                <div className="absolute right-0 mt-4 w-[280px] md:w-[28rem] bg-white rounded-3xl md:rounded-[3rem] shadow-2xl border border-slate-100 overflow-hidden z-50 animate-in fade-in slide-in-from-top-4 duration-300">
                  <div className="p-5 md:p-8 border-b border-slate-50 flex items-center justify-between bg-white">
                    <div>
                      <h4 className="font-black text-slate-900 text-base md:text-lg tracking-tight">Notifikasi</h4>
                      <p className="text-[8px] md:text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Kamu punya {unreadCount} pesan baru</p>
                    </div>
                    {unreadCount > 0 && (
                      <button 
                        onClick={() => {
                          onMarkAllAsRead?.();
                          setShowNotifications(false);
                        }}
                        className="text-[8px] md:text-[10px] font-black text-emerald-600 uppercase hover:bg-emerald-50 px-3 py-1.5 rounded-lg transition-all active:scale-95"
                      >
                        Tandai Semua
                      </button>
                    )}
                  </div>
                  <div className="max-h-[350px] md:max-h-[450px] overflow-y-auto scrollbar-hide bg-white">
                    {sortedNotifications.length === 0 ? (
                      <div className="py-12 md:py-20 text-center">
                        <div className="w-16 h-16 bg-slate-50 text-slate-200 rounded-2xl flex items-center justify-center mx-auto mb-4">
                           <Bell size={30} />
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Belum ada aktivitas baru</p>
                      </div>
                    ) : (
                      sortedNotifications.map((notif) => (
                        <div 
                          key={notif.id} 
                          onClick={() => {
                            onMarkAsRead?.(notif.id);
                            if (!notif.read) setShowNotifications(false);
                          }}
                          className={`p-4 md:p-6 flex gap-4 md:gap-5 cursor-pointer transition-all border-b border-slate-50 last:border-0 ${!notif.read ? 'bg-emerald-50/30 hover:bg-emerald-50/50' : 'hover:bg-slate-50 opacity-60'}`}
                        >
                          <div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center shrink-0 shadow-sm ${!notif.read ? 'bg-white' : 'bg-slate-100 grayscale'}`}>
                            {getIcon(notif.type)}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-start justify-between gap-2 mb-0.5 md:mb-1">
                              <p className={`text-xs md:text-sm truncate ${!notif.read ? 'font-black text-slate-900' : 'font-bold text-slate-500'}`}>{notif.title}</p>
                              <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest shrink-0">{notif.createdAt.split(',')[0]}</p>
                            </div>
                            <p className="text-[10px] md:text-xs text-slate-500 font-medium line-clamp-2 leading-relaxed">{notif.message}</p>
                          </div>
                          {!notif.read && (
                            <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full mt-2 shrink-0 shadow-[0_0_8px_rgba(16,185,129,0.8)]"></div>
                          )}
                        </div>
                      ))
                    )}
                  </div>
                </div>
              )}
            </div>

            <div className="h-8 w-[1px] bg-slate-100 mx-1 md:mx-2"></div>

            <div className="relative" ref={profileRef}>
              <button 
                onClick={() => setShowProfileMenu(!showProfileMenu)}
                className={`flex items-center gap-2 p-1 md:p-1.5 md:pr-5 rounded-full transition-all ${
                  showProfileMenu 
                    ? 'bg-slate-900 text-white shadow-2xl' 
                    : 'bg-slate-50 border border-slate-100 text-slate-800'
                }`}
              >
                <img 
                  src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} 
                  alt="Profile" 
                  className={`w-8 h-8 md:w-9 md:h-9 rounded-full border-2 ${showProfileMenu ? 'border-white/20' : 'border-white'} bg-white object-cover`}
                />
                <div className="text-left hidden sm:block">
                  <p className="text-xs font-black leading-none">{user.name.split(' ')[0]}</p>
                </div>
                <ChevronDown size={12} className={`transition-transform duration-300 hidden md:block ${showProfileMenu ? 'rotate-180' : ''}`} />
              </button>

              {showProfileMenu && (
                <div className="absolute right-0 mt-4 w-64 md:w-72 bg-white rounded-3xl md:rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden z-50 animate-in fade-in slide-in-from-top-4 duration-300">
                  <div className="p-6 md:p-8 bg-slate-50 border-b border-slate-100 flex flex-col items-center text-center">
                    <img 
                      src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} 
                      className="w-16 h-16 md:w-20 md:h-20 rounded-full border-4 border-white shadow-xl mb-4"
                      alt=""
                    />
                    <h5 className="text-sm md:text-base font-black text-slate-900">{user.name}</h5>
                    <p className="text-[8px] md:text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] mt-1">Siswa Informatika</p>
                  </div>

                  <div className="p-2 md:p-3 space-y-1">
                    <button 
                      onClick={() => { setActiveView('settings'); setShowProfileMenu(false); }}
                      className="w-full flex items-center gap-3 md:gap-4 px-4 py-3 rounded-xl md:rounded-2xl text-[10px] md:text-xs font-black text-slate-600 hover:bg-slate-50 transition-colors uppercase tracking-widest"
                    >
                      <Settings size={18} className="text-slate-400" /> Profil Akun
                    </button>
                    <button 
                      onClick={onLogout}
                      className="w-full flex items-center gap-3 md:gap-4 px-4 py-3 rounded-xl md:rounded-2xl text-[10px] md:text-xs font-black text-rose-500 hover:bg-rose-50 transition-colors uppercase tracking-widest"
                    >
                      <LogOut size={18} /> Logout
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-12 scrollbar-hide">
          {children}
        </div>
      </main>

      {/* Mobile Bottom Navigation */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex justify-around items-center h-16 px-2 z-50 shadow-[0_-10px_40px_rgba(0,0,0,0.05)] rounded-t-[1.5rem] md:rounded-t-[2.5rem]">
        {sidebarItems.slice(0, 3).map((item) => (
          <button
            key={item.id}
            onClick={() => setActiveView(item.id)}
            className={`flex flex-col items-center gap-1 p-2 rounded-xl transition-all ${
              activeView === item.id ? 'bg-slate-900 text-white shadow-lg scale-105' : 'text-slate-400'
            }`}
          >
            <item.icon size={20} />
          </button>
        ))}
        {/* Mobile Notification Access */}
        <button
          onClick={() => setShowNotifications(true)}
          className={`flex flex-col items-center gap-1 p-2 rounded-xl text-slate-400 relative`}
        >
          <Bell size={20} />
          <NotificationBadge count={unreadCount} />
        </button>
        <button
          onClick={() => setActiveView('settings')}
          className={`flex flex-col items-center gap-1 p-2 rounded-xl transition-all ${
            activeView === 'settings' ? 'bg-slate-900 text-white shadow-lg scale-105' : 'text-slate-400'
          }`}
        >
          <UserIcon size={20} />
        </button>
      </nav>
    </div>
  );
};

export default Layout;

