                      "{selectedTask.description || 'Selesaikan tugas ini tepat waktu.'}"
                    </p>
                  </div>

                  {/* Submission Status or Form */}
                  <div className="pt-6 md:pt-8 border-t border-slate-50 space-y-4 md:space-y-6">
