                        </div>

                        {/* Grading Card */}
                        <div className="bg-slate-900 p-6 md:p-8 rounded-[1.5rem] md:rounded-[2.5rem] text-white shadow-xl text-center">
                           <Award size={24} className="text-indigo-400 mx-auto mb-2 md:w-8 md:h-8" />
                           <p className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Nilai</p>
                           <div className="text-3xl md:text-5xl font-black text-white">
                              {currentSubmission.grade ?? '--'}
                           </div>
                           {currentSubmission.grade === undefined && (
                             <p className="text-[8px] font-bold text-amber-400 mt-3 uppercase tracking-widest bg-amber-400/10 px-3 py-1 rounded-full border border-amber-400/20 inline-block">Proses Koreksi</p>
                           )}
                        </div>
                      </div>
                    ) : (
                      <div className="space-y-4 md:space-y-6">
                        {selectedTask.isSubmissionEnabled ? (
                          <div className="space-y-3">
                            <label className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Link Hasil Tugas (URL)</label>
                            <div className="relative">
                              <Globe className={`absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 w-4 h-4 transition-colors ${link ? 'text-emerald-500' : ''}`} />
                              <input 
                                type="url"
                                value={link} 
                                onChange={e => setLink(e.target.value)} 
                                placeholder="https://..." 
                                className="w-full p-4 pl-11 bg-slate-50 border border-slate-100 rounded-xl text-[10px] font-bold outline-none focus:bg-white focus:border-emerald-500 transition-all shadow-inner" 
                              />
                            </div>
                          </div>
                        ) : (
                          <div className="p-4 bg-amber-50 rounded-xl border border-amber-100">
                             <p className="text-[9px] md:text-[10px] font-bold text-amber-700 leading-relaxed italic text-center">
                               Tugas ini tidak memerlukan pengiriman link.
                             </p>
                          </div>
                        )}

                        <button 
                          onClick={handleSubmit} 
                          disabled={submitting || isSuccess} 
                          className={`w-full py-4 md:py-6 rounded-xl md:rounded-3xl font-black text-xs md:text-sm uppercase tracking-[0.15em] transition-all flex items-center justify-center gap-3 shadow-xl active:scale-[0.98] ${
                            isSuccess 
                              ? 'bg-emerald-600 text-white' 
                              : 'bg-slate-900 text-white hover:bg-emerald-600'
                          }`}
                        >
                          {submitting ? (
                            <Loader2 size={20} className="animate-spin" />
                          ) : isSuccess ? (
                            <>Berhasil!</>
                          ) : (
                            <>{selectedTask.isSubmissionEnabled ? 'Kirim Tugas' : 'Selesai'}</>
                          )}
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
      )}
    </div>
  );
};

export default TasksTab;

import React, { useState, useMemo } from 'react';
import { 
  FileText, ExternalLink, Search, Filter, 
  PlayCircle, Link as LinkIcon, Clock, Sparkles, 
  SearchX, ChevronRight, BookOpen, X, Info,
  Monitor, Globe, ArrowUpRight, Zap
} from 'lucide-react';

interface MaterialsTabProps {
  materials: any[];
}

const MaterialsTab: React.FC<MaterialsTabProps> = ({ materials }) => {
  const [search, setSearch] = useState('');
  const [activeFilter, setActiveFilter] = useState('all');
  const [selectedMaterial, setSelectedMaterial] = useState<any | null>(null);

  const filteredMaterials = useMemo(() => {
    return materials.filter(m => {
      const matchSearch = m.title.toLowerCase().includes(search.toLowerCase()) || 
                          m.description.toLowerCase().includes(search.toLowerCase());
      const matchFilter = activeFilter === 'all' || m.type === activeFilter;
      return matchSearch && matchFilter;
    });
  }, [materials, search, activeFilter]);

  const getTypeStyle = (type: string) => {
    switch(type) {
      case 'embed': return { bg: 'bg-purple-50', text: 'text-purple-600', icon: PlayCircle, label: 'Video' };
      case 'file': return { bg: 'bg-emerald-50', text: 'text-emerald-600', icon: FileText, label: 'Modul' };
      case 'link': return { bg: 'bg-blue-50', text: 'text-blue-600', icon: LinkIcon, label: 'Tautan' };
      default: return { bg: 'bg-slate-50', text: 'text-slate-600', icon: BookOpen, label: 'Materi' };
    }
  };

  const getEmbedUrl = (url: string) => {
    if (!url) return '';
    let embedUrl = url;

    // YouTube
    if (url.includes('youtube.com/watch?v=')) {
      embedUrl = url.replace('watch?v=', 'embed/');
    } else if (url.includes('youtu.be/')) {
      embedUrl = 'https://www.youtube.com/embed/' + url.split('youtu.be/')[1];
    }
    // Google Forms/Docs/Slides
    else if (url.includes('docs.google.com')) {
      embedUrl = url.includes('?') ? `${url}&embedded=true` : `${url}?embedded=true`;
    }

    return embedUrl;
  };

  return (
    <div className="space-y-4 md:space-y-8 animate-in fade-in duration-700 text-black pb-20">

      {/* Search & Filter */}
      <section className="bg-white p-4 md:p-6 rounded-2xl md:rounded-[2.5rem] border border-slate-100 shadow-sm space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-3">
          <div className="space-y-0.5">
            <h3 className="text-lg md:text-xl font-black text-slate-800 tracking-tight">Perpustakaan Digital</h3>
            <p className="text-slate-500 font-medium text-[10px] md:text-xs">Akses materi Informatika kapan pun.</p>
          </div>
          <div className="relative w-full md:w-80 group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 w-4 h-4 md:w-[18px] md:h-[18px] group-focus-within:text-emerald-500 transition-colors" size={18} />
            <input 
              type="text" 
              placeholder="Cari materi..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-11 pr-5 py-2.5 md:py-3 bg-slate-50 border border-slate-100 rounded-xl md:rounded-2xl font-bold outline-none focus:ring-4 focus:ring-emerald-500/5 transition-all text-xs md:text-sm shadow-inner"
            />
          </div>
        </div>

        <div className="flex flex-wrap gap-1.5 md:gap-2">
          {['all', 'embed', 'file', 'link'].map((f) => (
            <button
              key={f}
              onClick={() => setActiveFilter(f)}
              className={`px-4 py-2 rounded-lg md:rounded-xl text-[7px] md:text-[9px] font-black uppercase tracking-widest transition-all ${
                activeFilter === f ? 'bg-slate-900 text-white shadow-lg' : 'bg-slate-50 text-slate-400 border border-slate-100 hover:bg-slate-100'
              }`}
            >
              {f === 'all' ? 'Semua' : f === 'embed' ? 'Video' : f === 'file' ? 'Modul' : 'Tautan'}
            </button>
          ))}
        </div>
      </section>

      {/* Materials Grid */}
      <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-5">
        {filteredMaterials.map((m: any) => {
          const style = getTypeStyle(m.type);
          const Icon = style.icon;
          return (
            <div key={m.id} className="bg-white rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300 group flex flex-col overflow-hidden">
              <div className={`h-20 md:h-24 ${style.bg} relative flex items-center justify-center`}>
                <Icon size={28} className={`${style.text} opacity-20 group-hover:scale-110 transition-transform md:w-8 md:h-8`} />
              </div>
              <div className="p-5 md:p-6 flex-1 flex flex-col">
                <span className={`text-[7px] md:text-[8px] font-black uppercase tracking-widest px-2 py-0.5 ${style.bg} ${style.text} rounded-md w-fit mb-2 md:mb-3`}>
                  {style.label}
                </span>
                <h4 className="text-sm md:text-base font-black text-slate-800 mb-1.5 md:mb-2 leading-tight line-clamp-2">{m.title}</h4>
                <p className="text-[10px] md:text-[11px] text-slate-500 font-medium mb-4 line-clamp-2 opacity-80 leading-relaxed">{m.description || 'Pelajari materi ini.'}</p>
                <button 
                  onClick={() => setSelectedMaterial(m)}
                  className="mt-auto w-full py-3 bg-slate-900 text-white rounded-xl font-black text-[8px] md:text-[9px] uppercase tracking-widest hover:bg-emerald-600 transition-all flex items-center justify-center gap-1.5 shadow-sm"
                >
                  Buka Materi <ChevronRight size={14}/>
                </button>
              </div>
            </div>
          );
        })}
      </section>

      {/* Embed Modal for Materials */}
      {selectedMaterial && (() => {
        const style = getTypeStyle(selectedMaterial.type);
        const Icon = style.icon;
        return (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-md z-[100] flex items-center justify-center p-2 md:p-8 animate-in fade-in duration-300">
            <div className="bg-white w-full max-w-6xl h-full md:max-h-[90vh] rounded-2xl md:rounded-[3.5rem] shadow-2xl flex flex-col overflow-hidden">

              {/* Header */}
              <div className="p-4 md:px-10 border-b border-slate-50 flex items-center justify-between bg-white shrink-0">
                 <div className="flex items-center gap-3 md:gap-4">
                    <div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center ${style.bg} ${style.text} shadow-inner`}>
                      <Icon size={20} className="md:w-6 md:h-6" />
                    </div>
                    <div className="min-w-0">
                      <h3 className="text-sm md:text-xl font-black text-slate-800 leading-none truncate max-w-[180px] md:max-w-none">{selectedMaterial.title}</h3>
                      <p className="text-slate-400 font-bold text-[8px] md:text-[9px] uppercase tracking-widest mt-1 md:mt-2">Materi Informatika</p>
                    </div>
                 </div>
                 <button onClick={() => setSelectedMaterial(null)} className="p-2 md:p-3 bg-slate-50 text-slate-400 rounded-lg md:rounded-2xl hover:bg-rose-50 hover:text-rose-500 transition-all">
                    <X size={20} className="md:w-6 md:h-6" />
                 </button>
              </div>

              {/* Content Area */}
              <div className="flex-1 flex flex-col lg:flex-row overflow-hidden">
                {/* Main Viewer */}
                <div className="flex-1 bg-slate-100 relative p-3 md:p-8 flex flex-col">
                   <div className="bg-blue-50 border border-blue-100 p-3 md:p-4 rounded-xl md:rounded-2xl mb-3 md:mb-4 flex items-center justify-between gap-3">
                      <div className="flex items-center gap-2">
                         <Info size={14} className="text-blue-500 shrink-0 md:w-4 md:h-4" />
                         <p className="text-[9px] md:text-[10px] font-bold text-blue-700 leading-tight">Lihat materi di bawah atau buka di tab baru.</p>
                      </div>
                      <a href={selectedMaterial.content} target="_blank" rel="noreferrer" className="shrink-0 px-3 md:px-5 py-2 bg-white text-blue-600 rounded-lg md:rounded-xl text-[8px] md:text-[10px] font-black uppercase tracking-widest border border-blue-100 hover:bg-blue-600 hover:text-white transition-all">Tab Baru</a>
                   </div>

                   <div className="flex-1 w-full bg-white rounded-xl md:rounded-[2rem] shadow-xl overflow-hidden border-2 md:border-4 border-white">
                      <iframe 
                        src={getEmbedUrl(selectedMaterial.content)} 
                        className="w-full h-full border-0" 
                        allowFullScreen 
                        title="Material Content"
                        loading="lazy"
                      ></iframe>
                   </div>
                </div>
              </div>
            </div>
          </div>
        );
      })()}
    </div>
  );
};

export default MaterialsTab;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { 
  LogOut, User as UserIcon, Bell, X, Check, 
  Info, BookOpen, ClipboardList, CheckCircle, 
  UserPlus, ChevronDown, Settings, UserCircle 
} from 'lucide-react';

interface Notification {
  id: string;
  title: string;
  message: string;
  read: boolean;
  type: 'material' | 'task' | 'grade' | 'registration';
  createdAt: string;
}

interface LayoutProps {
  children: React.ReactNode;
  user: any;
  onLogout: () => void;
  sidebarItems: { icon: any; label: string; id: string }[];
  activeView: string;
  setActiveView: (id: string) => void;
  logoUrl: string;
  siteName: string;
  notifications?: Notification[];
  onMarkAsRead?: (id: string) => void;
  onMarkAllAsRead?: () => void;
}

const Layout: React.FC<LayoutProps> = ({ 
  children, 
  user, 
  onLogout, 
  sidebarItems, 
  activeView, 
  setActiveView,
  logoUrl,
  siteName,
  notifications = [],
  onMarkAsRead,
  onMarkAllAsRead
}) => {
  const [showNotifications, setShowNotifications] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);

  const sortedNotifications = useMemo(() => {
    return [...notifications].sort((a, b) => b.id.localeCompare(a.id));
  }, [notifications]);

  const unreadCount = useMemo(() => {
    return notifications.filter(n => !n.read).length;
  }, [notifications]);

  const notificationRef = useRef<HTMLDivElement>(null);
  const profileRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setShowProfileMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const getIcon = (type: string) => {
    switch(type) {
      case 'material': return <BookOpen size={16} className="text-emerald-500" />;
      case 'task': return <ClipboardList size={16} className="text-purple-500" />;
      case 'grade': return <CheckCircle size={16} className="text-blue-500" />;
      case 'registration': return <UserPlus size={16} className="text-orange-500" />;
      default: return <Info size={16} className="text-slate-400" />;
    }
  };

  const NotificationBadge = ({ count }: { count: number }) => (
    count > 0 ? (
      <span className="absolute -top-1 -right-1 w-4 h-4 md:w-5 md:h-5 bg-rose-500 text-white text-[8px] md:text-[9px] font-black flex items-center justify-center rounded-full border-2 border-white shadow-lg animate-in zoom-in-50 duration-300">
        {count > 9 ? '9+' : count}
      </span>
    ) : null
  );

  return (
    <div className="flex min-h-screen bg-slate-50">
      {/* Sidebar Desktop */}
      <aside className="w-72 bg-white border-r border-slate-200 hidden md:flex flex-col sticky top-0 h-screen">
        <div className="p-8 flex flex-col gap-4">
          <img src={logoUrl} alt="Logo" className="h-14 w-auto object-contain self-start" />
          <span className="font-black text-slate-800 text-[10px] leading-tight opacity-40 uppercase tracking-[0.3em]">{siteName}</span>
        </div>

        <nav className="flex-1 px-4 py-4 space-y-2">
          {sidebarItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveView(item.id)}
              className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${
                activeView === item.id 
                  ? 'bg-slate-900 text-white shadow-2xl shadow-slate-200 translate-x-1' 
                  : 'text-slate-400 hover:bg-slate-50 hover:text-slate-600'
              }`}
            >
              <item.icon size={20} />
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-6 border-t border-slate-50">
          <div className="p-5 bg-emerald-50 rounded-[2rem] border border-emerald-100/50">
             <p className="text-[9px] font-black text-emerald-600 uppercase tracking-widest mb-1.5 flex items-center gap-2">
               <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
               Status Sistem
             </p>
             <span className="text-[11px] font-bold text-slate-700">Cloud Terhubung</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        {/* Navbar */}
        <header className="h-16 md:h-20 bg-white/80 backdrop-blur-md border-b border-slate-200 px-4 md:px-10 flex items-center justify-between sticky top-0 z-40">
          <div className="flex items-center gap-4">
            <h2 className="text-lg md:text-xl font-black text-slate-900 tracking-tighter truncate max-w-[150px] md:max-w-none">
              {sidebarItems.find(i => i.id === activeView)?.label || 'Dashboard'}
            </h2>
          </div>

          <div className="flex items-center gap-2 md:gap-4">
            <div className="relative" ref={notificationRef}>
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className={`p-2.5 md:p-3.5 rounded-xl md:rounded-2xl transition-all relative ${showNotifications ? 'bg-slate-900 text-white shadow-xl' : 'bg-slate-50 text-slate-400 hover:text-slate-900'}`}
              >
                <Bell size={18} className="md:w-5 md:h-5" />
                <NotificationBadge count={unreadCount} />
              </button>

              {showNotifications && (
                <div className="absolute right-0 mt-4 w-[280px] md:w-[28rem] bg-white rounded-3xl md:rounded-[3rem] shadow-2xl border border-slate-100 overflow-hidden z-50 animate-in fade-in slide-in-from-top-4 duration-300">
                  <div className="p-5 md:p-8 border-b border-slate-50 flex items-center justify-between bg-white">
                    <div>
                      <h4 className="font-black text-slate-900 text-base md:text-lg tracking-tight">Notifikasi</h4>
                      <p className="text-[8px] md:text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Kamu punya {unreadCount} pesan baru</p>
                    </div>
                    {unreadCount > 0 && (
                      <button 
                        onClick={() => {
                          onMarkAllAsRead?.();
                          setShowNotifications(false);
                        }}
                        className="text-[8px] md:text-[10px] font-black text-emerald-600 uppercase hover:bg-emerald-50 px-3 py-1.5 rounded-lg transition-all active:scale-95"
                      >
                        Tandai Semua
                      </button>
                    )}
                  </div>
                  <div className="max-h-[350px] md:max-h-[450px] overflow-y-auto scrollbar-hide bg-white">
                    {sortedNotifications.length === 0 ? (
                      <div className="py-12 md:py-20 text-center">
                        <div className="w-16 h-16 bg-slate-50 text-slate-200 rounded-2xl flex items-center justify-center mx-auto mb-4">
                           <Bell size={30} />
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Belum ada aktivitas baru</p>
                      </div>
                    ) : (
                      sortedNotifications.map((notif) => (
                        <div 
                          key={notif.id} 
                          onClick={() => {
                            onMarkAsRead?.(notif.id);
                            if (!notif.read) setShowNotifications(false);
                          }}
                          className={`p-4 md:p-6 flex gap-4 md:gap-5 cursor-pointer transition-all border-b border-slate-50 last:border-0 ${!notif.read ? 'bg-emerald-50/30 hover:bg-emerald-50/50' : 'hover:bg-slate-50 opacity-60'}`}
                        >
                          <div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center shrink-0 shadow-sm ${!notif.read ? 'bg-white' : 'bg-slate-100 grayscale'}`}>
                            {getIcon(notif.type)}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-start justify-between gap-2 mb-0.5 md:mb-1">
                              <p className={`text-xs md:text-sm truncate ${!notif.read ? 'font-black text-slate-900' : 'font-bold text-slate-500'}`}>{notif.title}</p>
                              <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest shrink-0">{notif.createdAt.split(',')[0]}</p>
                            </div>
                            <p className="text-[10px] md:text-xs text-slate-500 font-medium line-clamp-2 leading-relaxed">{notif.message}</p>
                          </div>
                          {!notif.read && (
                            <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full mt-2 shrink-0 shadow-[0_0_8px_rgba(16,185,129,0.8)]"></div>
                          )}
                        </div>
                      ))
                    )}
                  </div>
                </div>
              )}
            </div>

            <div className="h-8 w-[1px] bg-slate-100 mx-1 md:mx-2"></div>

            <div className="relative" ref={profileRef}>
              <button 
                onClick={() => setShowProfileMenu(!showProfileMenu)}
                className={`flex items-center gap-2 p-1 md:p-1.5 md:pr-5 rounded-full transition-all ${
                  showProfileMenu 
                    ? 'bg-slate-900 text-white shadow-2xl' 
                    : 'bg-slate-50 border border-slate-100 text-slate-800'
                }`}
              >
                <img 
                  src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} 
                  alt="Profile" 
                  className={`w-8 h-8 md:w-9 md:h-9 rounded-full border-2 ${showProfileMenu ? 'border-white/20' : 'border-white'} bg-white object-cover`}
                />
                <div className="text-left hidden sm:block">
                  <p className="text-xs font-black leading-none">{user.name.split(' ')[0]}</p>
                </div>
                <ChevronDown size={12} className={`transition-transform duration-300 hidden md:block ${showProfileMenu ? 'rotate-180' : ''}`} />
              </button>

              {showProfileMenu && (
                <div className="absolute right-0 mt-4 w-64 md:w-72 bg-white rounded-3xl md:rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden z-50 animate-in fade-in slide-in-from-top-4 duration-300">
                  <div className="p-6 md:p-8 bg-slate-50 border-b border-slate-100 flex flex-col items-center text-center">
                    <img 
                      src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} 
                      className="w-16 h-16 md:w-20 md:h-20 rounded-full border-4 border-white shadow-xl mb-4"
                      alt=""
                    />
                    <h5 className="text-sm md:text-base font-black text-slate-900">{user.name}</h5>
                    <p className="text-[8px] md:text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] mt-1">Siswa Informatika</p>
                  </div>

                  <div className="p-2 md:p-3 space-y-1">
                    <button 
                      onClick={() => { setActiveView('settings'); setShowProfileMenu(false); }}
                      className="w-full flex items-center gap-3 md:gap-4 px-4 py-3 rounded-xl md:rounded-2xl text-[10px] md:text-xs font-black text-slate-600 hover:bg-slate-50 transition-colors uppercase tracking-widest"
                    >
                      <Settings size={18} className="text-slate-400" /> Profil Akun
                    </button>
                    <button 
                      onClick={onLogout}
                      className="w-full flex items-center gap-3 md:gap-4 px-4 py-3 rounded-xl md:rounded-2xl text-[10px] md:text-xs font-black text-rose-500 hover:bg-rose-50 transition-colors uppercase tracking-widest"
                    >
                      <LogOut size={18} /> Logout
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-12 scrollbar-hide">
          {children}
        </div>
      </main>

      {/* Mobile Bottom Navigation */}
