                  </button>
                </div>
              </div>
            </div>
          );
        })}
      </section>

      {/* Enhanced Task Modal */}
      {selectedTask && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-md z-[100] flex items-center justify-center p-2 md:p-10 animate-in fade-in zoom-in-95 duration-300">
