      setLoading(true);
      try {
        const [s, t, u] = await Promise.all([
          db.get('elearning_submissions'), 
          db.get('elearning_tasks'), 
          db.get('users')
        ]);
        setSubs(Array.isArray(s) ? s : []);
        setTasks(Array.isArray(t) ? t : []);
